  let CLIENTE_URL = _cliUrlStored || 'https://portal.zelloambiental.com.br';

  // SEMANA 4.19 FIX: Helper pra normalizar a URL do cliente (com .html se necessário)
  // O portal Vercel está em /cliente.html. Sem .html dá erro de rota.
  function getClienteUrl() {
    let url = CLIENTE_URL || 'https://portal.zelloambiental.com.br';
    // Remove barra final se houver
    url = url.replace(/\/$/, '');
    // Se a URL contém o domínio principal (portal.zelloambiental.com.br), NÃO adiciona .html
    // — o Vercel já roteia / → cliente.html via rewrite. Adicionar .html quebraria.
    // Só adiciona .html para domínios legados tipo zello-zeta.vercel.app/cliente.
    if (/portal\.zelloambiental\.com\.br/i.test(url)) {
      return url;
    }
    // Se já termina com .html, OK. Senão, adiciona (compat com domínios antigos).
    if (!/\.html?$/i.test(url)) {
      url += '.html';
    }
    return url;
  }

  // ===========================================================
  // AUTENTICAÇÃO (LOGIN ADMIN)
  // ===========================================================
  const SESSION_KEY = 'z_admin_session';
  const SESSION_DURATION = 7 * 24 * 60 * 60 * 1000;  // 7 dias
  let _adminLogado = null;  // Objeto do admin logado

  // ⚠️ DEPRECATED desde Onda 2 (2026-06-13).
  // SHA-256 sem salt foi substituído por PBKDF2-SHA256 (600k iter) na Edge Function
  // auth-pin-cliente. Esta função NÃO deve ser usada para criar/validar PIN de cliente.
  // Mantida apenas pra compatibilidade com hash de senha de admin (que tem outro
  // contexto e ainda usa SHA-256 client-side por enquanto — pendente refatorar).
  // NÃO USAR em novo código para PIN/credenciais sensíveis.
  async function hashSenha(senha) {
    const enc = new TextEncoder().encode(senha);
    const buf = await crypto.subtle.digest('SHA-256', enc);
    return Array.from(new Uint8Array(buf))
      .map(b => b.toString(16).padStart(2, '0'))
      .join('');
  }

  // ============================================================
  // FASE 14.1: Sistema multi-usuário (admin + hunters + projetos)
  // ============================================================
  // Configuração de cores (UI)
  const CORES_TIMES = {
    azul:     { hex: '#2196F3', emoji: '🔵', nome: 'Azul',     papel: 'hunter' },
    vermelho: { hex: '#E53935', emoji: '🔴', nome: 'Vermelho', papel: 'hunter' },
    verde:    { hex: '#43A047', emoji: '🟢', nome: 'Verde',    papel: 'hunter' },
    amarelo:  { hex: '#FBC02D', emoji: '🟡', nome: 'Amarelo',  papel: 'hunter' },
    rosa:     { hex: '#EC407A', emoji: '🩷', nome: 'Rosa',     papel: 'hunter' },
    roxo:     { hex: '#8E24AA', emoji: '🟣', nome: 'Roxo',     papel: 'hunter' },
    laranja:  { hex: '#F57C00', emoji: '🟠', nome: 'Laranja',  papel: 'hunter' },
    marrom:   { hex: '#6D4C41', emoji: '🟤', nome: 'Marrom',   papel: 'hunter' },
    preto:    { hex: '#212121', emoji: '⚫', nome: 'Preto',    papel: 'projetos' },
    branco:   { hex: '#F5F5F5', emoji: '⚪', nome: 'Branco',   papel: 'projetos' },
    cinza:    { hex: '#757575', emoji: '⚙️', nome: 'Cinza',    papel: 'projetos' }
  };

  // ONDA NICE-TO-HAVE 2026-05-27 #1.3: helper pra colocar spinner em qualquer botão
  // Uso:
  //   btnLoading(btn, true, 'Salvando...');   // ativa loading
  //   btnLoading(btn, false);                  // restaura texto original
  // Guarda o texto original em data-original-text pra restaurar depois.
  function btnLoading(btn, on, texto) {
    if (!btn) return;
    if (on) {
      if (!btn.dataset.originalText) {
        btn.dataset.originalText = btn.innerHTML;
      }
      btn.innerHTML = '<span class="btn-spinner"></span>' + (texto || 'Salvando...');
      btn.classList.add('is-loading');
      btn.disabled = true;
    } else {
      if (btn.dataset.originalText) {
        btn.innerHTML = btn.dataset.originalText;
        delete btn.dataset.originalText;
      }
      btn.classList.remove('is-loading');
      btn.disabled = false;
    }
  }
  window.btnLoading = btnLoading;

  let _corLoginSelecionada = null;  // pra fluxo PIN

  // Verifica se há sessão válida no localStorage
  function getSessao() {
    try {
      const raw = localStorage.getItem(SESSION_KEY);
      if (!raw) return null;
      const s = JSON.parse(raw);
      if (!s.expires || Date.now() > s.expires) {
        localStorage.removeItem(SESSION_KEY);
        return null;
      }
      return s;
    } catch (e) { return null; }
  }

  // FASE 14.1: setSessao genérico (admin OU hunter/projetos)
  // ONDA Z.A.4 (retomada): também guarda 'sessao_hash' (vem do auth-login v9)
  // pra autenticar em Edge Functions como senhas-gateway. Trocar senha
  // invalida automaticamente sessões antigas. Campo opcional — se não vier,
  // sistema cai no caminho legado (PATCH direto).
  function setSessao(usuario) {
    const s = {
      id: usuario.id,
      nome: usuario.nome,
      papel: usuario.papel || 'admin',     // default admin pra compatibilidade
      cor: usuario.cor || null,
      email: usuario.email || null,
      sessao_hash: usuario.sessao_hash || null,  // Z.A.4
      expires: Date.now() + SESSION_DURATION
    };
    localStorage.setItem(SESSION_KEY, JSON.stringify(s));
    _adminLogado = s;
  }

  function limparSessao() {
    localStorage.removeItem(SESSION_KEY);
    _adminLogado = null;
  }

  // Verifica sessão ao carregar; mostra login se inválida
  async function verificarLogin() {
    const sess = getSessao();
    if (sess) {
      _adminLogado = sess;
      mostrarPainel();
      // SEMANA 2: verifica AGORA se está ativo + inicia verificação periódica
      if (typeof iniciarVerificacaoSessao === 'function') {
        iniciarVerificacaoSessao();
        // Verifica imediatamente também (sem esperar 5 min)
        setTimeout(function(){ if (typeof verificarSessaoAtiva === 'function') verificarSessaoAtiva(); }, 2000);
        // SEMANA 2: inicializa sino de notificações
        if (typeof inicializarSino === 'function') setTimeout(inicializarSino, 1000);
      // SEMANA 3.3: mostra onboarding na 1ª vez (hunter)
      if (typeof verificarMostrarOnboarding === 'function') setTimeout(verificarMostrarOnboarding, 2500);
      }
      return true;
    }
    mostrarLogin();
    return false;
  }

  function mostrarLogin() {
    document.getElementById('login-screen').style.display = 'flex';
    // Mostra tela 1 (escolha de times) por padrão
    voltarTelaTimes();
  }

  function mostrarPainel() {
    document.getElementById('login-screen').style.display = 'none';
    // Mostra info do usuário logado no rodapé do sidebar (se elemento existir)
    const elInfo = document.getElementById('admin-info');
    if (elInfo && _adminLogado) {
      const cor = _adminLogado.cor ? (CORES_TIMES[_adminLogado.cor] || null) : null;
      const prefixo = cor ? cor.emoji + ' ' : '👤 ';
      elInfo.textContent = prefixo + (_adminLogado.nome || _adminLogado.email || 'Usuário');
    }
    const elConta = document.getElementById('cfg-minha-conta');
    if (elConta && _adminLogado) {
      const papelLabel = _adminLogado.papel === 'hunter' ? 'Hunter' :
                         _adminLogado.papel === 'projetos' ? 'Equipe Projetos' : 'Admin';
      elConta.innerHTML = '<strong>' + escapeHtml(_adminLogado.nome || '—') + '</strong><br/>'
        + '<span style="font-size:11px;color:var(--text-muted);">' + papelLabel
        + (_adminLogado.cor ? ' · ' + (CORES_TIMES[_adminLogado.cor] || {}).nome : '')
        + '</span>'
        + (_adminLogado.email ? '<br/><span style="font-family:monospace;font-size:11px;">' + escapeHtml(_adminLogado.email) + '</span>' : '');
    }

    // FASE 14.2: aplica visibilidade do menu lateral conforme papel
    aplicarPermissoesPapel();

    // FASE 14.2: admin verifica auto-liberação de leads inativos (executa em background)
    setTimeout(function(){ verificarAutoLiberacao(); }, 2000);
  }

  // FASE 14.2: Esconde/mostra menus, telas e botões conforme papel do usuário logado
  function aplicarPermissoesPapel() {
    const sess = getSessao();
    const papel = (sess && sess.papel) || 'admin';

    // 1. Menu lateral: esconde itens que não pertencem ao papel
    document.querySelectorAll('aside.sidebar [data-roles]').forEach(function(el){
      const roles = (el.getAttribute('data-roles') || '').split(',').map(function(s){ return s.trim(); });
      if (roles.indexOf(papel) === -1) {
        el.style.display = 'none';
      } else {
        el.style.display = '';
      }
    });

    // 2. Label "Prospecção" muda pra "Meus Leads" pro hunter
    const lblProsp = document.getElementById('lbl-prospeccao');
    if (lblProsp) {
      lblProsp.textContent = (papel === 'hunter') ? 'Meus Leads' : 'Prospecção';
    }

    // 3. Dashboards: hunter vê dash-hunter, admin/projetos vê dash-operacional
    const dashHunter = document.getElementById('dash-hunter');
    const dashOper = document.getElementById('dash-operacional');
    if (dashHunter && dashOper) {
      if (papel === 'hunter') {
        dashHunter.style.display = '';
        dashOper.style.display = 'none';
      } else {
        dashHunter.style.display = 'none';
        dashOper.style.display = '';
      }
    }

    // 4. Ajusta tela padrão se a atual não for permitida pro papel
    const pageAtiva = document.querySelector('.page.active');
    if (pageAtiva) {
      const idAtiva = pageAtiva.id.replace('page-', '');
      const itemMenu = document.querySelector('aside.sidebar [data-page="' + idAtiva + '"]');
      if (itemMenu && itemMenu.style.display === 'none') {
        // Página atual não é permitida pro papel — vai pro dashboard
        navTo('dashboard');
      }
    }
  }

  // FASE 14.2: helpers de papel (usados pra mostrar/esconder UI dinamicamente)
  function souAdmin() {
    const s = getSessao();
    return s && s.papel === 'admin';
  }
  function souHunter() {
    const s = getSessao();
    return s && s.papel === 'hunter';
  }

  // ONDA B: detecta "modo dev" — controla visibilidade de botões destrutivos
  // de teste (Apagar TUDO, Excluir MODO TESTE). Em produção (default): esconde.
  // Pra ativar: console → localStorage.setItem('z_modo_dev','1') → F5.
  // Pra desativar: localStorage.removeItem('z_modo_dev') → F5.
  function souModoDev() {
    try { return localStorage.getItem('z_modo_dev') === '1'; }
    catch(e) { return false; }
  }

  // FASE 14.1: navegação entre as 3 telas de login
  function voltarTelaTimes() {
    const t1 = document.getElementById('login-tela-times');
    const t2 = document.getElementById('login-tela-pin');
    const t3 = document.getElementById('login-tela-admin');
    if (t1) t1.style.display = 'block';
    if (t2) t2.style.display = 'none';
    if (t3) t3.style.display = 'none';
    // Limpa campos de erro
    const e1 = document.getElementById('login-pin-erro'); if (e1) e1.style.display = 'none';
    const e2 = document.getElementById('login-erro'); if (e2) e2.style.display = 'none';
    _corLoginSelecionada = null;
  }

  function mostrarLoginAdmin() {
    document.getElementById('login-tela-times').style.display = 'none';
    document.getElementById('login-tela-pin').style.display = 'none';
    document.getElementById('login-tela-admin').style.display = 'block';
    setTimeout(function(){
      const el = document.getElementById('login-email');
      if (el) el.focus();
    }, 100);
  }

  // FASE 14.1: hunter/projetos clicou na cor — abre tela do PIN
  function abrirLoginPin(cor, nome) {
    _corLoginSelecionada = cor;
    const info = CORES_TIMES[cor] || { hex: '#999', emoji: '?', nome: nome };
    document.getElementById('login-tela-times').style.display = 'none';
    document.getElementById('login-tela-pin').style.display = 'block';
    document.getElementById('login-tela-admin').style.display = 'none';

    const badge = document.getElementById('login-pin-cor-badge');
    if (badge) {
      badge.style.background = info.hex;
      badge.textContent = info.emoji;
    }
    const lbl = document.getElementById('login-pin-cor-nome');
    if (lbl) lbl.textContent = 'Time ' + info.nome;

    const inp = document.getElementById('login-pin-input');
    if (inp) { inp.value = ''; setTimeout(function(){ inp.focus(); }, 100); }
    const err = document.getElementById('login-pin-erro');
    if (err) err.style.display = 'none';
  }

  // FASE 14.1: valida PIN do hunter/projetos
  // SEMANA 2: Rate limit PIN — protege contra brute force
  // Bloqueia uma cor após 5 tentativas erradas consecutivas por 15 minutos.
  // Estado persistente no localStorage (sobrevive a refresh).
  const PIN_MAX_TENTATIVAS = 5;
  const PIN_BLOQUEIO_MIN = 15;  // minutos

  function getPinBloqueio(cor) {
    try {
      const raw = localStorage.getItem('z_pin_block_' + cor);
      if (!raw) return null;
      const obj = JSON.parse(raw);
      // Se expirou, remove
      if (obj.bloqueadoAte && Date.now() > obj.bloqueadoAte) {
        localStorage.removeItem('z_pin_block_' + cor);
        return null;
      }
      return obj;
    } catch (e) { return null; }
  }

  function setPinBloqueio(cor, obj) {
    try { localStorage.setItem('z_pin_block_' + cor, JSON.stringify(obj)); } catch (e) {}
  }

  function registrarTentativaPin(cor, sucesso) {
    if (sucesso) {
      // Reseta contador no sucesso
      try { localStorage.removeItem('z_pin_block_' + cor); } catch (e) {}
      return null;
    }
    let info = getPinBloqueio(cor) || { tentativas: 0, bloqueadoAte: null };
    info.tentativas = (info.tentativas || 0) + 1;
    if (info.tentativas >= PIN_MAX_TENTATIVAS) {
      info.bloqueadoAte = Date.now() + PIN_BLOQUEIO_MIN * 60 * 1000;
      info.tentativas = 0;   // zera pra próximo ciclo
    }
    setPinBloqueio(cor, info);
    return info;
  }

  function formatarTempoBloqueio(timestamp) {
    const restanteMs = timestamp - Date.now();
    if (restanteMs <= 0) return '0 min';
    const min = Math.ceil(restanteMs / 60000);
    return min + ' min';
  }

  async function doLoginPin(ev) {
    if (ev) ev.preventDefault();
    const cor = _corLoginSelecionada;
    if (!cor) { voltarTelaTimes(); return false; }

    const pin = (document.getElementById('login-pin-input').value || '').trim();
    const erroEl = document.getElementById('login-pin-erro');
    const btn = document.getElementById('login-pin-btn');

    // SEMANA 2: Verifica bloqueio antes de tentar
    const bloqueio = getPinBloqueio(cor);
    if (bloqueio && bloqueio.bloqueadoAte && Date.now() < bloqueio.bloqueadoAte) {
      const restante = formatarTempoBloqueio(bloqueio.bloqueadoAte);
      erroEl.textContent = '🔒 Time bloqueado por ' + restante + ' (muitas tentativas). Tente mais tarde.';
      erroEl.style.display = 'block';
      return false;
    }

    if (!pin || !/^[0-9]{6}$/.test(pin)) {
      erroEl.textContent = 'PIN deve ter 6 dígitos numéricos.';
      erroEl.style.display = 'block';
      return false;
    }

    erroEl.style.display = 'none';
    btn.disabled = true;
    btn.textContent = 'Entrando...';

    try {
      // ONDA Z.A.2: valida PIN no SERVIDOR (Edge Function auth-pin-hunter).
      // Antes a comparação era client-side: o navegador recebia pin_hash e
      // comparava local — qualquer um com F12 forjava sessão. Agora a Edge
      // Function compara o hash internamente e só retorna o usuário se OK.
      const r = await fetch(SUPABASE_URL + '/functions/v1/auth-pin-hunter', {
        method: 'POST',
        headers: {
          'Authorization': 'Bearer ' + SUPABASE_KEY,
          'Content-Type': 'application/json'
        },
        body: JSON.stringify({ cor: cor, pin: pin })
      });
      const dados = await r.json().catch(function(){ return {}; });

      if (!r.ok) {
        // 401 = PIN/cor errado, 400 = formato inválido
        const info = registrarTentativaPin(cor, false);
        if (info && info.bloqueadoAte) {
          erroEl.textContent = '🔒 Time bloqueado por 15 minutos (muitas tentativas erradas).';
        } else if (info) {
          const restantes = PIN_MAX_TENTATIVAS - info.tentativas;
          erroEl.textContent = (dados.erro || 'PIN incorreto.') + ' Restam ' + restantes + ' tentativa' + (restantes > 1 ? 's' : '') + '.';
        } else {
          erroEl.textContent = dados.erro || 'PIN incorreto. Esqueceu? Fale com o admin.';
        }
        erroEl.style.display = 'block';
        return false;
      }

      const usr = dados.usuario;
      if (!usr || !usr.id) {
        erroEl.textContent = 'Resposta inválida do servidor. Tente novamente.';
        erroEl.style.display = 'block';
        return false;
      }

      // Sucesso — limpa contador de tentativas
      registrarTentativaPin(cor, true);

      // (ultimo_login já foi atualizado pela Edge Function — não precisa de PATCH aqui)

      setSessao(usr);
      mostrarPainel();
      // Inicia o painel
      if (typeof carregarDados === 'function') carregarDados();
      if (typeof carregarTodasCidades === 'function') carregarTodasCidades();
      if (typeof carregarConfigEmpresa === 'function') setTimeout(carregarConfigEmpresa, 500);
      if (typeof inicializarDragDropMenu === 'function') setTimeout(inicializarDragDropMenu, 100);
      // SEMANA 2: inicia verificação periódica de sessão
      if (typeof iniciarVerificacaoSessao === 'function') iniciarVerificacaoSessao();
      if (typeof inicializarSino === 'function') setTimeout(inicializarSino, 1000);
      // SEMANA 3.3: mostra onboarding na 1ª vez (hunter)
      if (typeof verificarMostrarOnboarding === 'function') setTimeout(verificarMostrarOnboarding, 2500);
      return false;
    } catch (e) {
      erroEl.textContent = 'Erro: ' + (e.message || 'tente novamente');
      erroEl.style.display = 'block';
    } finally {
      btn.disabled = false;
      btn.textContent = 'Entrar';
    }
    return false;
  }

  // Submete o formulário de login (admin email + senha)
  async function doLogin(ev) {
    if (ev) ev.preventDefault();
    const email = (document.getElementById('login-email').value || '').trim().toLowerCase();
    const senha = document.getElementById('login-senha').value || '';
    const erroEl = document.getElementById('login-erro');
    const btn = document.getElementById('login-btn');

    if (!email || !senha) {
      erroEl.textContent = 'Preencha e-mail e senha.';
      erroEl.style.display = 'block';
      return false;
    }

    erroEl.style.display = 'none';
    btn.disabled = true;
    btn.textContent = 'Entrando...';

    try {
      // BLOCO 6 (Fase 1): a senha é verificada no SERVIDOR (Edge Function).
      // O navegador nunca recebe o hash — só "entrou" ou "não entrou".
      let resp, dados;
      try {
        resp = await fetch(SUPABASE_URL + '/functions/v1/auth-login', {
          method: 'POST',
          headers: {
            'Content-Type': 'application/json',
            'apikey': SUPABASE_KEY,
            'Authorization': 'Bearer ' + SUPABASE_KEY
          },
          body: JSON.stringify({ acao: 'login', email: email, senha: senha })
        });
        dados = await resp.json();
      } catch(eRede) {
        erroEl.textContent = 'Falha de comunicação. Verifique sua conexão.';
        erroEl.style.display = 'block';
        return false;
      }

      if (!resp.ok || !dados || !dados.ok) {
        erroEl.textContent = (dados && dados.erro) ? dados.erro : 'E-mail ou senha inválidos.';
        erroEl.style.display = 'block';
        return false;
      }

      // Sucesso — a Edge Function devolve os dados do usuário (sem hash)
      const usuario = dados.usuario;
      usuario.papel = usuario.papel || 'admin';
      setSessao(usuario);
      mostrarPainel();
      // Inicia o painel com tudo que precisa
      if (typeof carregarDados === 'function') carregarDados();
      if (typeof carregarTodasCidades === 'function') carregarTodasCidades();
      if (typeof carregarConfigEmpresa === 'function') setTimeout(carregarConfigEmpresa, 500);
      if (typeof inicializarDragDropMenu === 'function') setTimeout(inicializarDragDropMenu, 100);
      // SEMANA 2: inicia verificação periódica de sessão
      if (typeof iniciarVerificacaoSessao === 'function') iniciarVerificacaoSessao();
      if (typeof inicializarSino === 'function') setTimeout(inicializarSino, 1000);
      // SEMANA 3.3: mostra onboarding na 1ª vez (hunter)
      if (typeof verificarMostrarOnboarding === 'function') setTimeout(verificarMostrarOnboarding, 2500);
      return false;
    } catch (e) {
      erroEl.textContent = 'Erro: ' + (e.message || 'tente novamente');
      erroEl.style.display = 'block';
    } finally {
      btn.disabled = false;
      btn.textContent = 'Entrar';
    }
    return false;
  }

  // Logout: limpa sessão e mostra login de novo
  function doLogout() {
    if (!confirm('Sair da sua conta?')) return;
    pararVerificacaoSessao();   // SEMANA 2: para o polling antes de sair
    limparSessao();
    location.reload();
  }

  // ============================================================
  // BLOCO 6 (Fase 1): GERENCIAR EQUIPE
  // ============================================================
  // Lista, cria e ativa/desativa membros da equipe.
  // A criação passa pela Edge Function auth-login (ação "criar"),
  // que valida que quem pede é admin e gera o hash bcrypt seguro.
  // ============================================================

  async function carregarEquipe() {
    const lista = document.getElementById('lista-equipe');
    const card = document.getElementById('card-gerenciar-equipe');
    if (!lista) return;

    // Só admin vê o card de gerenciar equipe
    const sess = getSessao();
    if (!sess || sess.papel !== 'admin') {
      if (card) card.style.display = 'none';
      return;
    }
    if (card) card.style.display = '';

    try {
      const r = await fetch(SUPABASE_URL + '/rest/v1/usuarios?select=id,nome,email,papel,cor,ativo,ultimo_login&order=nome.asc', {
        headers: { 'apikey': SUPABASE_KEY, 'Authorization': 'Bearer ' + SUPABASE_KEY }
      });
      if (!r.ok) throw new Error('Falha ao carregar');
      const usuarios = await r.json();
      _renderEquipe(usuarios);
    } catch(e) {
      lista.innerHTML = '<div style="font-size:12px;color:#C62828;text-align:center;padding:10px;">Erro ao carregar a equipe.</div>';
    }
  }

  function _renderEquipe(usuarios) {
    const lista = document.getElementById('lista-equipe');
    if (!lista) return;
    if (!usuarios || !usuarios.length) {
      lista.innerHTML = '<div style="font-size:12px;color:var(--text-muted);text-align:center;padding:10px;font-style:italic;">Nenhum membro cadastrado ainda.</div>';
      return;
    }
    const papelLabel = { admin:'Administrador', hunter:'Hunter', projetos:'Equipe Projetos' };
    const sess = getSessao();
    lista.innerHTML = usuarios.map(function(u) {
      const ehEu = sess && sess.id === u.id;
      const inativo = u.ativo === false;
      const ultimo = u.ultimo_login
        ? new Date(u.ultimo_login).toLocaleDateString('pt-BR')
        : 'nunca';
      return '<div style="display:flex;align-items:center;gap:10px;padding:10px;border:1px solid var(--border);border-radius:6px;margin-bottom:6px;' +
          (inativo ? 'opacity:0.55;' : '') + '">' +
        '<div style="flex:1;min-width:0;">' +
          '<div style="font-size:13px;font-weight:600;">' + escapeHtml(u.nome || '—') +
            (ehEu ? ' <span style="font-size:10px;color:var(--blue);">(você)</span>' : '') +
            (inativo ? ' <span style="font-size:10px;color:#C62828;">(desativado)</span>' : '') +
          '</div>' +
          '<div style="font-size:11px;color:var(--text-muted);">' +
            escapeHtml(u.email || '') + ' · ' + (papelLabel[u.papel] || u.papel) +
            ' · último acesso: ' + ultimo +
          '</div>' +
        '</div>' +
        (ehEu ? '' :
          '<button class="btn btn-sm" onclick="alternarAtivoUsuario(\'' + u.id + '\',' + (inativo?'true':'false') + ')" ' +
          'style="background:' + (inativo?'#E8F5E9':'#FFF3E0') + ';color:' + (inativo?'#1B5E20':'#E65100') + ';border:none;">' +
          (inativo ? 'Reativar' : 'Desativar') + '</button>'
        ) +
      '</div>';
    }).join('');
  }

  function abrirNovoUsuario() {
    document.getElementById('nu-nome').value = '';
    document.getElementById('nu-email').value = '';
    document.getElementById('nu-papel').value = 'hunter';
    document.getElementById('nu-senha').value = '';
    document.getElementById('nu-erro').style.display = 'none';
    abrirModal('ov-novo-usuario');
  }

  async function salvarNovoUsuario() {
    const nome = (document.getElementById('nu-nome').value || '').trim();
    const email = (document.getElementById('nu-email').value || '').trim().toLowerCase();
    const papel = document.getElementById('nu-papel').value;
    const senha = document.getElementById('nu-senha').value || '';
    const erroEl = document.getElementById('nu-erro');
    const btn = document.getElementById('btn-salvar-usuario');

    function erro(msg) {
      erroEl.textContent = msg;
      erroEl.style.display = 'block';
    }
    erroEl.style.display = 'none';

    if (!nome || !email || !senha) { erro('Preencha nome, e-mail e senha.'); return; }
    if (senha.length < 6) { erro('A senha deve ter ao menos 6 caracteres.'); return; }
    if (!validarEmail(email)) { erro('E-mail inválido.'); return; }

    const sess = getSessao();
    if (!sess || sess.papel !== 'admin') { erro('Apenas administradores podem criar usuários.'); return; }

    // FIX SEGURANÇA: a Edge Function agora exige a senha do admin pra confirmar.
    // Pede a senha aqui — conhecer o ID do admin não basta mais.
    const adminSenha = await zPrompt(
      'Para criar um novo membro, confirme sua senha de administrador:',
      '',
      { titulo: '🔐 Confirmação de segurança', placeholder: 'Sua senha', inputType: 'password', btnOk: 'Confirmar' }
    );
    if (adminSenha === null || adminSenha === false) return; // cancelou
    if (!adminSenha) { erro('Senha de administrador é obrigatória para criar membros.'); return; }

    btn.disabled = true;
    btn.textContent = 'Criando...';
    try {
      const r = await fetch(SUPABASE_URL + '/functions/v1/auth-login', {
        method: 'POST',
        headers: {
          'Content-Type': 'application/json',
          'apikey': SUPABASE_KEY,
          'Authorization': 'Bearer ' + SUPABASE_KEY
        },
        body: JSON.stringify({
          acao: 'criar', admin_id: sess.id, admin_senha: adminSenha,
          nome: nome, email: email, senha: senha, papel: papel
        })
      });
      const dados = await r.json();
      if (!r.ok || !dados.ok) {
        erro(dados.erro || 'Erro ao criar usuário.');
        return;
      }
      fecharModal('ov-novo-usuario');
      if (typeof showToast === 'function') showToast('✓ Membro criado com sucesso', 'success', 2500);
      carregarEquipe();
    } catch(e) {
      erro('Falha de comunicação. Tente novamente.');
    } finally {
      btn.disabled = false;
      btn.textContent = '💾 Criar membro';
    }
  }

  async function alternarAtivoUsuario(userId, ativar) {
    const acao = ativar ? 'reativar' : 'desativar';
    if (!(await zConfirm('Deseja ' + acao + ' este membro da equipe?'))) return;
    try {
      const r = await fetch(SUPABASE_URL + '/rest/v1/usuarios?id=eq.' + userId, {
        method: 'PATCH',
        headers: {
          'apikey': SUPABASE_KEY, 'Authorization': 'Bearer ' + SUPABASE_KEY,
          'Content-Type': 'application/json', 'Prefer': 'return=minimal'
        },
        body: JSON.stringify({ ativo: ativar })
      });
      if (!r.ok) throw new Error('falha');
      if (typeof showToast === 'function') showToast('✓ Equipe atualizada', 'success', 2000);
      carregarEquipe();
    } catch(e) {
      zAlert('Erro ao atualizar o membro.', 'erro');
    }
  }

  // ============================================================================
  // SEMANA 2: VERIFICAÇÃO PERIÓDICA DE SESSÃO
  // ============================================================================
  // A cada 5 minutos, checa se o usuário logado ainda está ativo no banco.
  // Se admin desativou o usuário, ele é deslogado em até 5 min (sem precisar
  // esperar os 7 dias do token).
  // ============================================================================

  let _verificacaoSessaoIntervalId = null;
  const VERIFICACAO_SESSAO_MS = 5 * 60 * 1000;   // 5 minutos

  function iniciarVerificacaoSessao() {
    // Para qualquer verificação anterior
    pararVerificacaoSessao();
    // Inicia nova
    _verificacaoSessaoIntervalId = setInterval(verificarSessaoAtiva, VERIFICACAO_SESSAO_MS);
    console.log('[Zello] Verificação periódica de sessão iniciada (a cada 5 min)');
  }

  function pararVerificacaoSessao() {
    if (_verificacaoSessaoIntervalId) {
      clearInterval(_verificacaoSessaoIntervalId);
      _verificacaoSessaoIntervalId = null;
    }
  }

  async function verificarSessaoAtiva() {
    const sess = getSessao();
    if (!sess || !sess.id) return;
    // Não verifica admin do email (ele está em outra tabela)
    if (sess.papel === 'admin' && sess.email) return;

    try {
      const r = await fetch(SUPABASE_URL + '/rest/v1/usuarios?id=eq.' + sess.id + '&select=ativo,papel,cor', {
        headers: { 'apikey': SUPABASE_KEY, 'Authorization': 'Bearer ' + SUPABASE_KEY }
      });
      if (!r.ok) {
        console.warn('[Sessão] Falha ao verificar (HTTP ' + r.status + ') — mantendo sessão');
        return;
      }
      const list = await r.json();
      const u = list && list[0];

      // Usuário foi DELETADO?
      if (!u) {
        pararVerificacaoSessao();
        zAlert('🔒 Sua conta foi removida pelo administrador.\n\nEntre em contato com o admin.', 'aviso');
        limparSessao();
        location.reload();
        return;
      }
      // Foi DESATIVADO?
      if (u.ativo === false) {
        pararVerificacaoSessao();
        zAlert('🔒 Sua conta foi desativada pelo administrador.\n\nEntre em contato com o admin.', 'aviso');
        limparSessao();
        location.reload();
        return;
      }
      // Papel ou cor mudaram? Avisa pra fazer login de novo
      if (u.papel !== sess.papel || u.cor !== sess.cor) {
        pararVerificacaoSessao();
        zAlert('🔄 Seu papel ou time mudou. Faça login novamente pra atualizar.', 'aviso');
        limparSessao();
        location.reload();
        return;
      }
    } catch (e) {
      console.warn('[Sessão] Erro na verificação:', e);
      // Erro de rede — mantém sessão (best-effort)
    }
  }

  // Trocar senha: usado em Configurações
  async function trocarSenha() {
    if (!_adminLogado) { zAlert('Você precisa estar logado.', 'aviso'); return; }
    if (!_adminLogado.email) { zAlert('Sua conta não tem e-mail cadastrado.', 'aviso'); return; }
    const atual = prompt('Senha atual:');
    if (!atual) return;
    const nova = prompt('Nova senha (mínimo 6 caracteres):');
    if (!nova) return;
    if (nova.length < 6) { zAlert('A nova senha deve ter pelo menos 6 caracteres.', 'aviso'); return; }
    const conf = prompt('Confirme a nova senha:');
    if (conf !== nova) { zAlert('A confirmação não bate com a nova senha.', 'aviso'); return; }

    try {
      // BLOCO 6 (Fase 1): troca de senha verificada no servidor (Edge Function)
      const r = await fetch(SUPABASE_URL + '/functions/v1/auth-login', {
        method: 'POST',
        headers: {
          'Content-Type': 'application/json',
          'apikey': SUPABASE_KEY,
          'Authorization': 'Bearer ' + SUPABASE_KEY
        },
        body: JSON.stringify({
          acao: 'trocar_senha',
          email: _adminLogado.email,
          senha_atual: atual,
          senha_nova: nova
        })
      });
      const dados = await r.json();
      if (r.ok && dados.ok) {
        zAlert('✅ Senha alterada com sucesso!', 'sucesso');
      } else {
        zAlert(dados.erro || 'Erro ao alterar senha.', 'erro');
      }
    } catch (e) {
      zAlert('Falha de comunicação. Tente novamente.', 'erro');
    }
  }

  // Definir/resetar PIN de um cliente (chamado pelo admin)
  // ONDA 2 FIX (2026-06-13): renomeada conceitualmente pra "Forçar primeiro acesso".
  // Antes: admin digitava PIN de 6 dígitos, virava SHA-256, gravava em pin_hash via REST.
  //   Problemas:
  //   - SHA-256 sem salt (Onda 2 substituiu por PBKDF2 600k iter)
  //   - Hash trafegava em texto pelo REST do navegador
  //   - PIN de 6 dígitos quando o portal só aceita 4
  //   - Admin via o PIN em texto plano
  // Depois: zera AMBOS pin_hash e pin_hash_v2. Cliente recebe OTP por email no
  //   próximo acesso e CRIA o próprio PIN (gravado em pin_hash_v2 PBKDF2).
  //   Admin nunca mais vê o PIN do cliente.
  async function definirPinCliente(clienteId) {
    const c = acharPessoa(clienteId);
    if (!c) { zAlert('Cliente não encontrado.', 'erro'); return; }

    const ok = await zConfirm(
      '🔄 Forçar primeiro acesso de ' + (c.nome||'?') + '?\n\n' +
      'O cliente recebe um código por email no próximo acesso ao portal\n' +
      'e cria o próprio PIN. Você não precisa (nem deve) ver o PIN dele.\n\n' +
      'Use isso quando:\n' +
      '· Cliente esqueceu o PIN\n' +
      '· Acabou de ser cadastrado e precisa criar PIN\n' +
      '· Suspeita de acesso indevido\n\n' +
      'Email cadastrado: ' + (c.email||'(SEM EMAIL — CORRIGIR ANTES!)'),
      { tipo: 'aviso', btnOk: 'Sim, forçar' }
    );
    if (!ok) return;

    if (!c.email) {
      zAlert('⚠ Cliente sem email cadastrado.\n\nO portal envia o código por email — sem email o cliente não consegue acessar. Cadastre o email primeiro.', 'erro');
      return;
    }

    try {
      const r = await fetch(SUPABASE_URL + '/rest/v1/clientes?id=eq.' + clienteId, {
        method: 'PATCH',
        headers: { 'apikey': SUPABASE_KEY, 'Authorization': 'Bearer ' + SUPABASE_KEY, 'Content-Type': 'application/json', 'Prefer': 'return=minimal' },
        body: JSON.stringify({ pin_hash: null, pin_hash_v2: null, portal_ativo: true })
      });
      if (r.ok) {
        zAlert('✅ Pronto!\n\n' +
               '· Cliente: ' + (c.nome||'?') + '\n' +
               '· CPF/CNPJ: ' + (c.cpf_cnpj||'?') + '\n' +
               '· Portal: ' + getClienteUrl() + '\n\n' +
               'Avise o cliente que ele precisa entrar no portal e criar o PIN. Vai receber um código por email.', 'sucesso');
        if (typeof carregarDados === 'function') await carregarDados();
      } else {
        zAlert('Erro ao resetar acesso.', 'erro');
      }
    } catch (e) {
      zAlert('Erro: ' + (e.message || e), 'erro');
    }
  }

  document.getElementById('cfg-url').value = SUPABASE_URL;
  document.getElementById('cfg-key').value = SUPABASE_KEY;
  document.getElementById('cfg-cli-url').value = CLIENTE_URL;

  function salvarCreds() {
    const url = document.getElementById('cfg-url').value.trim();
    const key = document.getElementById('cfg-key').value.trim();
    const cliUrl = document.getElementById('cfg-cli-url').value.trim();

    if (!url) { zAlert('⚠️ Informe a URL do Supabase.', 'aviso'); return; }
    if (!key) { zAlert('⚠️ Informe a Anon Key do Supabase.', 'aviso'); return; }
    if (!cliUrl) { zAlert('⚠️ Informe a URL do formulário do cliente.', 'aviso'); return; }

    // Validação básica de formato URL
    if (!/^https:\/\/.+\.supabase\.co\/?$/.test(url) && !/^https:\/\/.+/.test(url)) {
      if (!confirm('⚠️ URL do Supabase parece incomum.\nDeve começar com "https://" e geralmente termina em ".supabase.co".\n\nSalvar mesmo assim?')) return;
    }
    // Validação básica de URL do cliente
    if (!/^https?:\/\//.test(cliUrl)) {
      zAlert('⚠️ A URL do formulário do cliente deve começar com http:// ou https://', 'aviso');
      return;
    }
    // Validação Anon Key (JWT começa com "eyJ")
    if (!/^eyJ/.test(key)) {
      if (!confirm('⚠️ A Anon Key do Supabase normalmente começa com "eyJ".\n\nSalvar mesmo assim?')) return;
    }

    SUPABASE_URL = url.replace(/\/$/, '');  // remove barra final
    SUPABASE_KEY = key;
    CLIENTE_URL = cliUrl;
    localStorage.setItem('z_url', SUPABASE_URL);
    localStorage.setItem('z_key', SUPABASE_KEY);
    localStorage.setItem('z_cliurl', CLIENTE_URL);

    zAlert('✅ Credenciais salvas!\nO sistema vai testar a conexão agora.', 'aviso');
    testarConexaoConfig();
    carregarDados().catch(function(e){ console.warn('Erro pós-salvarCreds:', e); });
  }

  // =============================================
  // TESTE DE CONEXÃO
  // =============================================
  async function testarConexaoConfig() {
    const el = document.getElementById('cfg-status-conexao');
    const det = document.getElementById('cfg-status-detalhes');
    if (!el) return;

    el.style.background = '#FFF8E1';
    el.innerHTML = '<span style="font-size:18px;">⏳</span><span>Testando conexão com Supabase...</span>';
    det.innerHTML = '';

    if (!SUPABASE_URL || !SUPABASE_KEY) {
      el.style.background = '#FFEBEE';
      el.innerHTML = '<span style="font-size:18px;">❌</span><span style="color:#C62828;font-weight:600;">Credenciais não configuradas</span>';
      det.innerHTML = 'Preencha a URL do Supabase e a Anon Key abaixo, e clique em "Salvar e conectar".';
      return;
    }

    try {
      const t0 = performance.now();
      const r = await fetch(SUPABASE_URL + '/rest/v1/clientes?select=id&limit=1', {
        headers: { 'apikey': SUPABASE_KEY, 'Authorization': 'Bearer ' + SUPABASE_KEY }
      });
      const dt = Math.round(performance.now() - t0);

      if (r.ok) {
        el.style.background = '#E8F5E9';
        el.innerHTML = '<span style="font-size:18px;">✅</span><span style="color:#2E7D32;font-weight:600;">Conectado ao Supabase</span>';
        // Detalhes contagem
        let detalhes = 'Latência: ' + dt + 'ms · URL: ' + SUPABASE_URL + '<br/>';
        // Tentar contar registros
        try {
          const tabelas = ['clientes','propriedades','usos','leituras','contatos','notificacoes'];
          const counts = await Promise.all(tabelas.map(function(t){
            return fetch(SUPABASE_URL + '/rest/v1/' + t + '?select=id', {
              headers: { 'apikey': SUPABASE_KEY, 'Authorization': 'Bearer ' + SUPABASE_KEY, 'Prefer': 'count=exact' }
            }).then(function(rr){
              const cr = rr.headers.get('content-range');
              if (cr) {
                const m = cr.match(/\/(\d+)$/);
                return m ? parseInt(m[1],10) : 0;
              }
              return 0;
            }).catch(function(){ return '?'; });
          }));
          detalhes += 'Registros: ' + tabelas.map(function(t,i){ return t + ': <strong>' + counts[i] + '</strong>'; }).join(' · ');
        } catch(e) {}
        det.innerHTML = detalhes;
      } else if (r.status === 401 || r.status === 403) {
        el.style.background = '#FFEBEE';
        el.innerHTML = '<span style="font-size:18px;">🔒</span><span style="color:#C62828;font-weight:600;">Acesso negado (HTTP ' + r.status + ')</span>';
        det.innerHTML = 'A Anon Key parece inválida, ou as policies RLS não permitem acesso. Verifique a key e rode o SQL <code>zello_rls.sql</code>.';
      } else if (r.status === 404) {
        el.style.background = '#FFEBEE';
        el.innerHTML = '<span style="font-size:18px;">❌</span><span style="color:#C62828;font-weight:600;">Endpoint não encontrado (HTTP 404)</span>';
        det.innerHTML = 'A tabela <code>clientes</code> não existe no banco. Rode o SQL <code>zello_schema.sql</code> primeiro.';
      } else {
        el.style.background = '#FFEBEE';
        el.innerHTML = '<span style="font-size:18px;">❌</span><span style="color:#C62828;font-weight:600;">Erro HTTP ' + r.status + '</span>';
        det.innerHTML = 'Tente novamente ou verifique se a URL está correta.';
      }
    } catch(e) {
      el.style.background = '#FFEBEE';
      el.innerHTML = '<span style="font-size:18px;">📡</span><span style="color:#C62828;font-weight:600;">Falha de rede</span>';
      det.innerHTML = 'Não foi possível alcançar ' + SUPABASE_URL + '. Verifique sua conexão de internet e a URL.<br/>Erro: ' + (e.message || e);
    }
  }

  // =============================================
  // BACKUP / EXPORTAÇÃO COMPLETA
  // =============================================
  async function baixarBackupCompleto() {
    const status = document.getElementById('cfg-backup-status');
    if (!confirm('📦 Baixar backup completo de todos os dados?\n\nIsso vai consultar o Supabase. Pode levar alguns segundos se você tiver muitos registros.')) return;

    status.style.color = '#1565C0';
    status.innerHTML = '⏳ Baixando dados do Supabase...';

    try {
      const tabelas = ['clientes','propriedades','usos','contatos','leituras','notificacoes'];
      const backup = {
        _meta: {
          versao: '1.0',
          gerado_em: new Date().toISOString(),
          empresa: EMPRESA.nome || 'Zello Ambiental',
          supabase_url: SUPABASE_URL
        }
      };

      for (let i = 0; i < tabelas.length; i++) {
        const t = tabelas[i];
        status.innerHTML = '⏳ Baixando ' + t + ' (' + (i+1) + '/' + tabelas.length + ')...';
        const dados = await api(t + '?select=*') || [];
        backup[t] = dados;
      }

      const totalRegs = tabelas.reduce(function(s,t){ return s + (backup[t] || []).length; }, 0);

      // Gera arquivo
      const blob = new Blob([JSON.stringify(backup, null, 2)], {type: 'application/json'});
      const url = URL.createObjectURL(blob);
      const dt = new Date().toISOString().slice(0,16).replace(/[:T]/g,'-');
      const a = document.createElement('a');
      a.href = url;
      a.download = 'zello_backup_' + dt + '.json';
      document.body.appendChild(a);
      a.click();
      setTimeout(function(){ URL.revokeObjectURL(url); a.remove(); }, 100);

      status.style.color = '#2E7D32';
      status.innerHTML = '✅ Backup baixado: <strong>' + totalRegs + ' registros</strong> em ' + tabelas.length + ' tabelas. Guarde o arquivo em local seguro.';
    } catch(e) {
      status.style.color = '#C62828';
      status.innerHTML = '❌ Erro ao gerar backup: ' + (e.message || e);
      console.error('Backup error:', e);
    }
  }

  function restaurarBackup(evento) {
    const arquivo = evento.target.files[0];
    if (!arquivo) return;
    const status = document.getElementById('cfg-backup-status');

    const reader = new FileReader();
    reader.onload = async function(ev) {
      let backup;
      try {
        backup = JSON.parse(ev.target.result);
      } catch(e) {
        status.style.color = '#C62828';
        status.innerHTML = '❌ Arquivo inválido: não é um JSON válido.';
        return;
      }

      if (!backup._meta || !backup.clientes) {
        status.style.color = '#C62828';
        status.innerHTML = '❌ Arquivo não parece ser um backup válido do Zello (faltam metadados).';
        return;
      }

      const tabelas = ['clientes','propriedades','usos','contatos','leituras','notificacoes'];
      const totais = tabelas.map(function(t){ return t + ': ' + (backup[t] || []).length; }).join('\n• ');

      // Dupla confirmação porque é destrutivo
      const c1 = confirm('⚠️ ATENÇÃO!\n\nVai RESTAURAR o backup feito em ' + new Date(backup._meta.gerado_em).toLocaleString('pt-BR') + '.\n\nConteúdo:\n• ' + totais + '\n\nIMPORTANTE: este backup será INSERIDO no banco. Se houver registros com mesmo ID, vai dar erro.\n\nRecomendação: faça um backup ANTES, caso queira voltar.\n\nProsseguir?');
      if (!c1) { evento.target.value = ''; return; }

      const c2 = prompt('Para confirmar, digite RESTAURAR (em maiúsculas):');
      if (c2 !== 'RESTAURAR') {
        status.innerHTML = 'Restauração cancelada.';
        evento.target.value = '';
        return;
      }

      status.style.color = '#1565C0';
      status.innerHTML = '⏳ Restaurando backup...';

      let totalInserido = 0, erros = [];
      // Ordem importante por causa das foreign keys
      for (let i = 0; i < tabelas.length; i++) {
        const t = tabelas[i];
        const regs = backup[t] || [];
        if (!regs.length) continue;
        status.innerHTML = '⏳ Restaurando ' + t + ' (' + regs.length + ' registros)...';
        try {
          // Insere em lotes de 100
          for (let j = 0; j < regs.length; j += 100) {
            const lote = regs.slice(j, j + 100);
            const r = await api(t, 'POST', lote, 'return=minimal');
            if (r && r.ok) totalInserido += lote.length;
            else {
              const txt = r ? await r.text() : 'sem resposta';
              erros.push(t + ': ' + txt.substring(0,100));
              break;
            }
          }
        } catch(e) {
          erros.push(t + ': ' + (e.message || e));
        }
      }

      if (erros.length) {
        status.style.color = '#C62828';
        status.innerHTML = '⚠️ Restauração com ' + erros.length + ' erro(s). Inseridos ' + totalInserido + ' registros.<br/>Erros: ' + erros.join('; ');
      } else {
        status.style.color = '#2E7D32';
        status.innerHTML = '✅ Backup restaurado! ' + totalInserido + ' registros inseridos.';
        await carregarDados();
      }
      evento.target.value = '';
    };
    reader.readAsText(arquivo);
  }

  function limparConfigsLocais() {
    if (!confirm('⚠️ Isso vai apagar TODAS as preferências salvas localmente:\n\n• Credenciais do Supabase\n• Dados do responsável técnico\n• Ordem do menu\n• URL do formulário do cliente\n\nOs DADOS DO BANCO não serão afetados, apenas as configurações deste navegador.\n\nProsseguir?')) return;

    const chaves = ['z_url','z_key','z_cliurl','z_eng_nome','z_eng_crea','z_eng_tel','z_eng_email','z_eng_empresa','z_menu_ordem','z_pend_concluidos'];
    chaves.forEach(function(k){ try { localStorage.removeItem(k); } catch(e) {} });

    zAlert('✅ Preferências locais limpas. A página vai recarregar.', 'aviso');
    location.reload();
  }

  const hdrs = function() { return { 'apikey': SUPABASE_KEY, 'Authorization': 'Bearer ' + SUPABASE_KEY, 'Content-Type': 'application/json' }; };

  // ONDA C.2: api() com retry inteligente para falhas transitórias.
  // - Retry só em métodos IDEMPOTENTES (GET, PATCH, DELETE). POST não pode ter
  //   retry automático: corre risco de criar registros duplicados (ex: 2 leituras
  //   do mesmo mês). Para POSTs com idempotência garantida pelo schema, considere
  //   uma versão dedicada no futuro.
  // - Retry só em erros TRANSITÓRIOS: erro de rede (fetch joga exceção) ou HTTP
  //   5xx ou 429. 4xx (401/403/404/409/etc) não retenta — são erros de negócio.
  // - Backoff exponencial: 200ms, 600ms, 1500ms (3 tentativas no total).
  // - Contrato externo preserved: mesma assinatura, mesmo retorno (null no erro).

  function _apiEhRetryavel(method, statusOuErro) {
    const m = (method || 'GET').toUpperCase();
    if (m === 'POST') return false; // POST nunca retenta (não-idempotente)
    if (m !== 'GET' && m !== 'PATCH' && m !== 'DELETE' && m !== 'PUT') return false;

    // statusOuErro pode ser um número (HTTP status) ou um Error (rede)
    if (typeof statusOuErro === 'number') {
      // 5xx = servidor com problema temporário; 429 = rate limit
      return statusOuErro >= 500 || statusOuErro === 429;
    }
    // Erro de rede (fetch joga TypeError, AbortError quando navegação cancela, etc)
    if (statusOuErro && statusOuErro.name) {
      const n = statusOuErro.name;
      // AbortError = usuário fechou aba; não vale retentar nesse caso
      if (n === 'AbortError') return false;
      return true; // TypeError ('Failed to fetch'), NetworkError, etc
    }
    return false;
  }

  function _apiSleep(ms) {
    return new Promise(function(res){ setTimeout(res, ms); });
  }

  async function api(path, method, body, prefer) {
    method = (method || 'GET').toUpperCase();
    const tentativasMax = _apiEhRetryavel(method, 0) ? 3 : 1; // POST: só 1 tentativa
    const delays = [200, 600, 1500]; // ms entre tentativas (com jitter abaixo)
    let ultimoErro = null;

    for (let tentativa = 1; tentativa <= tentativasMax; tentativa++) {
      try {
        const opts = { method: method, headers: hdrs() };
        if (prefer) opts.headers['Prefer'] = prefer;
        if (body) opts.body = JSON.stringify(body);
        const r = await fetch(SUPABASE_URL + '/rest/v1/' + path, opts);

        // HTTP retorno: decide se retenta com base no status
        if (!r.ok && _apiEhRetryavel(method, r.status) && tentativa < tentativasMax) {
          console.warn('[api retry] ' + method + ' ' + path + ' HTTP ' + r.status + ' (tentativa ' + tentativa + '/' + tentativasMax + ')');
          const jitter = Math.floor(Math.random() * 100);
          await _apiSleep(delays[tentativa - 1] + jitter);
          continue;
        }

        // Resposta final (ok ou erro não-retryável)
        if (method === 'GET') return await r.json();
        return r;
      } catch(e) {
        ultimoErro = e;
        if (_apiEhRetryavel(method, e) && tentativa < tentativasMax) {
          console.warn('[api retry] ' + method + ' ' + path + ' erro="' + (e.message || e.name) + '" (tentativa ' + tentativa + '/' + tentativasMax + ')');
          const jitter = Math.floor(Math.random() * 100);
          await _apiSleep(delays[tentativa - 1] + jitter);
          continue;
        }
        // Erro não-retryável OU esgotou tentativas
        console.error('API error:', e);
        return null;
      }
    }
    // Não deveria chegar aqui, mas por segurança
    console.error('API error (esgotou tentativas):', ultimoErro);
    return null;
  }

  async function uploadFile(bucket, path, file) {
    try {
      // Tentar POST primeiro, se falhar (arquivo existe) tenta PUT (upsert)
      const headers = { 'apikey': SUPABASE_KEY, 'Authorization': 'Bearer ' + SUPABASE_KEY, 'Content-Type': file.type || 'application/octet-stream', 'x-upsert': 'true' };
      const r = await fetch(SUPABASE_URL + '/storage/v1/object/' + bucket + '/' + path, {
        method: 'POST', headers: headers, body: file
      });
      if (r.ok) return SUPABASE_URL + '/storage/v1/object/public/' + bucket + '/' + path;
      // Se falhou, tentar PUT
      const r2 = await fetch(SUPABASE_URL + '/storage/v1/object/' + bucket + '/' + path, {
        method: 'PUT', headers: headers, body: file
      });
      if (r2.ok) return SUPABASE_URL + '/storage/v1/object/public/' + bucket + '/' + path;
      const err = await r2.json().catch(function(){return {};});
      console.error('Upload falhou:', r2.status, err);
      return null;
    } catch(e) { console.error('Upload erro:', e); return null; }
  }

  let clientes = [], propriedades = [], usos = [], leituras = [], contatos = [], documentos = [];
  let leads = [];                      // Fase 1: clientes com status_funil='prospeccao'
  let leadsPool = [];                  // FASE 14.2: leads sem hunter_id (no pool)
  let grupos = [];                     // ETAPA 2 OPÇÃO B (2026-06-02): grupos de clientes (PF+PJ unificados)
  let _usuariosCache = [];             // FASE 14.2: cache de usuários (pra bolinhas de cor)
  let clientesEmProjeto = [];          // Fase 2: clientes com status_funil='em_projeto'
  let historicoContatos = [];          // Fase 1: histórico de contatos do funil
  // POST-ONDA 4 (Follow-up): cache de tentativas de contato por lead { leadId: [registros] }
  let historicoContatosCache = {};
  let configFunil = [];                // FASE 9: colunas do kanban da Prospecção
  let _leadsExpandidos = {};           // FASE 9: {codigo: true} se coluna está expandida
  let _leadsKanbanListenersOk = false; // FASE 9: previne memory leak
  let _leadStatusInicial = 'novo';     // FASE 9: status quando criar lead em coluna específica
  let leadAtualId = null;              // ID do lead aberto no modal "ver lead"
  let projetos = [];                   // Fase 2: projetos ativos (cliente em_projeto)
  let cidadesCache = [];
  let clienteAtualId = null;
  let propAtualId = null;
  let dadosImportLeads = null;         // dados parseados da planilha de prospecção
  // ONDA 3.5: contexto pra reabrir modal anterior após editar prop/ponto
  let _contextoAnteriorModal = null;   // 'cliente' | 'projeto' | null
  let _contextoAnteriorId = null;

  // POST-ONDA 4 (Bloco 2): normaliza o "papel" de um contato importado.
  // A planilha permite papéis específicos (conjuge, gerente, advogado...).
  // Mas o resto do sistema só reconhece 'responsavel_legal' como representante
  // legal de PJ. Esta função decide: papéis de representação legal viram
  // 'responsavel_legal'; o resto fica como está.
  function _normalizarPapelContato(papelPlanilha) {
    const p = String(papelPlanilha || '').toLowerCase().trim();
    // Papéis que representam legalmente a pessoa/empresa → responsavel_legal
    const papeisRepLegal = ['conjuge', 'cônjuge', 'socio', 'sócio', 'gerente',
      'advogado', 'procurador', 'administrador', 'representante', 'responsavel_legal',
      'responsável legal', 'diretor', 'pai_mae', 'filho_filha', 'irmao_irma'];
    if (papeisRepLegal.indexOf(p) >= 0) return 'responsavel_legal';
    // 'intermediador', 'contador', 'outro' e desconhecidos → mantém como veio
    return p || 'outro';
  }

  function getMes() { const n = new Date(); return n.getFullYear() + '-' + String(n.getMonth()+1).padStart(2,'0'); }

  // POST-ONDA 4 (Bloco 2): busca unificada de pessoa por ID.
  // Lead, cliente ativo e cliente em projeto ficam em listas separadas no front
  // (mas são a mesma tabela 'clientes' no banco). Antes, cada parte do código
  // buscava só em UMA lista — o que dava "não encontrado" quando a pessoa mudava
  // de fase. Esta função procura em todas as listas e retorna a 1ª ocorrência.
  function acharPessoa(id) {
    if (!id) return null;
    const listas = [
      typeof clientes !== 'undefined' ? clientes : null,
      typeof leads !== 'undefined' ? leads : null,
      typeof clientesEmProjeto !== 'undefined' ? clientesEmProjeto : null,
      typeof leadsPool !== 'undefined' ? leadsPool : null,
    ];
    for (let i = 0; i < listas.length; i++) {
      const lista = listas[i];
      if (!lista || !lista.length) continue;
      const achado = lista.find(function(p){ return p && p.id === id; });
      if (achado) return achado;
    }
    return null;
  }

  // ============================================================
  // ETAPA 2 OPÇÃO B (2026-06-02): Helpers de agrupamento de clientes
  // Permitem ver clientes vinculados (ex: ADRIANO PF + ADRIANO PJ) como uma
  // entidade lógica, sem perder os cadastros separados no banco.
  // Sempre testam null/undefined — nenhuma quebra se cliente não tem grupo.
  // ============================================================

  // Dado um cliente_id, retorna o objeto do grupo (linha da tabela grupos_clientes)
  // ou null se: cliente não existe, não tem grupo_id, ou grupo não foi carregado.
  function obterGrupoDoCliente(cid) {
    if (!cid) return null;
    const c = acharPessoa(cid);
    if (!c || !c.grupo_id) return null;
    return (grupos || []).find(function(g){ return g && g.id === c.grupo_id; }) || null;
  }

  // Dado um grupo_id, retorna array de TODOS os clientes que pertencem a ele.
  // Inclui clientes em qualquer status (ativos, leads, em projeto).
  function obterClientesDoGrupo(gid) {
    if (!gid) return [];
    const todos = [].concat(
      typeof clientes !== 'undefined' ? clientes : [],
      typeof leads !== 'undefined' ? leads : [],
      typeof clientesEmProjeto !== 'undefined' ? clientesEmProjeto : [],
      typeof leadsPool !== 'undefined' ? leadsPool : []
    );
    // Pode ter o mesmo cliente em mais de uma lista (ex: em_renovacao). Deduplica por id.
    const vistos = {};
    const resultado = [];
    todos.forEach(function(c){
      if (c && c.grupo_id === gid && !vistos[c.id]) {
        vistos[c.id] = true;
        resultado.push(c);
      }
    });
    return resultado;
  }

  // Dado 1 cliente_id, retorna os OUTROS clientes do mesmo grupo (sem ele mesmo).
  // Útil pra "quem mais está vinculado a essa pessoa?".
  function obterClientesIrmaos(cid) {
    if (!cid) return [];
    const c = acharPessoa(cid);
    if (!c || !c.grupo_id) return [];
    return obterClientesDoGrupo(c.grupo_id).filter(function(cc){ return cc.id !== cid; });
  }

  // Boolean — true se o cliente tem grupo E o grupo tem mais de 1 cliente (vinculação real).
  // Um cliente com grupo_id que aponta pra grupo só com ele mesmo é "tecnicamente agrupado"
  // mas funcionalmente é igual a não ter grupo. Esse helper trata isso.
  function clienteEstaAgrupado(cid) {
    if (!cid) return false;
    const irmaos = obterClientesIrmaos(cid);
    return irmaos.length > 0;
  }

  // Retorna array de IDs (do cliente + irmãos). Útil pra filtros tipo
  //   propriedades.filter(p => idsDoGrupo.includes(p.cliente_id))
  // Se cliente não tem grupo, retorna só o ID dele (compatibilidade — sempre dá pra usar).
  function obterTodosIdsDoGrupo(cid) {
    if (!cid) return [];
    const c = acharPessoa(cid);
    if (!c) return [];
    if (!c.grupo_id) return [cid];
    return obterClientesDoGrupo(c.grupo_id).map(function(cc){ return cc.id; });
  }

  // Dado um cliente_id, retorna 'PF' (CPF, 11 dígitos) ou 'PJ' (CNPJ, 14 dígitos) ou '?' (sem documento).
  // Usado pra colocar badges nos pontos/contatos/documentos quando há vínculos.
  function obterTipoPessoa(cid) {
    const c = acharPessoa(cid);
    if (!c || !c.cpf_cnpj) return '?';
    const dig = c.cpf_cnpj.replace(/\D/g, '');
    if (dig.length === 14) return 'PJ';
    if (dig.length === 11) return 'PF';
    return '?';
  }

  // Renderiza um badge pequeno [PF] ou [PJ]. Só aparece se o cliente ESTÁ AGRUPADO
  // (não tem sentido marcar PF quando não há PJ pra distinguir). Vazio se solo.
  function badgeTipoPessoaHtml(cid) {
    if (!clienteEstaAgrupado(cid)) return '';
    const tipo = obterTipoPessoa(cid);
    if (tipo === 'PF') {
      return '<span style="display:inline-block;background:#E0F2FE;color:#075985;font-size:9px;font-weight:700;padding:1px 5px;border-radius:4px;margin-left:4px;vertical-align:middle;border:1px solid #BAE6FD;" title="Cadastro pessoa física">👤 PF</span>';
    }
    if (tipo === 'PJ') {
      return '<span style="display:inline-block;background:#FEF3C7;color:#854D0E;font-size:9px;font-weight:700;padding:1px 5px;border-radius:4px;margin-left:4px;vertical-align:middle;border:1px solid #FDE68A;" title="Cadastro pessoa jurídica">🏢 PJ</span>';
    }
    return '';
  }

  // Expõe no window pra debug via console (você pode testar no F12)
  window._zGrupos = {
    obterGrupoDoCliente: obterGrupoDoCliente,
    obterClientesDoGrupo: obterClientesDoGrupo,
    obterClientesIrmaos: obterClientesIrmaos,
    clienteEstaAgrupado: clienteEstaAgrupado,
    obterTodosIdsDoGrupo: obterTodosIdsDoGrupo,
    obterTipoPessoa: obterTipoPessoa
  };

  // ============================================================
  // ETAPA 5 OPÇÃO B (2026-06-02): Agrupamento na lista de Clientes
  // ============================================================

  // Estado: lista agrupada por default. Pode ser desligado pelo toggle.
  let _clientesAgrupado = true;

  // Dado uma lista de clientes, devolve nova lista colapsando vinculados.
  // Cada grupo vira 1 entrada — representada pelo PRINCIPAL (cliente_principal_id) ou,
  // se não houver, pelo primeiro do grupo presente na lista. Clientes sem grupo passam direto.
  // Cada entrada agrupada ganha campos extras: _ehGrupoAgrupado=true, _idsDoGrupo, _membrosGrupo.
  function _agruparClientesPorGrupo(lista) {
    if (!_clientesAgrupado) return lista; // toggle desligado → comportamento antigo
    const resultado = [];
    const gruposJaVistos = {}; // grupo_id → true
    lista.forEach(function(c) {
      if (!c) return;
      if (!c.grupo_id) { resultado.push(c); return; }
      // Cliente vinculado: usa o representante do grupo
      if (gruposJaVistos[c.grupo_id]) return; // já adicionou este grupo
      gruposJaVistos[c.grupo_id] = true;
      // Pega TODOS os membros do grupo (não só os da lista filtrada — pra contadores corretos)
      const membrosTodos = obterClientesDoGrupo(c.grupo_id);
      // Filtra só os que estão na lista atual (respeitando filtros aplicados antes)
      const idsNaLista = {};
      lista.forEach(function(cc){ if (cc) idsNaLista[cc.id] = true; });
      const membrosNaLista = membrosTodos.filter(function(cc){ return idsNaLista[cc.id]; });
      if (!membrosNaLista.length) return; // segurança
      // Decide o "representante" do grupo: prioriza o principal SE está na lista filtrada,
      // senão usa o próprio `c` (que foi o cliente que apareceu na lista pela busca/filtro).
      // Importante: se busquei "08.775" e achei o PJ, faz sentido o PJ ser o representante
      // da linha — não o PF (que é o principal mas não bateu na busca).
      const g = obterGrupoDoCliente(c.id);
      let principal = null;
      if (g && g.cliente_principal_id) {
        principal = membrosNaLista.find(function(cc){ return cc.id === g.cliente_principal_id; });
      }
      if (!principal) principal = c; // fallback: o cliente que veio da busca
      // Cria objeto representante: cópia rasa com metadados do grupo
      const rep = Object.assign({}, principal, {
        _ehGrupoAgrupado: true,
        _idsDoGrupo: membrosNaLista.map(function(cc){ return cc.id; }),
        _membrosGrupo: membrosNaLista,
        _grupoObj: g
      });
      resultado.push(rep);
    });
    return resultado;
  }

  // Liga/desliga o toggle de agrupamento. Chamado pelo botão no HTML.
  function toggleAgruparClientes() {
    _clientesAgrupado = !_clientesAgrupado;
    // Atualiza o visual do botão
    const btn = document.getElementById('btn-toggle-agrupar');
    if (btn) {
      btn.textContent = _clientesAgrupado ? '🔗 Agrupado' : '📋 Separado';
      btn.title = _clientesAgrupado
        ? 'Clientes vinculados aparecem como 1 linha. Clique pra ver separadamente.'
        : 'Clientes vinculados aparecem em linhas separadas. Clique pra agrupar.';
      btn.style.background = _clientesAgrupado ? '#F0F9FF' : '';
      btn.style.color = _clientesAgrupado ? '#0369A1' : '';
      btn.style.borderColor = _clientesAgrupado ? '#BAE6FD' : '';
    }
    // Re-renderiza respeitando filtros atuais
    const inp = document.getElementById('busca-clientes');
    if (typeof filtrarClientes === 'function') {
      filtrarClientes(inp ? inp.value : '');
    } else if (typeof renderClientes === 'function') {
      renderClientes(_listaUnificadaAbaClientes());
    }
  }
  window.toggleAgruparClientes = toggleAgruparClientes;

  // Status misto: dado um array de clientes do grupo, retorna a label combinada.
  // - Se TODOS são 'cliente_ativo' → "🟢 Ativo"
  // - Se TODOS são 'em_projeto' → "🏗 Em projeto"
  // - Se misturado → "🟢 Ativo + 🏗 Em projeto" (decisão 3 da Etapa 0)
  function statusMistoDoGrupo(membros) {
    if (!membros || !membros.length) return null;
    const statuses = {};
    membros.forEach(function(c){ statuses[c.status_funil || 'cliente_ativo'] = true; });
    const tipos = Object.keys(statuses);
    const temAtivo = !!statuses['cliente_ativo'];
    const temProjeto = !!statuses['em_projeto'];
    if (tipos.length === 1) {
      if (temAtivo) return { html: '<span style="background:#E8F5E9;color:#2E7D32;font-size:10px;font-weight:700;padding:3px 8px;border-radius:999px;" title="Cliente com outorga publicada">🟢 Ativo</span>', misto: false };
      if (temProjeto) return { html: '<span style="background:#DBEAFE;color:#1E40AF;font-size:10px;font-weight:700;padding:3px 8px;border-radius:999px;" title="Cliente com projeto em andamento">🏗 Em projeto</span>', misto: false };
      return null;
    }
    // Misto
    let html = '';
    if (temAtivo) html += '<span style="background:#E8F5E9;color:#2E7D32;font-size:10px;font-weight:700;padding:3px 8px;border-radius:999px;" title="Pelo menos 1 cadastro do grupo está ativo">🟢 Ativo</span>';
    if (temProjeto) html += (html?' ':'') + '<span style="background:#DBEAFE;color:#1E40AF;font-size:10px;font-weight:700;padding:3px 8px;border-radius:999px;" title="Pelo menos 1 cadastro do grupo está em projeto">🏗 Em projeto</span>';
    return { html: html, misto: true };
  }
  // ============================================================
  // Fim Etapa 5 — Agrupamento de lista
  // ============================================================
  // ============================================================
  // Fim Etapa 2 — Helpers
  // ============================================================


  // ============================================================
  // ETAPA 3 OPÇÃO B (2026-06-02): Vinculação de clientes (UI + lógica)
  // Permite ao admin agrupar 2+ cadastros (PF + PJ) como "mesma pessoa".
  // Cada cliente mantém seus dados; só ganham um grupo_id em comum.
  // ============================================================

  // Estado interno do modal de vinculação (qual cliente é a "origem" do vínculo)
  let _vincularOrigemId = null;

  // Renderiza a seção "Vinculado a" no modal ver-cliente.
  // Mostra os clientes vinculados (se houver) + botão "Vincular a outro cliente".
  function renderSecaoVinculados(cid) {
    const el = document.getElementById('ver-cliente-vinculos');
    if (!el) return;
    const c = acharPessoa(cid);
    if (!c) { el.innerHTML = ''; return; }

    const irmaos = obterClientesIrmaos(cid);
    let html = '';

    if (irmaos.length > 0) {
      // Tem vínculos — lista cada irmão com botões [ir] e [desvincular]
      html += '<div style="background:#F0F9FF;border:1px solid #BAE6FD;border-radius:8px;padding:10px 12px;">'
            + '<div style="font-size:11px;font-weight:700;color:#0369A1;margin-bottom:6px;text-transform:uppercase;letter-spacing:0.3px;">🔗 Vinculado a</div>';
      irmaos.forEach(function(irmao){
        const docDig = (irmao.cpf_cnpj || '').replace(/\D/g, '');
        const tipo = docDig.length === 14 ? 'CNPJ' : (docDig.length === 11 ? 'CPF' : 'Documento');
        html += '<div style="display:flex;align-items:center;justify-content:space-between;gap:8px;padding:6px 0;border-top:1px solid rgba(186,230,253,0.5);">'
              +   '<div style="flex:1;min-width:0;">'
              +     '<div style="font-size:12.5px;font-weight:600;color:var(--text);">' + escapeHtml(irmao.nome || '—') + '</div>'
              +     '<div style="font-size:11px;color:var(--text-muted);">' + tipo + ': ' + escapeHtml(irmao.cpf_cnpj || '—') + '</div>'
              +   '</div>'
              +   '<div style="display:flex;gap:4px;flex-shrink:0;">'
              +     '<button class="btn btn-sm" onclick="verCliente(\'' + irmao.id + '\')" title="Abrir esse cadastro">→ Ir</button>'
              +     '<button class="btn btn-sm" onclick="desvincularDoGrupo(\'' + irmao.id + '\')" title="Desvincular esse cadastro" style="background:#FEE2E2;color:#991B1B;border:1px solid #FECACA;">✕</button>'
              +   '</div>'
              + '</div>';
      });
      // Botão pra vincular MAIS um
      html += '<div style="margin-top:8px;padding-top:8px;border-top:1px solid rgba(186,230,253,0.5);">'
            +   '<button class="btn btn-sm" onclick="abrirVincularCliente(\'' + cid + '\')" style="background:#fff;color:#0369A1;border:1px solid #BAE6FD;">🔗 Vincular a mais um</button>'
            + '</div>'
            + '</div>';
    } else {
      // Sem vínculos — só o botão "vincular"
      html += '<div style="display:flex;justify-content:flex-end;">'
            +   '<button class="btn btn-sm" onclick="abrirVincularCliente(\'' + cid + '\')" style="background:#F0F9FF;color:#0369A1;border:1px solid #BAE6FD;" title="Vincular este cadastro a outro (ex: PF + PJ da mesma pessoa)">🔗 Vincular a outro cliente</button>'
            + '</div>';
    }
    el.innerHTML = html;
  }
  window.renderSecaoVinculados = renderSecaoVinculados;

  // Abre o modal de seleção de cliente pra vincular
  function abrirVincularCliente(cid) {
    _vincularOrigemId = cid;
    const c = acharPessoa(cid);
    if (!c) return;
    const docDig = (c.cpf_cnpj || '').replace(/\D/g, '');
    const tipo = docDig.length === 14 ? 'CNPJ' : (docDig.length === 11 ? 'CPF' : 'Documento');
    const origemEl = document.getElementById('vincular-cliente-origem');
    if (origemEl) {
      origemEl.innerHTML = 'Vincular <strong>' + escapeHtml(c.nome) + '</strong> (' + tipo + ' ' + escapeHtml(c.cpf_cnpj || '—') + ') a:';
    }
    const buscaEl = document.getElementById('vincular-busca');
    if (buscaEl) buscaEl.value = '';
    renderListaVincular();
    abrirModal('ov-vincular-cliente');
    // Foca no campo de busca pra você já digitar
    setTimeout(function(){ if (buscaEl) buscaEl.focus(); }, 100);
  }
  window.abrirVincularCliente = abrirVincularCliente;

  // Renderiza a lista de clientes disponíveis pra vincular (filtrada pela busca)
  function renderListaVincular() {
    const lista = document.getElementById('vincular-lista');
    if (!lista || !_vincularOrigemId) return;
    const cOrigem = acharPessoa(_vincularOrigemId);
    if (!cOrigem) return;
    const q = (document.getElementById('vincular-busca') || {}).value || '';
    const qNorm = _strNormBusca(q);
    const qDig = q.replace(/\D/g, '');

    // Junta clientes ativos + em projeto + leads em renovação (não inclui leads puros — não faz sentido vincular lead)
    const candidatos = [].concat(
      typeof clientes !== 'undefined' ? clientes : [],
      typeof clientesEmProjeto !== 'undefined' ? clientesEmProjeto : []
    );
    // Dedup por id (em_renovacao aparece em 2 listas)
    const vistosId = {};
    const idsJaNoGrupo = cOrigem.grupo_id
      ? obterClientesDoGrupo(cOrigem.grupo_id).map(function(c){ return c.id; })
      : [_vincularOrigemId];

    const filtrados = candidatos.filter(function(c){
      if (!c || !c.id) return false;
      if (vistosId[c.id]) return false;
      vistosId[c.id] = true;
      // Não mostra o próprio cliente
      if (c.id === _vincularOrigemId) return false;
      // Não mostra quem já está no mesmo grupo
      if (idsJaNoGrupo.indexOf(c.id) >= 0) return false;
      // Filtro de busca: nome ou CPF/CNPJ
      if (q) {
        const nomeMatch = _strNormBusca(c.nome).indexOf(qNorm) >= 0;
        const docDig = (c.cpf_cnpj || '').replace(/\D/g, '');
        const docMatch = qDig.length >= 3 && docDig.indexOf(qDig) >= 0;
        if (!nomeMatch && !docMatch) return false;
      }
      return true;
    });

    // Ordena: nomes parecidos com a origem primeiro (provável match)
    const nomeOrigemNorm = _strNormBusca(cOrigem.nome);
    filtrados.sort(function(a, b){
      const aProx = _strNormBusca(a.nome) === nomeOrigemNorm ? 0 : 1;
      const bProx = _strNormBusca(b.nome) === nomeOrigemNorm ? 0 : 1;
      if (aProx !== bProx) return aProx - bProx;
      return (a.nome || '').localeCompare(b.nome || '');
    });

    if (filtrados.length === 0) {
      lista.innerHTML = '<div style="padding:16px;text-align:center;color:var(--text-muted);font-size:12px;">'
                      + (q ? 'Nenhum cliente encontrado com "' + escapeHtml(q) + '"' : 'Nenhum cliente disponível pra vincular')
                      + '</div>';
      return;
    }

    // Sugestão automática: destaca clientes com nome IGUAL à origem
    const itens = filtrados.slice(0, 30).map(function(c){
      const docDig = (c.cpf_cnpj || '').replace(/\D/g, '');
      const tipo = docDig.length === 14 ? 'CNPJ' : (docDig.length === 11 ? 'CPF' : 'Doc');
      const nomeIgual = _strNormBusca(c.nome) === nomeOrigemNorm;
      const badgeSugestao = nomeIgual
        ? '<span style="background:#FEF3C7;color:#92400E;font-size:9px;font-weight:700;padding:2px 6px;border-radius:999px;margin-left:6px;vertical-align:middle;">⭐ MESMO NOME</span>'
        : '';
      return '<div onclick="confirmarVinculo(\'' + c.id + '\')" style="padding:10px 12px;border-bottom:1px solid var(--border);cursor:pointer;background:' + (nomeIgual ? '#FFFBEB' : 'white') + ';" onmouseover="this.style.background=\'#EFF6FF\'" onmouseout="this.style.background=\'' + (nomeIgual ? '#FFFBEB' : 'white') + '\'">'
        +   '<div style="font-size:12.5px;font-weight:600;color:var(--text);">' + escapeHtml(c.nome) + badgeSugestao + '</div>'
        +   '<div style="font-size:11px;color:var(--text-muted);margin-top:2px;">' + tipo + ': ' + escapeHtml(c.cpf_cnpj || '—') + '</div>'
        + '</div>';
    }).join('');
    const aviso = filtrados.length > 30
      ? '<div style="padding:8px;text-align:center;font-size:11px;color:var(--text-muted);background:#fafbfc;">Mostrando 30 de ' + filtrados.length + ' — refine a busca</div>'
      : '';
    lista.innerHTML = itens + aviso;
  }
  window.renderListaVincular = renderListaVincular;

  // Cria/usa o grupo e vincula os 2 clientes (chamada quando usuário clica num item da lista)
  async function confirmarVinculo(outroCid) {
    const origemId = _vincularOrigemId;
    if (!origemId || !outroCid) return;
    const cOrigem = acharPessoa(origemId);
    const cOutro = acharPessoa(outroCid);
    if (!cOrigem || !cOutro) return;

    const ok = await zConfirm(
      'Vincular estes 2 cadastros como o mesmo cliente?\n\n• ' + cOrigem.nome + ' (' + (cOrigem.cpf_cnpj || '—') + ')\n• ' + cOutro.nome + ' (' + (cOutro.cpf_cnpj || '—') + ')\n\nOs dois aparecerão juntos no painel, mas cada um mantém seu próprio CPF/CNPJ, propriedades e outorgas separadamente.',
      { tipo:'info', btnOk:'Vincular', btnCancel:'Cancelar' }
    );
    if (!ok) return;

    try {
      // Caso 1: origem JÁ tem grupo (você já vinculou antes) → só joga o outro no mesmo grupo
      if (cOrigem.grupo_id) {
        const r = await api('clientes?id=eq.' + outroCid, 'PATCH', { grupo_id: cOrigem.grupo_id }, 'return=minimal');
        if (!r || !r.ok) throw new Error('Falha ao atualizar cliente');
        // Atualiza cache local
        cOutro.grupo_id = cOrigem.grupo_id;
      }
      // Caso 2: origem NÃO tem grupo → cria grupo novo e coloca os 2 nele
      else {
        // Cria o grupo (decisão A: nome_grupo = nome do cliente principal; principal = origem)
        // POST com return=representation retorna o registro criado como array
        const r = await api('grupos_clientes', 'POST', {
          nome_grupo: cOrigem.nome,
          cliente_principal_id: origemId,
          compartilha_portal: false
        }, 'return=representation');
        if (!r || !r.ok) throw new Error('Falha ao criar grupo (HTTP ' + (r ? r.status : '?') + ')');
        const dataGrupo = await r.json();
        const grupoCriado = Array.isArray(dataGrupo) ? dataGrupo[0] : dataGrupo;
        if (!grupoCriado || !grupoCriado.id) throw new Error('Resposta sem id do grupo');
        const gid = grupoCriado.id;
        // Atualiza os 2 clientes com o grupo_id
        const r1 = await api('clientes?id=eq.' + origemId, 'PATCH', { grupo_id: gid }, 'return=minimal');
        const r2 = await api('clientes?id=eq.' + outroCid, 'PATCH', { grupo_id: gid }, 'return=minimal');
        if (!r1 || !r1.ok || !r2 || !r2.ok) throw new Error('Falha ao atualizar clientes');
        // Atualiza cache local
        cOrigem.grupo_id = gid;
        cOutro.grupo_id = gid;
        grupos.push(grupoCriado);
      }
      fecharModal('ov-vincular-cliente');
      zToast('✅ Clientes vinculados', 'sucesso');
      // Re-renderiza a seção de vínculos no modal aberto
      renderSecaoVinculados(origemId);
      // Atualiza a lista de clientes em background (pra refletir badge etc)
      if (typeof renderClientes === 'function' && typeof _listaUnificadaAbaClientes === 'function') {
        renderClientes(_listaUnificadaAbaClientes());
      }
    } catch (e) {
      console.error('Erro ao vincular:', e);
      zAlert('Erro ao vincular os clientes. Tente de novo. Detalhe: ' + (e.message || e), 'erro');
    }
  }
  window.confirmarVinculo = confirmarVinculo;

  // Desvincula UM cliente do grupo. Se sobrar 1 ou 0 no grupo, deleta o grupo (banco limpo).
  async function desvincularDoGrupo(cid) {
    const c = acharPessoa(cid);
    if (!c || !c.grupo_id) return;
    const gid = c.grupo_id;

    const ok = await zConfirm(
      'Desvincular ' + c.nome + ' do grupo?\n\nEle voltará a ser um cadastro separado. Os outros clientes do grupo não são afetados.',
      { tipo:'aviso', btnOk:'Desvincular', btnCancel:'Cancelar' }
    );
    if (!ok) return;

    try {
      const r = await api('clientes?id=eq.' + cid, 'PATCH', { grupo_id: null }, 'return=minimal');
      if (!r || !r.ok) throw new Error('Falha ao desvincular');
      c.grupo_id = null;

      // Verifica quantos sobram no grupo. Se sobrar 0 ou 1, deleta o grupo
      const sobreviventes = obterClientesDoGrupo(gid);
      if (sobreviventes.length <= 1) {
        // Limpa o grupo_id do último sobrevivente (se houver) antes de apagar o grupo
        if (sobreviventes.length === 1) {
          const ultimoId = sobreviventes[0].id;
          const r2 = await api('clientes?id=eq.' + ultimoId, 'PATCH', { grupo_id: null }, 'return=minimal');
          if (r2 && r2.ok) {
            const cu = acharPessoa(ultimoId);
            if (cu) cu.grupo_id = null;
          }
        }
        // Agora deleta o grupo (já não tem mais ninguém apontando pra ele)
        const r3 = await api('grupos_clientes?id=eq.' + gid, 'DELETE', null, 'return=minimal');
        if (r3 && r3.ok) {
          // Remove do cache local
          const idx = grupos.findIndex(function(g){ return g.id === gid; });
          if (idx >= 0) grupos.splice(idx, 1);
        }
      }

      zToast('✅ Desvinculado', 'sucesso');
      // Re-renderiza a seção (no modal aberto, que é do cliente original)
      if (clienteAtualId) renderSecaoVinculados(clienteAtualId);
      // Atualiza a lista de clientes em background
      if (typeof renderClientes === 'function' && typeof _listaUnificadaAbaClientes === 'function') {
        renderClientes(_listaUnificadaAbaClientes());
      }
    } catch (e) {
      console.error('Erro ao desvincular:', e);
      zAlert('Erro ao desvincular. Tente de novo. Detalhe: ' + (e.message || e), 'erro');
    }
  }
  window.desvincularDoGrupo = desvincularDoGrupo;

  // ============================================================
