  var _savingCliente = false;
  async function salvarClienteESair() {
    if (_savingCliente) return;
    _savingCliente = true;
    try {
      var ok = await _salvarClienteInterno();
      if(ok) { fecharModal('ov-cliente'); await carregarDados(); }
    } finally { _savingCliente = false; }
  }

  async function salvarCliente() {
    if (_savingCliente) return;
    _savingCliente = true;
    try {
      var eid = document.getElementById('eid-cliente').value;
      var ok = await _salvarClienteInterno();
      if(!ok) return;
      if(eid) {
        fecharModal('ov-cliente');
        await carregarDados();
        zAlert('Cliente atualizado com sucesso!', 'sucesso');
      } else {
        fecharModal('ov-cliente');
        await carregarDados();
        _abrirEtapa2();
      }
    } finally { _savingCliente = false; }
  }

  async function _salvarClienteInterno() {
    var nome = document.getElementById('c-nome').value.trim();
    var doc = document.getElementById('c-doc').value.trim();
    var tel = document.getElementById('c-tel1').value.trim();
    var email = document.getElementById('c-email').value.trim();
    if(!nome) { zAlert('Nome é obrigatório.', 'aviso'); return false; }
    if(!doc) { zAlert('CPF/CNPJ é obrigatório.', 'aviso'); return false; }
    var isCNPJ = doc.replace(/\D/g,'').length > 11;

    // Validação de dígitos verificadores
    if (!validarDocumento(doc)) {
      zAlert((isCNPJ?'CNPJ':'CPF') + ' inválido. Confira os dígitos.', 'aviso');
      return false;
    }

    // Validação de email se preenchido
    if (email && !validarEmail(email)) {
      zAlert('E-mail inválido. Confira o formato.', 'aviso');
      return false;
    }

    // POST-ONDA 4 (Bloco 3): valida e-mail da nota fiscal se preenchido
    var _emailNfEl = document.getElementById('c-email-nf');
    var _emailNf = _emailNfEl ? _emailNfEl.value.trim() : '';
    if (_emailNf && !validarEmail(_emailNf)) {
      zAlert('E-mail para nota fiscal inválido. Confira o formato.', 'aviso');
      return false;
    }

    // Validação de telefone (mínimo 10 dígitos = DDD + 8 ou 9)
    var telDig = (tel||'').replace(/\D/g,'');
    if (tel && telDig.length < 10) {
      zAlert('Telefone incompleto. Use formato (XX) 9XXXX-XXXX.', 'aviso');
      return false;
    }

    var respLegais = coletarResponsaveisLegais();
    if(isCNPJ && respLegais.length === 0) {
      zAlert('Para empresas, informe ao menos um responsável legal.', 'aviso'); return false;
    }

    // Validar CPF de cada responsável legal
    for (var rli = 0; rli < respLegais.length; rli++) {
      var rl = respLegais[rli];
      if (!rl.cpf || rl.cpf.replace(/\D/g,'').length === 0) {
        zAlert('Responsável legal "' + rl.nome + '" — CPF é obrigatório.', 'aviso');
        return false;
      }
      if (!validarCPF(rl.cpf)) {
        zAlert('CPF do responsável legal "' + rl.nome + '" é inválido.', 'aviso');
        return false;
      }
    }

    var eid = document.getElementById('eid-cliente').value;

    // Validação de CPF/CNPJ duplicado — comparação só por dígitos
    // BUG FIX 2026-05-27: ANTES só checava 'clientes' (ativos).
    // Resultado: se o doc já existia como lead OU em projeto, criava DUPLICADO.
    // Agora varre TODAS as listas (clientes + leads + emProjeto + leadsPool).
    var docDigitos = doc.replace(/\D/g,'');
    var _todasListasDup = [].concat(
      typeof clientes !== 'undefined' ? clientes : [],
      typeof leads !== 'undefined' ? leads : [],
      typeof clientesEmProjeto !== 'undefined' ? clientesEmProjeto : [],
      typeof leadsPool !== 'undefined' ? leadsPool : []
    );
    var duplicado = _todasListasDup.find(function(cc){
      if (!cc) return false;
      var cdig = (cc.cpf_cnpj||'').replace(/\D/g,'');
      // Em edição, ignorar o próprio cliente
      if (eid && cc.id === eid) return false;
      return cdig && cdig === docDigitos;
    });
    if (duplicado) {
      zAlert('⚠️ Já existe um cliente cadastrado com este ' + (isCNPJ?'CNPJ':'CPF') + ':\n\n' +
            '• ' + duplicado.nome + '\n' +
            '• Documento: ' + (duplicado.cpf_cnpj||'') + '\n\n' +
            'Não é possível cadastrar o mesmo titular duas vezes. ' +
            'Se desejar adicionar uma nova propriedade ou ponto a este cliente, ' +
            'use o botão "Ver" na lista de clientes.', 'aviso');
      return false;
    }

    // BUG FIX 2026-05-26: payload base SEM status_funil.
    // Antes, qualquer EDIÇÃO de cliente forçava status_funil='cliente_ativo',
    // o que estragava clientes em outras etapas do funil (prospeccao, em_projeto).
    // Agora: INSERT seta cliente_ativo como default (compat com fluxo legado),
    // PATCH NÃO mexe em status_funil — preserva o que estiver lá.
    var payload = { nome: upper(nome), cpf_cnpj: doc, telefone1: tel||null, email: email||null, ativo: true };

    // POST-ONDA 4 (Bloco 3): dados fiscais de PJ — só grava se for CNPJ
    if (isCNPJ) {
      var _vCampo = function(id){ var el = document.getElementById(id); return el && el.value.trim() ? el.value.trim() : null; };
      // POST-ONDA 4: razão social = o próprio nome do cliente (campo único, sem duplicar)
      payload.razao_social      = upper(nome);
      payload.nome_fantasia     = _vCampo('c-nome-fantasia') ? upper(_vCampo('c-nome-fantasia')) : null;
      payload.inscricao_estadual  = _vCampo('c-insc-estadual');
      payload.inscricao_municipal = _vCampo('c-insc-municipal');
      payload.email_nf          = _vCampo('c-email-nf');
    } else {
      // PF: garante que campos fiscais fiquem nulos (caso edição tenha trocado de CNPJ p/ CPF)
      payload.razao_social = null;
      payload.nome_fantasia = null;
      payload.inscricao_estadual = null;
      payload.inscricao_municipal = null;
      payload.email_nf = null;
    }

    var cid;
    if(eid) {
      // PATCH (edição): NÃO toca em status_funil — preserva valor atual.
      // Isso evita que editar dados básicos (nome, tel, email) "promova" um lead
      // ou cliente em projeto pra cliente_ativo indevidamente.
      await api('clientes?id=eq.'+eid, 'PATCH', payload, 'return=minimal');
      cid = eid;
    } else {
      // INSERT: fluxo legado do botão "+ Novo cliente" cria já como ativo.
      // (leads são criados por outro caminho, status_funil='prospeccao')
      payload.status_funil = 'cliente_ativo';
      var r = await api('clientes?select=id,nome,cpf_cnpj,status_funil', 'POST', payload, 'return=representation');
      console.log('[Zello] POST clientes status:', r ? r.status : 'null');
      if(!r || !r.ok) {
        var errText = r ? await r.text() : 'sem resposta';
        console.error('[Zello] Erro clientes:', errText);
        zAlert('Erro ao salvar cliente: ' + errText.substring(0,200), 'erro'); return false;
      }
      var d = await r.json(); cid = d[0] && d[0].id;
      console.log('[Zello] Cliente salvo, id:', cid);
      if(!cid) { zAlert('Erro ao obter ID do cliente.', 'erro'); return false; }
    }
    clienteAtualId = cid;

    // Sempre limpa todos os contatos do cliente antes de re-inserir, em qualquer modo
    // (novo cadastro ou edição). Isso impede duplicatas se o usuário clica salvar duas
    // vezes ou se o fluxo de edição não tiver feito o DELETE corretamente.
    await api('contatos?cliente_id=eq.'+cid, 'DELETE', null, 'return=minimal');

    // Deduplica responsáveis legais por (nome+cpf) e contatos extras por (nome+telefone)
    // antes de gravar — mesmo se o usuário tiver adicionado o mesmo duas vezes na tela.
    var rlVistos = {};
    var rlDedup = [];
    for (var i=0; i<respLegais.length; i++) {
      var rl = respLegais[i];
      var k = (rl.nome||'').trim().toUpperCase() + '|' + (rl.cpf||'').replace(/\D/g,'');
      if (rlVistos[k]) continue;
      rlVistos[k] = true;
      rlDedup.push(rl);
    }
    for (var i2=0; i2<rlDedup.length; i2++) {
      var rl2 = rlDedup[i2];
      // BUG CRÍTICO corrigido: a coluna no banco é 'cpf_cnpj', não 'cpf'.
      // Por isso o CPF do responsável legal não salvava.
      await api('contatos', 'POST', { cliente_id: cid, nome: rl2.nome, cpf_cnpj: rl2.cpf || null, papel: rl2.papel, telefone: rl2.telefone, email: rl2.email, principal: rl2.principal }, 'return=minimal');
    }

    var extras = coletarContatosExtras();
    var ctVistos = {};
    var ctDedup = [];
    for (var j=0; j<extras.length; j++) {
      var ct = extras[j];
      var k2 = (ct.nome||'').trim().toUpperCase() + '|' + ((ct.telefone||'').replace(/\D/g,'')) + '|' + (ct.papel||'');
      if (ctVistos[k2]) continue;
      ctVistos[k2] = true;
      ctDedup.push(ct);
    }
    for (var j2=0; j2<ctDedup.length; j2++) {
      var ct2 = ctDedup[j2];
      await api('contatos', 'POST', { cliente_id: cid, nome: ct2.nome, papel: ct2.papel, telefone: ct2.telefone, email: ct2.email, principal: false }, 'return=minimal');
    }
    return true;
  }

