  async function _salvarPropInterno() {
    var nome = document.getElementById('p-nome').value.trim();
    if(!nome) { zAlert('Nome do empreendimento é obrigatório.', 'aviso'); return false; }
    if(!clienteAtualId) { zAlert('Erro: reinicie o cadastro.', 'erro'); return false; }
    var payload = {
      cliente_id: clienteAtualId,
      nome: upper(nome),
      cidade: upper(document.getElementById('p-cidade').value.trim()) || null,
      estado: document.getElementById('p-estado').value,
      ativo: true
    };

    // Helpers pra ler os campos da ficha técnica (agora dentro do mesmo form)
    function _valOr(id, fallback) {
      var el = document.getElementById(id);
      if (!el) return fallback;
      if (el.type === 'checkbox') return el.checked;
      var v = (el.value || '').trim();
      return v || fallback;
    }
    function _numOr(id) {
      var el = document.getElementById(id);
      if (!el || !el.value) return null;
      var n = parseFloat(String(el.value).replace(',', '.'));
      return isNaN(n) ? null : n;
    }

    // Identificação do imóvel + área + documentos rurais/urbanos
    payload.matricula = _valOr('fp-matricula', null);
    payload.endereco_local = _valOr('fp-endereco-local', null);
    payload.endereco_correspondencia = _valOr('fp-endereco-corresp', null);
    payload.area_tipo = _valOr('fp-area-tipo', null);
    payload.area_hectares = _numOr('fp-area-ha');   // valor da área (em ha OU m², ver area_unidade)
    payload.area_unidade = _valOr('fp-area-unidade', 'ha');
    payload.nirf = _valOr('fp-nirf', null);
    payload.ccir = _valOr('fp-ccir', null);
    payload.car = _valOr('fp-car', null);
    payload.dcaa = _valOr('fp-dcaa', false);
    payload.iptu = _valOr('fp-iptu', null);
    payload.tem_vigilancia_sanitaria = _valOr('fp-tem-vs', false);
    payload.inscricao_vs = _valOr('fp-insc-vs', null);

    // Coordenadas pertencem aos PONTOS de captação, não à propriedade.
    var eid = document.getElementById('eid-prop').value;
    if(eid) {
      await api('propriedades?id=eq.'+eid, 'PATCH', payload, 'return=minimal');
      propAtualId = eid;
    } else {
      var r = await api('propriedades', 'POST', payload, 'return=representation');
      console.log('[Zello] POST propriedades status:', r ? r.status : 'null');
      if(!r || !r.ok) {
        var errText = r ? await r.text() : 'sem resposta';
        console.error('[Zello] Erro propriedades:', errText);
        zAlert('Erro ao salvar propriedade: ' + errText.substring(0,200), 'erro'); return false;
      }
      var d = await r.json(); propAtualId = d[0] && d[0].id;
      console.log('[Zello] Propriedade salva, id:', propAtualId);
      if(!propAtualId) { zAlert('Erro ao obter ID da propriedade.', 'erro'); return false; }
    }
    return true;
  }

