  function trocarTabProjeto(tabName) {
    document.querySelectorAll('#ov-ver-projeto .modal-tab').forEach(function(t){ t.classList.remove('active'); });
    document.querySelectorAll('#ov-ver-projeto .modal-tab-content').forEach(function(c){ c.classList.remove('active'); });
    const tab = document.querySelector('#ov-ver-projeto .modal-tab[data-tab="' + tabName + '"]');
    if (tab) tab.classList.add('active');
    // FEATURE B: timeline incluída no map
    const map = { resumo:'proj-tab-resumo', etapas:'proj-tab-etapas', timeline:'proj-tab-timeline', docs:'proj-tab-docs', financeiro:'proj-tab-financeiro', hist:'proj-tab-hist' };
    const c = document.getElementById(map[tabName] || 'proj-tab-resumo');
    if (c) c.classList.add('active');
    // FEATURE B: renderiza timeline ao ativar a aba
    if (tabName === 'timeline') {
      const p = projetos.find(function(pp){ return pp.id === projetoAtualId; });
      if (p) _renderTimelineProjeto(p);
    }
  }

  function renderEtapasProgresso(p) {
    const cont = document.getElementById('ver-proj-prog-container');
    if (!cont) return;
    const atual = p.etapa_atual;
    let html = '<div class="sec-label" style="margin-top:14px;">Progresso das etapas</div>';
    html += '<div class="etapas-prog">';
    for (let i = 1; i <= 4; i++) {
      const cls = i < atual ? 'feita' : (i === atual ? 'atual' : '');
      html += '<div class="etapa-prog-item">';
      html += '<div class="etapa-prog-bola ' + cls + '">' + (i < atual ? '✓' : i) + '</div>';
      if (i < 4) html += '<div class="etapa-prog-linha ' + (i < atual ? 'feita' : '') + '"></div>';
      html += '</div>';
    }
    html += '</div>';
    html += '<div class="etapa-prog-label">';
    for (let i = 1; i <= 4; i++) {
      const cls = i < atual ? 'feita' : (i === atual ? 'atual' : '');
      html += '<div class="' + cls + '">' + ETAPAS_PROJETO[i-1].nome + '</div>';
    }
    html += '</div>';
    cont.innerHTML = html;
  }

  function carregarEtapasTimeline(p) {
    const cont = document.getElementById('ver-proj-etapas-timeline');
    if (!cont) return;
    let html = '';
    for (let i = 1; i <= 4; i++) {
      const e = ETAPAS_PROJETO[i-1];
      const data = p[e.col];
      const status = i < p.etapa_atual ? 'concluida' : (i === p.etapa_atual ? 'atual' : 'pendente');
      const statusLabel = status === 'concluida' ? '✓ Concluída' : (status === 'atual' ? '⏳ Em andamento' : '⏸ Aguardando');
      const cor = status === 'concluida' ? '#2E7D32' : (status === 'atual' ? '#1565C0' : '#9ca3af');
      html += '<div style="display:flex;gap:12px;padding:12px 0;border-bottom:1px solid var(--border);">';
      html += '<div style="font-size:24px;width:36px;text-align:center;">' + e.icone + '</div>';
      html += '<div style="flex:1;">';
      html += '<div style="font-size:13px;font-weight:600;color:' + cor + ';">Etapa ' + i + ': ' + e.nome + '</div>';
      html += '<div style="font-size:11.5px;color:var(--text-muted);margin-top:2px;">' + statusLabel + (data ? ' em ' + fmtData(data) : '') + '</div>';
      html += '</div></div>';
    }
    cont.innerHTML = html;
  }

  async function salvarEdicaoProjeto() {
    if (!projetoAtualId) return;
    const resp = document.getElementById('ver-proj-resp').value.trim();
    const obs = document.getElementById('ver-proj-obs').value.trim();

    try {
      // POST-ONDA 4: nome e status não são mais editáveis aqui.
      // O nome do projeto vem do cliente; o status é controlado pelo kanban.
      // O campo "requerimento" do projeto foi removido da tela — não é
      // enviado no PATCH, então o valor existente na coluna é preservado.
      const payload = {
        responsavel: resp || null,
        observacoes: obs || null,
        atualizado_em: new Date().toISOString()
      };
      const r = await api('projetos?id=eq.' + projetoAtualId, 'PATCH', payload, 'return=minimal');
      if (!r || !r.ok) throw new Error('HTTP ' + (r ? r.status : '?'));

      await carregarDados();
      verProjeto(projetoAtualId);
      const btn = event && event.target;
      if (btn && btn.tagName === 'BUTTON') {
        const orig = btn.textContent;
        btn.textContent = '✓ Salvo';
        setTimeout(function(){ btn.textContent = orig; }, 1500);
      }
    } catch(e) {
      console.error('Erro salvarEdicaoProjeto:', e);
      zAlert('Erro ao salvar: ' + (e.message || e), 'erro');
    }
  }

  // SEMANA 4.19: Excluir projeto MODO TESTE — força mesmo se tem comissão paga
  // Use APENAS pra testes! Vai deletar comissões também.
  async function excluirProjetoModoTeste() {
    if (!projetoAtualId) return;
    if (!souAdmin()) { toastError('Apenas admin.'); return; }
    const p = projetos.find(function(pp){ return pp.id === projetoAtualId; });
    if (!p) return;

    // Conta comissões pra mostrar info
    let qtdComs = 0, valorComs = 0;
    try {
      const rC = await fetch(SUPABASE_URL + '/rest/v1/comissoes?projeto_id=eq.' + projetoAtualId + '&select=valor_comissao', {
        headers: { 'apikey': SUPABASE_KEY, 'Authorization': 'Bearer ' + SUPABASE_KEY }
      });
      if (rC.ok) {
        const coms = await rC.json();
        qtdComs = coms.length;
        valorComs = coms.reduce(function(s,c){ return s + parseFloat(c.valor_comissao || 0); }, 0);
      }
    } catch(e) { /* ignore */ }

    // ONDA 2: zConfirm + zPrompt em vez de nativos
    // 1ª confirmação (dupla)
    const ok1 = await zConfirm(
      '⚠️ EXCLUSÃO FORÇADA (MODO TESTE)\n\n' +
      'Projeto: ' + p.nome + '\n' +
      'Vai apagar TAMBÉM:\n' +
      '• ' + qtdComs + ' comissão(ões) — total R$ ' + valorComs.toLocaleString('pt-BR') + '\n' +
      '• Histórico de pagamentos\n' +
      '• Histórico de etapas\n' +
      '• Vínculo com documentos\n\n' +
      'Esta operação NUNCA deve ser feita em produção!\n' +
      'Use APENAS pra limpar dados de teste.',
      { tipo:'erro', titulo:'Exclusão forçada', btnOk:'Continuar', btnCancel:'Cancelar' }
    );
    if (!ok1) return;

    // 2ª confirmação: digitar EXCLUIR
    const txt = await zPrompt(
      'Digite EXCLUIR (em maiúsculas) pra confirmar:',
      '',
      { titulo:'⚠️ Última confirmação', placeholder:'EXCLUIR', btnOk:'Confirmar', tipo:'erro' }
    );
    if (txt !== 'EXCLUIR') {
      toastInfo('Cancelado.');
      return;
    }

    try {
      // 1. Deleta comissões (TODAS, mesmo pagas — MODO TESTE)
      await fetch(SUPABASE_URL + '/rest/v1/comissoes?projeto_id=eq.' + projetoAtualId, {
        method: 'DELETE',
        headers: { 'apikey': SUPABASE_KEY, 'Authorization': 'Bearer ' + SUPABASE_KEY, 'Prefer': 'return=minimal' }
      }).catch(function(e){ console.warn('Falha deletando comissões:', e); });

      // 2. Deleta projeto_pagamentos
      await api('projeto_pagamentos?projeto_id=eq.' + projetoAtualId, 'DELETE', null, 'return=minimal').catch(function(){});
      // 3. Deleta projeto_historico
      await api('projeto_historico?projeto_id=eq.' + projetoAtualId, 'DELETE', null, 'return=minimal').catch(function(){});
      // 4. Desvincula documentos
      await api('documentos?projeto_id=eq.' + projetoAtualId, 'PATCH', { projeto_id: null }, 'return=minimal').catch(function(){});
      // 5. Deleta projeto
      const r = await api('projetos?id=eq.' + projetoAtualId, 'DELETE', null, 'return=minimal');
      if (!r || !r.ok) throw new Error('HTTP ' + (r ? r.status : '?'));

      // Volta cliente pra prospecção se não tem outros projetos
      const cliId = p.cliente_id;
      const outrosProj = projetos.filter(function(pp){ return pp.cliente_id === cliId && pp.id !== projetoAtualId; });
      if (!outrosProj.length) {
        await api('clientes?id=eq.' + cliId, 'PATCH', { status_funil: 'prospeccao', status_lead: 'em_contato' }, 'return=minimal').catch(function(){});
      }

      fecharModal('ov-ver-projeto');
      projetoAtualId = null;
      await carregarDados();
      if (typeof renderKanban === 'function') renderKanban();
      if (typeof atualizarCardComissoesDashboard === 'function') atualizarCardComissoesDashboard();
      toastSuccess('🗑️ Projeto excluído (modo teste): ' + qtdComs + ' comissão(ões) também removida(s)', 5000);
    } catch(e) {
      console.error('Erro excluirProjetoModoTeste:', e);
      toastError('Erro: ' + (e.message || ''));
    }
  }

  async function excluirProjetoConfirm() {
    if (!projetoAtualId) return;
    const p = projetos.find(function(pp){ return pp.id === projetoAtualId; });
    if (!p) return;

    // FIX BUG #12: Verifica se tem comissões pagas — não pode apagar (auditoria)
    let aviso = '';
    try {
      const rC = await fetch(SUPABASE_URL + '/rest/v1/comissoes?projeto_id=eq.' + projetoAtualId + '&select=status_pagamento,valor_comissao', {
        headers: { 'apikey': SUPABASE_KEY, 'Authorization': 'Bearer ' + SUPABASE_KEY }
      });
      if (rC.ok) {
        const coms = await rC.json();
        const pagas = coms.filter(function(c){ return c.status_pagamento === 'pago'; });
        const pendentes = coms.filter(function(c){ return c.status_pagamento === 'pendente'; });
        if (pagas.length > 0) {
          zAlert('❌ Não é possível excluir este projeto.\n\nEle tem ' + pagas.length + ' comissão(ões) JÁ PAGA(s) — apagar agora quebraria a auditoria financeira.\n\nAlternativa: marque o status como "cancelado" em vez de excluir.', 'aviso');
          return;
        }
        if (pendentes.length > 0) {
          aviso = '\n\n💰 Há ' + pendentes.length + ' comissão(ões) pendente(s) (R$ ' +
            pendentes.reduce(function(s,c){ return s + parseFloat(c.valor_comissao || 0); }, 0).toLocaleString('pt-BR') +
            ') que serão MARCADAS COMO ESTORNADAS.';
        }
      }
    } catch(e) { console.warn('Erro checando comissoes:', e); }

    if (!(await zConfirm('Excluir o projeto "' + p.nome + '"?\n\nIsso vai apagar:\n• Histórico de etapas\n• Registros de pagamentos\n• Vínculo de documentos' + aviso + '\n\nO cliente NÃO será excluído. Esta ação não pode ser desfeita.', { tipo:'erro', btnOk:'Excluir projeto' }))) return;

    try {
      // FIX: a FK comissoes→projetos é NO ACTION (não-cascata). Se houver
      // qualquer comissão apontando pro projeto, o DELETE falha com erro 409.
      // Comissões PAGAS já barram a exclusão lá em cima (auditoria); aqui só
      // resta apagar as não-pagas (pendente/estornado) pra liberar o DELETE.
      await api('comissoes?projeto_id=eq.' + projetoAtualId + '&status_pagamento=neq.pago', 'DELETE', null, 'return=minimal');

      // Deleta em ordem
      await api('projeto_pagamentos?projeto_id=eq.' + projetoAtualId, 'DELETE', null, 'return=minimal');
      await api('projeto_historico?projeto_id=eq.' + projetoAtualId, 'DELETE', null, 'return=minimal');
      // Documentos: só desvincula (não apaga, podem ser do cliente em geral)
      await api('documentos?projeto_id=eq.' + projetoAtualId, 'PATCH', { projeto_id: null }, 'return=minimal');
      const r = await api('projetos?id=eq.' + projetoAtualId, 'DELETE', null, 'return=minimal');
      if (!r || !r.ok) throw new Error('HTTP ' + (r ? r.status : '?'));

      // Volta o cliente pro funil de prospecção (não pode ficar sem status válido)
      // Mas só se o cliente NÃO tem outros projetos
      const cliId = p.cliente_id;
      const outrosProj = projetos.filter(function(pp){ return pp.cliente_id === cliId && pp.id !== projetoAtualId; });
      if (!outrosProj.length) {
        await api('clientes?id=eq.' + cliId, 'PATCH', { status_funil: 'prospeccao', status_lead: 'em_contato' }, 'return=minimal');
      }

      fecharModal('ov-ver-projeto');
      projetoAtualId = null;
      await carregarDados();
      renderKanban();
      atualizarCardComissoesDashboard();
      zAlert('✓ Projeto excluído.', 'aviso');
    } catch(e) {
      console.error('Erro excluirProjeto:', e);
      zAlert('Erro ao excluir: ' + (e.message || e), 'erro');
    }
  }


  // ============================================================
  // AVANÇAR ETAPA
  // ============================================================
  function abrirAvancarEtapa() {
    if (!projetoAtualId) return;
    const p = projetos.find(function(pp){ return pp.id === projetoAtualId; });
    if (!p) return;
    if (p.etapa_atual >= 4) { zAlert('Projeto já está na etapa final. Use "📜 Registrar publicação" em cada ponto pra concluir.', 'aviso'); return; }

    const proxima = p.etapa_atual + 1;

    // FASE 14.3: valida checkboxes obrigatórios antes de avançar
    const check = verificarChecksEtapa(p, proxima);
    if (!check.ok) {
      zAlert(check.motivo, 'aviso');
      return;
    }

    document.getElementById('avancar-etapa-titulo').textContent = '→ Avançar para Etapa ' + proxima + ': ' + ETAPAS_PROJETO[proxima-1].nome;
    document.getElementById('avancar-etapa-sub').textContent = 'Concluindo: ' + ETAPAS_PROJETO[p.etapa_atual-1].nome;
    document.getElementById('avancar-etapa-data').value = getDataHojeBR();
    document.getElementById('avancar-etapa-obs').value = '';
    abrirModal('ov-avancar-etapa');
  }

  async function confirmarAvancarEtapa() {
    if (!projetoAtualId) return;
    const p = projetos.find(function(pp){ return pp.id === projetoAtualId; });
    if (!p) return;
    const data = document.getElementById('avancar-etapa-data').value;
    const obs = document.getElementById('avancar-etapa-obs').value.trim();
    if (!data) { zAlert('Informe a data de conclusão da etapa atual.', 'aviso'); return; }

    const etapaInfo = ETAPAS_PROJETO[p.etapa_atual - 1];
    if (!etapaInfo || p.etapa_atual >= 4) {
      zAlert('Este projeto já está na última etapa — não há para onde avançar.', 'aviso');
      return;
    }
    const colAtual = etapaInfo.col; // ex: 'data_vistoria'
    const proxima = p.etapa_atual + 1;
    const sess = getSessao();
    const criadoPor = (sess && sess.nome) ? sess.nome : (sess && sess.email ? sess.email : 'admin');

    const btn = document.getElementById('btn-confirmar-avancar');
    btn.disabled = true; btn.textContent = '⏳ Avançando...';

    try {
      // Atualiza projeto
      const payload = {
        etapa_atual: proxima,
        atualizado_em: new Date().toISOString()
      };
      payload[colAtual] = data;
      const r = await api('projetos?id=eq.' + projetoAtualId, 'PATCH', payload, 'return=minimal');
      if (!r || !r.ok) throw new Error('HTTP ' + (r ? r.status : '?'));

      // Histórico
      await api('projeto_historico', 'POST', {
        projeto_id: projetoAtualId,
        acao: 'etapa_alterada',
        de_valor: String(p.etapa_atual),
        para_valor: String(proxima),
        observacao: obs || null,
        criado_por: criadoPor
      }, 'return=minimal');

      fecharModal('ov-avancar-etapa');
      await carregarDados();
      verProjeto(projetoAtualId);
    } catch(e) {
      console.error('Erro confirmarAvancarEtapa:', e);
      zAlert('Erro ao avançar etapa: ' + (e.message || e), 'erro');
    } finally {
      btn.disabled = false; btn.textContent = '→ Avançar';
    }
  }


  // ============================================================
  // ONDA HISTÓRICO DE OUTORGAS
  // ============================================================
  // Mostra todas as outorgas que já passaram por um ponto de captação:
  // vigente, substituídas (renovações antigas), vencidas, revogadas.
  // ============================================================
  function abrirHistoricoOutorgas(usoId) {
    if (!usoId) return;
    var ponto = (typeof usos !== 'undefined' ? usos : []).find(function(u){ return u.id === usoId; });
    if (!ponto) { zAlert('Ponto não encontrado.', 'erro'); return; }
    var prop = (typeof propriedades !== 'undefined' ? propriedades : []).find(function(p){ return p.id === ponto.propriedade_id; });
    var cli = (typeof clientes !== 'undefined' ? clientes : []).find(function(c){ return c.id === ponto.cliente_id; }) ||
              (typeof clientesEmProjeto !== 'undefined' ? clientesEmProjeto : []).find(function(c){ return c.id === ponto.cliente_id; }) ||
              (typeof leads !== 'undefined' ? leads : []).find(function(c){ return c.id === ponto.cliente_id; });

    // Filtra histórico deste ponto, ordena pelo mais recente
    var registros = (typeof outorgasHistorico !== 'undefined' ? outorgasHistorico : [])
      .filter(function(oh){ return oh.uso_id === usoId; })
      .sort(function(a, b){
        // vigente sempre em cima, depois por data_emissao desc
        if (a.status === 'vigente' && b.status !== 'vigente') return -1;
        if (b.status === 'vigente' && a.status !== 'vigente') return 1;
        return (b.data_emissao || '').localeCompare(a.data_emissao || '');
      });

    if (registros.length === 0) {
      zAlert('Sem histórico de outorgas para este ponto ainda.', 'aviso');
      return;
    }

    // Helpers
    function fmtData(d) {
      if (!d) return '—';
      try { return new Date(d + 'T12:00:00').toLocaleDateString('pt-BR'); }
      catch(e) { return d; }
    }
    function badgeStatus(s) {
      var cores = {
        'vigente':     { bg:'#E8F5E9', cor:'#1B5E20', ico:'🟢', nome:'Vigente' },
        'substituida': { bg:'#F5F5F5', cor:'#616161', ico:'⚪', nome:'Substituída' },
        'vencida':     { bg:'#FFEBEE', cor:'#B71C1C', ico:'🔴', nome:'Vencida' },
        'revogada':    { bg:'#FFF3E0', cor:'#E65100', ico:'🚫', nome:'Revogada' }
      };
      var c = cores[s] || cores['substituida'];
      return '<span style="display:inline-block;background:' + c.bg + ';color:' + c.cor +
             ';font-size:10px;font-weight:700;padding:2px 8px;border-radius:8px;">' +
             c.ico + ' ' + c.nome + '</span>';
    }

    // Monta HTML
    var html = '<div style="padding:4px 8px;font-size:12px;color:var(--text-muted);margin-bottom:10px;">' +
      (cli ? '<strong style="color:#1565C0;">' + escapeHtml(cli.nome) + '</strong> · ' : '') +
      (prop ? escapeHtml(prop.nome) + ' · ' : '') +
      '<em>' + escapeHtml(ponto.descricao || 'Ponto') + '</em>' +
      '</div>';

    html += '<div style="display:flex;flex-direction:column;gap:8px;">';
    registros.forEach(function(r) {
      var bordaCor = r.status === 'vigente' ? '#4CAF50' : '#BDBDBD';
      html += '<div style="border:1px solid #E0E0E0;border-left:4px solid ' + bordaCor + ';border-radius:6px;padding:10px 12px;background:white;">';

      // Linha 1: status + portaria
      html += '<div style="display:flex;justify-content:space-between;align-items:center;margin-bottom:6px;">';
      html += '<div style="font-size:13px;font-weight:700;color:#1a2332;">Portaria ' + escapeHtml(r.portaria) + '</div>';
      html += badgeStatus(r.status);
      html += '</div>';

      // Linha 2: datas + prazo
      // ONDA HISTÓRICO: usa eh_dispensa explícito (fallback: SEM nenhum prazo)
      // BUG FIX 2026-05-26: considerar prazo_anos também (não só meses).
      // Antes, ponto com prazo_anos=5 e prazo_meses=null aparecia como "dispensa".
      var temPrazo = (r.prazo_meses != null && r.prazo_meses > 0) ||
                     (r.prazo_anos != null && r.prazo_anos > 0);
      var ehDispensa = r.eh_dispensa === true || !temPrazo;
      html += '<div style="display:grid;grid-template-columns:1fr 1fr 1fr;gap:8px;font-size:11px;color:#555;margin-bottom:6px;">';
      html += '<div><strong>Emitida:</strong> ' + fmtData(r.data_emissao) + '</div>';
      if (ehDispensa) {
        html += '<div style="grid-column:span 2;"><strong style="color:#2E7D32;">📌 Dispensa de outorga</strong> <span style="color:#888;">— uso regular, sem vencimento</span></div>';
      } else {
        html += '<div><strong>Vence em:</strong> ' + fmtData(r.data_vencimento) + '</div>';
        var prazoTexto = r.prazo_meses ? (r.prazo_meses + ' meses') : (r.prazo_anos + ' anos');
        html += '<div><strong>Prazo:</strong> ' + prazoTexto + '</div>';
      }
      html += '</div>';

      // Linha 3: motivo + requerimento (se existir)
      if (r.motivo || r.requerimento) {
        var infos = [];
        if (r.motivo) infos.push('<strong>Motivo:</strong> ' + escapeHtml(r.motivo));
        if (r.requerimento) infos.push('<strong>Requerimento:</strong> ' + escapeHtml(r.requerimento));
        html += '<div style="font-size:11px;color:#666;margin-bottom:6px;">' + infos.join(' · ') + '</div>';
      }

      // Linha 4: PDF + auditoria
      var rodape = [];
      if (r.pdf_url) {
        rodape.push('<a href="' + r.pdf_url + '" target="_blank" rel="noopener" style="color:#1565C0;text-decoration:underline;font-weight:600;">📄 Abrir PDF</a>');
      } else {
        rodape.push('<span style="color:#999;">Sem PDF anexado</span>');
      }
      if (r.criado_em) {
        try {
          var dataCriacao = new Date(r.criado_em);
          rodape.push('<span style="color:#999;font-size:10px;">Registrada em ' + dataCriacao.toLocaleDateString('pt-BR') + (r.criado_por ? ' por ' + escapeHtml(r.criado_por) : '') + '</span>');
        } catch(e) {}
      }
      html += '<div style="display:flex;justify-content:space-between;align-items:center;font-size:11px;padding-top:6px;border-top:1px solid #F0F0F0;">' + rodape.join('<span style="color:#ccc;margin:0 8px;">|</span>') + '</div>';

      html += '</div>';
    });
    html += '</div>';

    // Mostra modal genérico (cria overlay simples)
    var modalId = 'ov-hist-outorgas';
    var modalExiste = document.getElementById(modalId);
    if (!modalExiste) {
      var ov = document.createElement('div');
      ov.id = modalId;
      ov.className = 'overlay';
      // Deixa o CSS .overlay/.overlay.open controlar display.
      // Outros estilos só pra garantir z-index alto.
      ov.style.zIndex = '10000';
      ov.innerHTML =
        '<div class="modal" style="background:white;border-radius:10px;max-width:700px;width:100%;max-height:85vh;display:flex;flex-direction:column;box-shadow:0 10px 40px rgba(0,0,0,0.3);">' +
          '<div class="modal-header" style="padding:14px 20px;border-bottom:1px solid #E0E0E0;display:flex;justify-content:space-between;align-items:center;">' +
            '<div class="modal-title" style="font-size:16px;font-weight:700;color:#1a2332;">📜 Histórico de Outorgas</div>' +
            '<button onclick="fecharModal(\'' + modalId + '\')" style="background:none;border:none;font-size:24px;cursor:pointer;color:#999;line-height:1;">×</button>' +
          '</div>' +
          '<div id="hist-outorgas-body" style="padding:16px 20px;overflow-y:auto;flex:1;"></div>' +
          '<div class="modal-footer" style="padding:12px 20px;border-top:1px solid #E0E0E0;text-align:right;">' +
            '<button class="btn" onclick="fecharModal(\'' + modalId + '\')" style="background:#F5F5F5;color:#333;border:1px solid #DDD;">Fechar</button>' +
          '</div>' +
        '</div>';
      document.body.appendChild(ov);
    }
    document.getElementById('hist-outorgas-body').innerHTML = html;
    abrirModal(modalId);
  }
  // Expor pra ser chamada via onclick inline
  window.abrirHistoricoOutorgas = abrirHistoricoOutorgas;

  // ============================================================
  // ONDA SITUAÇÃO DO PONTO
  // ============================================================
  // Permite dar baixa em um ponto de captação:
  //   - desativado: temporariamente parado (pode reativar)
  //   - tamponado: poço selado permanentemente
  //   - substituido: trocado por outro ponto
  //   - vendido: saiu da propriedade
  //
  // Pontos não-ativos:
  //   - não aparecem em alertas de renovação
  //   - mapa pinta cinza
  //   - histórico fica preservado
  // ============================================================
  var _baixaUsoAtual = null;

  function abrirMenuBaixaPonto(usoId, evt) {
    if (evt) { evt.stopPropagation(); evt.preventDefault(); }
    _baixaUsoAtual = usoId;
    var u = (typeof usos !== 'undefined' ? usos : []).find(function(uu){ return uu.id === usoId; });
    if (!u) return;

    var modalId = 'ov-baixa-menu';
    var existente = document.getElementById(modalId);
    if (existente) existente.remove();

    var html =
      '<div style="display:flex;flex-direction:column;gap:6px;padding:6px 0;">' +
        '<div style="font-size:11px;color:#666;margin-bottom:6px;">Selecione o tipo de baixa pra <strong>' + escapeHtml(u.descricao || 'este ponto') + '</strong>:</div>' +

        '<button onclick="abrirModalBaixaPonto(\'desativado\')" style="text-align:left;padding:10px 12px;background:#F5F5F5;border:1px solid #E0E0E0;border-radius:6px;cursor:pointer;font-size:12px;">' +
          '<div style="font-weight:700;color:#424242;">🔌 Desativado <span style="font-weight:400;color:#888;font-size:11px;">— temporariamente fora de uso</span></div>' +
          '<div style="font-size:10px;color:#888;margin-top:2px;">Pode reativar depois</div>' +
        '</button>' +

        '<button onclick="abrirModalBaixaPonto(\'tamponado\')" style="text-align:left;padding:10px 12px;background:#F5F5F5;border:1px solid #E0E0E0;border-radius:6px;cursor:pointer;font-size:12px;">' +
          '<div style="font-weight:700;color:#424242;">🚫 Tamponado <span style="font-weight:400;color:#888;font-size:11px;">— poço selado permanentemente</span></div>' +
          '<div style="font-size:10px;color:#888;margin-top:2px;">Ação irreversível fisicamente</div>' +
        '</button>' +

        '<button onclick="abrirModalBaixaPonto(\'substituido\')" style="text-align:left;padding:10px 12px;background:#F5F5F5;border:1px solid #E0E0E0;border-radius:6px;cursor:pointer;font-size:12px;">' +
          '<div style="font-weight:700;color:#424242;">🔄 Substituído <span style="font-weight:400;color:#888;font-size:11px;">— trocado por outro ponto</span></div>' +
          '<div style="font-size:10px;color:#888;margin-top:2px;">Aponta pro ponto novo</div>' +
        '</button>' +

        '<button onclick="abrirModalBaixaPonto(\'vendido\')" style="text-align:left;padding:10px 12px;background:#F5F5F5;border:1px solid #E0E0E0;border-radius:6px;cursor:pointer;font-size:12px;">' +
          '<div style="font-weight:700;color:#424242;">💰 Vendido <span style="font-weight:400;color:#888;font-size:11px;">— saiu da propriedade do cliente</span></div>' +
          '<div style="font-size:10px;color:#888;margin-top:2px;">Venda da terra ou transferência</div>' +
        '</button>' +

        '<div style="border-top:1px solid #E0E0E0;margin:6px 0;"></div>' +

        '<button onclick="fecharModal(\'' + modalId + '\')" style="padding:8px 12px;background:none;border:1px solid #DDD;border-radius:6px;cursor:pointer;font-size:12px;color:#666;">Cancelar</button>' +
      '</div>';

    var ov = document.createElement('div');
    ov.id = modalId;
    ov.className = 'overlay';
    ov.style.zIndex = '10001';
    ov.innerHTML =
      '<div class="modal" style="background:white;border-radius:10px;max-width:480px;width:100%;box-shadow:0 10px 40px rgba(0,0,0,0.3);">' +
        '<div class="modal-header" style="padding:14px 20px;border-bottom:1px solid #E0E0E0;">' +
          '<div class="modal-title" style="font-size:15px;font-weight:700;color:#1a2332;">⋮ Baixar ponto de captação</div>' +
        '</div>' +
        '<div style="padding:14px 20px;">' + html + '</div>' +
      '</div>';
    document.body.appendChild(ov);
    abrirModal(modalId);
  }
  window.abrirMenuBaixaPonto = abrirMenuBaixaPonto;

  function abrirModalBaixaPonto(novaSituacao) {
    if (!_baixaUsoAtual) return;
    fecharModal('ov-baixa-menu');
    var u = (typeof usos !== 'undefined' ? usos : []).find(function(uu){ return uu.id === _baixaUsoAtual; });
    if (!u) return;

    var rotulos = {
      'desativado':  { ico:'🔌', label:'Desativar ponto',     pergunta:'Por que está sendo desativado?',  placeholder:'Ex: equipamento em manutenção, uso suspenso temporariamente...' },
      'tamponado':   { ico:'🚫', label:'Tamponar poço',       pergunta:'Por que foi tamponado?',          placeholder:'Ex: contaminação detectada, poço seco, exigência CETESB...' },
      'substituido': { ico:'🔄', label:'Marcar como substituído', pergunta:'Por que foi substituído?',    placeholder:'Ex: novo poço construído com melhor vazão, ponto antigo inviável...' },
      'vendido':     { ico:'💰', label:'Marcar como vendido', pergunta:'Por que saiu da propriedade?',    placeholder:'Ex: venda da fazenda, desmembramento, transferência de titularidade...' }
    };
    var r = rotulos[novaSituacao];
    if (!r) return;

    var modalId = 'ov-baixa-form';
    var existente = document.getElementById(modalId);
    if (existente) existente.remove();

    var listaSubst = '';
    if (novaSituacao === 'substituido') {
      var outrosUsos = (typeof usos !== 'undefined' ? usos : [])
        .filter(function(uu){ return uu.propriedade_id === u.propriedade_id && uu.id !== u.id && uu.situacao_ponto === 'ativo'; });
      listaSubst =
        '<div style="margin-top:10px;">' +
          '<label style="font-size:12px;font-weight:600;color:#5D4037;display:block;margin-bottom:4px;">Substituído por (opcional):</label>' +
          '<select id="baixa-substituto-id" style="width:100%;padding:8px;border:1px solid #DDD;border-radius:4px;font-size:12px;">' +
            '<option value="">-- (não selecionar, deixar em branco) --</option>' +
            outrosUsos.map(function(uu){ return '<option value="' + uu.id + '">' + escapeHtml(uu.descricao || 'ponto') + (uu.portaria ? ' — Port. ' + escapeHtml(uu.portaria) : '') + '</option>'; }).join('') +
          '</select>' +
          (outrosUsos.length === 0 ? '<small style="font-size:10px;color:#888;">Nenhum outro ponto ativo nesta propriedade. Cadastre o novo ponto primeiro pra linká-lo aqui.</small>' : '') +
        '</div>';
    }

    var hojeISO = new Date().toISOString().substring(0,10);

    var html =
      '<div style="padding:6px 0;">' +
        '<div style="font-size:11px;color:#666;margin-bottom:10px;">Ponto: <strong>' + escapeHtml(u.descricao || '') + '</strong></div>' +

        '<div style="margin-bottom:10px;">' +
          '<label style="font-size:12px;font-weight:600;color:#1a2332;display:block;margin-bottom:4px;">Data da baixa <span style="color:#C62828;">*</span></label>' +
          '<input type="date" id="baixa-data" value="' + hojeISO + '" style="width:100%;padding:8px;border:1px solid #DDD;border-radius:4px;font-size:12px;" />' +
        '</div>' +

        '<div style="margin-bottom:10px;">' +
          '<label style="font-size:12px;font-weight:600;color:#1a2332;display:block;margin-bottom:4px;">' + r.pergunta + ' <span style="color:#C62828;">*</span></label>' +
          '<input type="text" id="baixa-motivo" placeholder="' + r.placeholder + '" maxlength="200" style="width:100%;padding:8px;border:1px solid #DDD;border-radius:4px;font-size:12px;" />' +
        '</div>' +

        '<div style="margin-bottom:10px;">' +
          '<label style="font-size:12px;font-weight:600;color:#1a2332;display:block;margin-bottom:4px;">Observação (opcional)</label>' +
          '<textarea id="baixa-obs" rows="2" maxlength="500" placeholder="Detalhes adicionais, números de processo, observações técnicas..." style="width:100%;padding:8px;border:1px solid #DDD;border-radius:4px;font-size:12px;resize:vertical;"></textarea>' +
        '</div>' +

        listaSubst +

        '<div style="margin-top:14px;padding:10px 12px;background:#FFF3CD;border:1px solid #FFC107;border-radius:6px;font-size:11px;color:#5D4037;">' +
          '⚠ <strong>Atenção:</strong> esta ação registra a baixa no histórico. ' +
          (novaSituacao === 'tamponado' ? 'Poço tamponado é considerado <strong>permanente</strong> (mas pode ser reativado se necessário).' : 'Você pode reativar este ponto depois se necessário.') +
        '</div>' +

        '<div style="display:flex;justify-content:flex-end;gap:8px;margin-top:14px;">' +
          '<button class="btn" onclick="fecharModal(\'' + modalId + '\')" style="background:#F5F5F5;color:#333;border:1px solid #DDD;">Cancelar</button>' +
          '<button class="btn btn-blue" onclick="salvarBaixaPonto(\'' + novaSituacao + '\')">' + r.ico + ' Confirmar baixa</button>' +
        '</div>' +
      '</div>';

    var ov = document.createElement('div');
    ov.id = modalId;
    ov.className = 'overlay';
    ov.style.zIndex = '10002';
    ov.innerHTML =
      '<div class="modal" style="background:white;border-radius:10px;max-width:520px;width:100%;box-shadow:0 10px 40px rgba(0,0,0,0.3);">' +
        '<div class="modal-header" style="padding:14px 20px;border-bottom:1px solid #E0E0E0;">' +
          '<div class="modal-title" style="font-size:15px;font-weight:700;color:#1a2332;">' + r.ico + ' ' + r.label + '</div>' +
        '</div>' +
        '<div style="padding:14px 20px;">' + html + '</div>' +
      '</div>';
    document.body.appendChild(ov);
    abrirModal(modalId);
  }
  window.abrirModalBaixaPonto = abrirModalBaixaPonto;

  async function salvarBaixaPonto(novaSituacao) {
    if (!_baixaUsoAtual) return;
    var u = (typeof usos !== 'undefined' ? usos : []).find(function(uu){ return uu.id === _baixaUsoAtual; });
    if (!u) { zAlert('Ponto não encontrado.', 'erro'); return; }

    var dataBaixa = (document.getElementById('baixa-data') || {}).value || '';
    var motivo = ((document.getElementById('baixa-motivo') || {}).value || '').trim();
    var obs = ((document.getElementById('baixa-obs') || {}).value || '').trim();
    var substitutoId = ((document.getElementById('baixa-substituto-id') || {}).value || '') || null;

    if (!dataBaixa) { zAlert('Data da baixa é obrigatória.', 'aviso'); return; }
    if (!motivo) { zAlert('Motivo é obrigatório.', 'aviso'); return; }

    var sess = getSessao();
    var criadoPor = (sess && sess.nome) ? sess.nome : (sess && sess.email ? sess.email : 'admin');

    try {
      var patchUso = {
        situacao_ponto: novaSituacao,
        data_baixa: dataBaixa,
        motivo_baixa: motivo
      };
      if (novaSituacao === 'substituido') {
        patchUso.substituido_por_id = substitutoId;
      } else {
        patchUso.substituido_por_id = null;
      }
      await api('usos?id=eq.' + u.id, 'PATCH', patchUso, 'return=minimal');

      await api('pontos_baixas', 'POST', {
        uso_id: u.id,
        cliente_id: u.cliente_id,
        propriedade_id: u.propriedade_id,
        situacao_anterior: u.situacao_ponto || 'ativo',
        situacao_nova: novaSituacao,
        data_baixa: dataBaixa,
        motivo: motivo,
        observacao: obs || null,
        substituido_por_id: substitutoId,
        criado_por: criadoPor
      }, 'return=minimal');

      await carregarDados();

      fecharModal('ov-baixa-form');
      _baixaUsoAtual = null;
      if (typeof toastSuccess === 'function') toastSuccess('✓ Baixa registrada — ponto agora aparece como ' + novaSituacao + '.');
      else zAlert('✓ Baixa registrada.', 'sucesso');
    } catch(err) {
      console.error('Erro ao salvar baixa:', err);
      zAlert('Erro ao salvar baixa: ' + (err && err.message ? err.message : 'desconhecido'), 'erro');
    }
  }
  window.salvarBaixaPonto = salvarBaixaPonto;

  async function reativarPonto(usoId) {
    var u = (typeof usos !== 'undefined' ? usos : []).find(function(uu){ return uu.id === usoId; });
    if (!u) return;
    if (!(await zConfirm('Reativar o ponto "' + (u.descricao || 'ponto') + '"?\n\nEle voltará a aparecer nos alertas de renovação e no mapa como ativo. A baixa anterior fica registrada no histórico.'))) return;
    try {
      var sess = getSessao();
      var criadoPor = (sess && sess.nome) ? sess.nome : (sess && sess.email ? sess.email : 'admin');
      var hojeISO = new Date().toISOString().substring(0,10);

      await api('pontos_baixas', 'POST', {
        uso_id: u.id,
        cliente_id: u.cliente_id,
        propriedade_id: u.propriedade_id,
        situacao_anterior: u.situacao_ponto || 'desativado',
        situacao_nova: 'ativo',
        data_baixa: hojeISO,
        motivo: 'Reativação manual',
        criado_por: criadoPor
      }, 'return=minimal');

      await api('usos?id=eq.' + u.id, 'PATCH', {
        situacao_ponto: 'ativo',
        data_baixa: null,
        motivo_baixa: null,
        substituido_por_id: null
      }, 'return=minimal');

      await carregarDados();
      if (typeof toastSuccess === 'function') toastSuccess('✓ Ponto reativado.');
      else zAlert('✓ Ponto reativado.', 'sucesso');
    } catch(err) {
      console.error('Erro ao reativar:', err);
      zAlert('Erro ao reativar: ' + (err && err.message ? err.message : 'desconhecido'), 'erro');
    }
  }
  window.reativarPonto = reativarPonto;

  // ============================================================
  // ONDA HISTÓRICO: alterna campo "Prazo" conforme checkbox dispensa
  // ============================================================
  function togglePubDispensa() {
    var ckb = document.getElementById('pub-eh-dispensa');
    var inpPrazo = document.getElementById('pub-prazo');
    var labelObrig = document.getElementById('pub-prazo-obrig');
    if (!ckb || !inpPrazo) return;
    var dispensa = !!ckb.checked;
    // Container pai do campo prazo (.fg) — pra esconder por completo
    var fgPrazo = inpPrazo.closest('.fg');
    if (dispensa) {
      // Dispensa marcada: oculta o campo prazo e zera valor
      if (fgPrazo) fgPrazo.style.display = 'none';
      inpPrazo.value = '';
      inpPrazo.disabled = true;
    } else {
      // Outorga com prazo: mostra campo, obrigatório
      if (fgPrazo) fgPrazo.style.display = '';
      inpPrazo.disabled = false;
      if (labelObrig) labelObrig.style.display = '';
    }
  }
  window.togglePubDispensa = togglePubDispensa;

  // ============================================================
  // PUBLICAR OUTORGA (etapa final → cliente ativo)
  // ============================================================
  // ============================================================
  // ONDA PUBLICAÇÃO POR PONTO 2026-05-26
  // ============================================================
  // Quando preenchida, indica que a publicação será aplicada APENAS
  // a esse ponto (e não a todos os pontos da propriedade como antes).
  // Reseta após cada publicação pra evitar contaminar próxima.
  // ============================================================
  var _pontoEspecificoPublicar = null;

  // ============================================================
  // ONDA PUBLICAÇÃO POR PONTO 2026-05-26
  // ============================================================
  // Finaliza o projeto quando TODOS os pontos ativos já têm outorga
  // vigente publicada. Chamada pelo botão verde do banner de progresso.
  //
  // Faz:
  //   1) Confirma com o usuário (com opção de gerar PIN)
  //   2) Marca projeto como concluído (status='concluido', data_publicacao=hoje)
  //   3) Promove cliente para 'cliente_ativo' + portal_ativo
  //   4) Gera PIN de 4 dígitos e salva pin_hash
  //   5) Registra entrada em projeto_historico
  //   6) Fecha modal, atualiza Kanban, mostra resumo
  //   7) Opcionalmente envia WhatsApp com PIN
  // ============================================================
  async function finalizarProjetoAtivarCliente() {
    if (!projetoAtualId) return;
    const p = projetos.find(function(pp){ return pp.id === projetoAtualId; });
    if (!p) return;

    const cli = todosClientesUnificado(p.cliente_id) || {};

    // Confere se realmente todos os pontos ativos têm outorga vigente
    const usosAtivos = (typeof usos !== 'undefined' ? usos : [])
      .filter(function(u){ return u.cliente_id === p.cliente_id && (u.situacao_ponto || 'ativo') === 'ativo'; });
    const oh = (typeof outorgasHistorico !== 'undefined' ? outorgasHistorico : []);
    const pendentes = usosAtivos.filter(function(u) {
      return !oh.some(function(r){ return r.uso_id === u.id && r.status === 'vigente'; });
    });
    if (pendentes.length > 0) {
      zAlert(
        'Ainda há ' + pendentes.length + ' ponto(s) sem publicação registrada:\n\n' +
        pendentes.map(function(u){ return '• ' + (u.descricao || 'ponto'); }).join('\n') +
        '\n\nRegistre a publicação de cada ponto antes de finalizar o projeto.',
        { tipo:'aviso', titulo:'Pontos pendentes' }
      );
      return;
    }

    // Confirmação visual com checklist do que vai acontecer
    const ok = await zConfirm(
      '🎉 Finalizar o projeto?\n\n' +
      'Ao confirmar, vai acontecer:\n' +
      '• Projeto marcado como CONCLUÍDO\n' +
      '• Cliente "' + (cli.nome || '—') + '" promovido para CLIENTES ATIVOS\n' +
      '• Portal do cliente ativado\n' +
      '• PIN de 4 dígitos gerado pra acesso ao portal\n\n' +
      'Tem certeza?',
      { tipo:'sucesso', btnOk: 'Sim, finalizar e ativar cliente' }
    );
    if (!ok) return;

    try {
      // Data da última publicação (entre todas as outorgas vigentes desse cliente)
      let ultimaData = null;
      usosAtivos.forEach(function(u) {
        const ohu = oh.find(function(r){ return r.uso_id === u.id && r.status === 'vigente'; });
        if (ohu && ohu.data_emissao) {
          if (!ultimaData || ohu.data_emissao > ultimaData) ultimaData = ohu.data_emissao;
        }
      });
      const dataPub = ultimaData || getDataHojeBR();

      // 1. Marca projeto como concluído
      await api('projetos?id=eq.' + projetoAtualId, 'PATCH', {
        status: 'concluido',
        data_publicacao: dataPub,
        atualizado_em: new Date().toISOString()
      }, 'return=minimal');

      // 2. Promove cliente — SEM gerar PIN.
      // ONDA 2026-05-26: Cliente cria o próprio PIN no 1º acesso ao portal.
      // Estratégia: pin_hash fica NULL → portal detecta primeiro acesso e
      // pede pro cliente criar PIN próprio (lógica já existe em cliente.js).
      // Vantagens: sem trabalho pro admin, mais seguro (admin nunca vê o PIN),
      // cliente escolhe um PIN que ele lembra.
      await api('clientes?id=eq.' + p.cliente_id, 'PATCH', {
        status_funil: 'cliente_ativo',
        portal_ativo: true
        // pin_hash NÃO é setado: cliente cria no 1º acesso
      }, 'return=minimal');

      // 3. Registra no histórico do projeto
      const sess = getSessao();
      const criadoPor = (sess && sess.nome) ? sess.nome : (sess && sess.email ? sess.email : 'admin');
      try {
        await api('projeto_historico', 'POST', {
          projeto_id: projetoAtualId,
          campo_alterado: 'status',
          de_valor: 'em_andamento',
          para_valor: 'concluido',
          observacao: 'Projeto finalizado. Todos os pontos com outorga publicada. Cliente promovido a ativo. Aguardando criação de PIN no 1º acesso.',
          criado_por: criadoPor
        }, 'return=minimal');
      } catch(eh) { console.warn('historico:', eh); }

      // 4. Fecha modal + atualiza tela
      fecharModal('ov-ver-projeto');
      projetoAtualId = null;
      await carregarDados();
      renderKanban();

      // 5. Mostra resultado + opção de WhatsApp
      const enviarWpp = await zConfirm(
        '✅ Projeto finalizado com sucesso!\n\n' +
        '• Cliente "' + (cli.nome || '—') + '" agora está nos CLIENTES ATIVOS\n' +
        '• Portal ativado\n' +
        '• O cliente vai criar o próprio PIN no 1º acesso\n\n' +
        'Quer enviar o link de acesso pro cliente por WhatsApp agora?',
        { tipo:'sucesso', btnOk: '📲 Sim, enviar link', btnCancelar: 'Não, depois' }
      );

      if (enviarWpp) {
        const tel = (cli.telefone1 || '').replace(/\D/g,'');
        if (tel) {
          const cleanTel = tel.length === 11 || tel.length === 10 ? '55' + tel : tel;
          // Mensagem sem PIN — cliente cria no 1º acesso
          const txt = 'Olá ' + (cli.nome ? cli.nome.split(' ')[0] : '') +
            '! Seu processo de regularização ambiental foi concluído com sucesso.\n\n' +
            '*Portal Zello Ambiental*\n' +
            'Acesse para ver sua portaria e gerenciar a outorga:\n' +
            getClienteUrl() + '\n\n' +
            '*No primeiro acesso:*\n' +
            '• Use seu CPF/CNPJ: ' + (cli.cpf_cnpj || '—') + '\n' +
            '• Crie um PIN de 4 dígitos (memorize, é a sua senha)\n\n' +
            'Em caso de dúvidas, fale comigo.\n\n' +
            'Eng. Guilherme Montanari - Zello Ambiental';
          window.open('https://wa.me/' + cleanTel + '?text=' + encodeURIComponent(txt), '_blank');
        } else {
          zAlert('Cliente sem telefone cadastrado. Avise o cliente manualmente que ele já pode acessar o portal com o CPF/CNPJ.', 'aviso');
        }
      }
    } catch(e) {
      console.error('finalizarProjetoAtivarCliente:', e);
      zAlert('Erro ao finalizar: ' + (e.message || e), 'erro');
    }
  }
  window.finalizarProjetoAtivarCliente = finalizarProjetoAtivarCliente;

  function abrirPublicarOutorgaPorPonto(usoId) {
    if (!projetoAtualId) return;
    const p = projetos.find(function(pp){ return pp.id === projetoAtualId; });
    if (!p) return;
    if (p.etapa_atual !== 4) { zAlert('Só é possível publicar outorga na etapa 4 (Publicação).', 'aviso'); return; }

    // Mesma trava do pagamento 2º
    if (!p.pago_2) {
      zAlert(
        '⚠️ Pagamento pendente\n\n' +
        'O 2º pagamento (50% restante) ainda não foi marcado como pago.\n\n' +
        'Marque o checkbox "Pago 2º" no checklist da etapa antes de publicar a outorga.',
        'aviso'
      );
      return;
    }

    var u = (typeof usos !== 'undefined' ? usos : []).find(function(uu){ return uu.id === usoId; });
    if (!u) { zAlert('Ponto não encontrado.', 'erro'); return; }

    // Seta o ponto específico — confirmarPublicarOutorga vai usar isso
    _pontoEspecificoPublicar = usoId;

    const cli = todosClientesUnificado(p.cliente_id) || {};
    const prop = (typeof propriedades !== 'undefined' ? propriedades : []).find(function(pp){ return pp.id === u.propriedade_id; }) || {};

    // Subtítulo destaca o PONTO específico
    document.getElementById('publicar-out-sub').textContent =
      cli.nome + ' · ' + prop.nome + ' · 📍 ' + (u.descricao || 'ponto');

    document.getElementById('pub-data').value = getDataHojeBR();
    document.getElementById('pub-portaria').value = '';
    document.getElementById('pub-prazo').value = '';
    var _ehDispCkb = document.getElementById('pub-eh-dispensa');
    if (_ehDispCkb) _ehDispCkb.checked = false;
    if (typeof togglePubDispensa === 'function') togglePubDispensa();
    // ONDA 2 FIX (2026-06-13): pub-gerar-pin descontinuado (PIN agora via OTP no portal).
    // Setagem antiga removida — input fica como 'nao' no HTML (legado, ninguém lê mais).
    document.getElementById('pub-enviar-wpp').checked = false;
    var pdfInp = document.getElementById('pub-pdf-portaria');
    if (pdfInp) pdfInp.value = '';
    var pdfInfo = document.getElementById('pub-pdf-info');
    if (pdfInfo) pdfInfo.textContent = '';
    abrirModal('ov-publicar-outorga');
  }
  window.abrirPublicarOutorgaPorPonto = abrirPublicarOutorgaPorPonto;

  function abrirPublicarOutorga() {
    if (!projetoAtualId) return;
    const p = projetos.find(function(pp){ return pp.id === projetoAtualId; });
    if (!p) return;
    if (p.etapa_atual !== 4) { zAlert('Só é possível publicar outorga na etapa 4 (Publicação).', 'aviso'); return; }

    // ONDA F9: bloqueia publicação se o 2º pagamento ainda não foi marcado.
    // Garante que o card só sai da coluna "Publicação e Pagamento" depois
    // do pagamento confirmado — evita publicar sem ter recebido o final.
    if (!p.pago_2) {
      zAlert(
        '⚠️ Pagamento pendente\n\n' +
        'O 2º pagamento (50% restante) ainda não foi marcado como pago.\n\n' +
        'Marque o checkbox "Pago 2º" no checklist da etapa antes de publicar a outorga.',
        'aviso'
      );
      return;
    }

    const cli = todosClientesUnificado(p.cliente_id) || {};
    const prop = (typeof propriedades !== 'undefined' ? propriedades : []).find(function(pp){ return pp.id === p.propriedade_id; }) || {};
    document.getElementById('publicar-out-sub').textContent = cli.nome + ' · ' + prop.nome;
    document.getElementById('pub-data').value = getDataHojeBR();
    document.getElementById('pub-portaria').value = '';
    document.getElementById('pub-prazo').value = '';
    // ONDA HISTÓRICO: checkbox de dispensa começa desmarcada (assume outorga com prazo)
    var _ehDispCkb = document.getElementById('pub-eh-dispensa');
    if (_ehDispCkb) _ehDispCkb.checked = false;
    // chama o toggle pra garantir estado correto (campo prazo visível, label obrigatório, etc)
    if (typeof togglePubDispensa === 'function') togglePubDispensa();
    // ONDA 2 FIX (2026-06-13): pub-gerar-pin descontinuado (PIN agora via OTP no portal).
    // Setagem antiga removida — input fica como 'nao' no HTML (legado, ninguém lê mais).
    document.getElementById('pub-enviar-wpp').checked = false;
    // ONDA F9: limpar campo de PDF
    var pdfInp = document.getElementById('pub-pdf-portaria');
    if (pdfInp) pdfInp.value = '';
    var pdfInfo = document.getElementById('pub-pdf-info');
    if (pdfInfo) pdfInfo.textContent = '';
    abrirModal('ov-publicar-outorga');
  }

  // ⚠️ DEPRECATED desde Onda 2 (2026-06-13).
  // SHA-256 não é mais usado pra PIN de cliente (substituído por PBKDF2-SHA256
  // 600k iter na Edge Function auth-pin-cliente). Função mantida pra evitar
  // ReferenceError em hot-paths legados, mas não há mais chamadores ativos.
  async function sha256Hex(str) {
    const buf = new TextEncoder().encode(str);
    const h = await crypto.subtle.digest('SHA-256', buf);
    const arr = Array.from(new Uint8Array(h));
    return arr.map(function(b){ return b.toString(16).padStart(2,'0'); }).join('');
  }

  async function confirmarPublicarOutorga() {
    if (!projetoAtualId) return;
    const p = projetos.find(function(pp){ return pp.id === projetoAtualId; });
    if (!p) return;

    const data = document.getElementById('pub-data').value;
    const portariaRaw = document.getElementById('pub-portaria').value.trim();
    // ONDA HISTÓRICO: checkbox de dispensa é a fonte da verdade
    const ehDispensa = !!document.getElementById('pub-eh-dispensa').checked;
    // Se for dispensa: prazo é null. Senão: lê do input (e exige preenchido).
    let prazoMeses = null;
    if (!ehDispensa) {
      const prazoRaw = document.getElementById('pub-prazo').value.trim();
      prazoMeses = parseInt(prazoRaw, 10);
      if (!prazoMeses || isNaN(prazoMeses) || prazoMeses <= 0) {
        zAlert('Prazo (meses) é obrigatório.\n\nSe esta outorga não tem prazo, marque a caixa "É dispensa de outorga".', { tipo:'erro', titulo:'Prazo não preenchido' });
        document.getElementById('pub-prazo').focus();
        return;
      }
    }
    // ONDA 2 FIX (2026-06-13): removida leitura de pub-gerar-pin (PIN automático
    // SHA-256 foi descontinuado). Cliente cria PIN via OTP no portal.
    const enviarWpp = document.getElementById('pub-enviar-wpp').checked;

    if (!data) { zAlert('Data da publicação é obrigatória.', 'aviso'); return; }
    if (!portariaRaw) { zAlert('Número da portaria é obrigatório.', 'aviso'); return; }

    // FASE 3B Item 4: validação de portaria
    const vPort = validarPortaria(portariaRaw);
    if (!vPort.ok) {
      zAlert('⚠ Portaria inválida\n\n' + vPort.mensagem, 'erro');
      document.getElementById('pub-portaria').focus();
      return;
    }
    const portaria = vPort.valor;

    const sess = getSessao();
    const criadoPor = (sess && sess.nome) ? sess.nome : (sess && sess.email ? sess.email : 'admin');

    const btn = document.getElementById('btn-confirmar-publicar');
    btn.disabled = true; btn.textContent = '⏳ Publicando...';

    // ============================================================
    // ONDA PUBLICAÇÃO POR PONTO 2026-05-26
    // ============================================================
    // Detecta modo: se _pontoEspecificoPublicar está setado, publica
    // APENAS nesse ponto e NÃO finaliza o projeto (espera os outros).
    // Se vazio, comportamento legado (publica em todos + finaliza).
    // ============================================================
    var modoPorPonto = !!_pontoEspecificoPublicar;
    var usoIdEspecifico = _pontoEspecificoPublicar;

    try {
      // ONDA F9: Upload do PDF da portaria (opcional mas recomendado).
      var pdfUrlPortaria = null;
      var pdfInput = document.getElementById('pub-pdf-portaria');
      if (pdfInput && pdfInput.files && pdfInput.files[0]) {
        try {
          pdfUrlPortaria = await uploadFile(
            'documentos-zello',
            'outorgas/' + p.cliente_id + '/' + Date.now() + '.pdf',
            pdfInput.files[0]
          );
        } catch(e) {
          console.error('Upload PDF portaria falhou:', e);
          if (!confirm('⚠ Falha ao subir o PDF da portaria.\n\nQuer continuar a publicação SEM o PDF? Você pode anexar depois.')) {
            btn.disabled = false; btn.textContent = '✅ Publicar e ativar cliente';
            return;
          }
        }
      }

      // 1. Atualiza projeto — MAS no modo por-ponto, NÃO marca como concluído!
      // O projeto só fecha quando finalizarProjetoAtivarCliente() for chamado
      // (depois que TODOS os pontos tiverem outorga registrada).
      if (!modoPorPonto) {
        await api('projetos?id=eq.' + projetoAtualId, 'PATCH', {
          status: 'concluido',
          data_publicacao: data,
          atualizado_em: new Date().toISOString()
        }, 'return=minimal');
      } else {
        // Modo por ponto: só atualiza data_publicacao (timestamp da última publicação)
        await api('projetos?id=eq.' + projetoAtualId, 'PATCH', {
          data_publicacao: data,
          atualizado_em: new Date().toISOString()
        }, 'return=minimal');
      }

      // 2. Atualiza cliente: status_funil='cliente_ativo'
      //    MAS no modo por-ponto, NÃO ativa o cliente ainda — espera finalizar.
      // ONDA 2 FIX (2026-06-13): removida geração automática de PIN SHA-256.
      // O fluxo antigo gerava um PIN aleatório de 4 dígitos, SHA-256 → pin_hash,
      // mas NUNCA EXIBIA o PIN pro admin — era um bug latente. Agora o cliente
      // cria o próprio PIN no portal via OTP no primeiro acesso (PBKDF2).
      if (!modoPorPonto) {
        const updCli = {
          status_funil: 'cliente_ativo',
          portal_ativo: true
        };
        await api('clientes?id=eq.' + p.cliente_id, 'PATCH', updCli, 'return=minimal');
      } // fim if (!modoPorPonto)

      // 3. Atualiza pontos (usos) da publicação
      //    Modo legado: TODOS os pontos da propriedade
      //    Modo por-ponto: APENAS o ponto selecionado
      const usosProp = modoPorPonto
        ? (typeof usos !== 'undefined' ? usos : []).filter(function(u){ return u.id === usoIdEspecifico; })
        : (typeof usos !== 'undefined' ? usos : []).filter(function(u){ return u.propriedade_id === p.propriedade_id; });
      for (const u of usosProp) {
        try {
          var patchUso = {
            portaria: portaria,
            data_emissao: data,
            prazo_meses: prazoMeses,
            eh_dispensa: ehDispensa,  // ONDA HISTÓRICO: marca explicitamente
            requerimento: u.requerimento || p.requerimento || null
          };
          if (pdfUrlPortaria) patchUso.outorga_pdf_url = pdfUrlPortaria;
          await api('usos?id=eq.' + u.id, 'PATCH', patchUso, 'return=minimal');
        } catch(e) { /* segue */ }
      }

      // ONDA F9: cria 1 documento PÚBLICO no portal do cliente (visivel_cliente=true)
      // pra ele baixar a portaria oficial. Faz só se o PDF foi anexado.
      // ONDA HISTÓRICO: capturamos o documento_id pra vincular ao histórico
      var documentoIdCriado = null;
      if (pdfUrlPortaria) {
        try {
          var rDoc = await api('documentos', 'POST', {
            cliente_id: p.cliente_id,
            projeto_id: projetoAtualId,
            tipo: 'OUTORGA',
            titulo: 'Portaria de Outorga ' + portaria,
            numero: portaria,
            orgao: 'SP Águas',
            data_emissao: data,
            arquivo_url: pdfUrlPortaria,
            visivel_cliente: true,
            observacao: 'Portaria oficial de outorga publicada.'
          }, 'return=representation');
          if (rDoc && rDoc.ok) {
            var dataDoc = await rDoc.json();
            if (dataDoc && dataDoc[0] && dataDoc[0].id) {
              documentoIdCriado = dataDoc[0].id;
            }
          }
        } catch(e) {
          console.error('Falha ao registrar documento público:', e);
          // não bloqueia o fluxo — o PDF já está nos pontos
        }
      }

      // ============================================================
      // ONDA HISTÓRICO DE OUTORGAS: registra cada outorga publicada
      // ============================================================
      // Pra cada ponto da propriedade:
      //   1. Se já existe outorga vigente → marca como 'substituida' (e linka pra nova)
      //   2. Insere nova linha em outorgas_historico com status='vigente'
      //
      // Isso mantém o rastro de todas as renovações ao longo dos anos,
      // sem nunca perder dado anterior.
      // ============================================================
      for (const u of usosProp) {
        try {
          // 1. Buscar outorga vigente anterior (se houver)
          var vigentesAnteriores = await api(
            'outorgas_historico?uso_id=eq.' + u.id + '&status=eq.vigente&select=id'
          ) || [];

          // 2. Inserir nova como vigente
          var rNova = await api('outorgas_historico', 'POST', {
            uso_id: u.id,
            propriedade_id: p.propriedade_id,
            cliente_id: p.cliente_id,
            projeto_id: projetoAtualId,
            documento_id: documentoIdCriado,
            portaria: portaria,
            data_emissao: data,
            prazo_meses: prazoMeses,
            eh_dispensa: ehDispensa,  // ONDA HISTÓRICO: marca tipo explicitamente
            pdf_url: pdfUrlPortaria,
            requerimento: u.requerimento || p.requerimento || null,
            status: 'vigente',
            motivo: ehDispensa ? 'dispensa de outorga' : ((vigentesAnteriores && vigentesAnteriores.length > 0) ? 'renovação' : 'publicação inicial'),
            criado_por: criadoPor
          }, 'return=representation');

          // 3. Marcar anteriores como substituídas (apontando pra nova)
          if (rNova && rNova.ok && vigentesAnteriores && vigentesAnteriores.length > 0) {
            var dataNova = await rNova.json();
            var novoId = dataNova && dataNova[0] && dataNova[0].id;
            if (novoId) {
              for (const vAnt of vigentesAnteriores) {
                try {
                  await api('outorgas_historico?id=eq.' + vAnt.id, 'PATCH', {
                    status: 'substituida',
                    substituida_por_id: novoId
                  }, 'return=minimal');
                } catch(e) { /* segue */ }
              }
            }
          }
        } catch(e) {
          console.error('Falha ao registrar histórico de outorga (não bloqueia):', e);
          // Importante: NÃO bloqueia o fluxo. Sistema funciona mesmo sem histórico.
        }
      }

      // 4. Histórico
      await api('projeto_historico', 'POST', {
        projeto_id: projetoAtualId,
        acao: 'projeto_concluido',
        para_valor: 'concluido',
        observacao: 'Outorga publicada — Portaria ' + portaria + ' (' + (ehDispensa ? 'DISPENSA — sem prazo' : 'prazo ' + prazoMeses + ' meses') + ')' + (pdfUrlPortaria ? ' · PDF anexado' : '') + '.',
        criado_por: criadoPor
      }, 'return=minimal');

      fecharModal('ov-publicar-outorga');

      // ONDA PUBLICAÇÃO POR PONTO: comportamento muda conforme o modo
      if (modoPorPonto) {
        // Recarrega só os dados, mantém modal do projeto aberto pra usuário
        // continuar publicando os outros pontos
        await carregarDados();
        // Re-abre projeto pra mostrar o banner atualizado
        var _pidAtual = projetoAtualId;
        if (_pidAtual) {
          // Não fecha o modal — só re-renderiza dentro dele
          var _pAtual = projetos.find(function(pp){ return pp.id === _pidAtual; });
          if (_pAtual) {
            _renderPropriedadesPontosProjeto(_pAtual);
            carregarHistoricoProjeto(_pidAtual);
          }
        }
        renderKanban();

        // Reset do estado
        _pontoEspecificoPublicar = null;

        var _uPub = (typeof usos !== 'undefined' ? usos : []).find(function(uu){ return uu.id === usoIdEspecifico; });
        var _nomePub = (_uPub && _uPub.descricao) || 'ponto';
        var msgOK = '✅ Publicação registrada pro ponto "' + _nomePub + '"!\n\n' +
          (ehDispensa ? '📌 Dispensa de outorga registrada.' : '📜 Portaria ' + portaria + ' registrada.') +
          '\n\nQuando todos os pontos tiverem publicação, use "🎉 Finalizar projeto e ativar cliente" no banner verde.';
        zAlert(msgOK, 'sucesso');
        return;
      }

      // Modo legado (publicação única pra tudo): fecha projeto e ativa cliente
      fecharModal('ov-ver-projeto');
      projetoAtualId = null;
      await carregarDados();
      renderKanban();

      let msg = '✅ Outorga publicada com sucesso!\n\n• Cliente movido para "Clientes ativos"\n• Pontos atualizados com Portaria ' + portaria + '\n• Portal ativado — cliente cria PIN no 1º acesso';
      zAlert(msg, 'aviso');

      // 5. WhatsApp opcional — manda só o link, sem PIN
      // ONDA 2026-05-26: cliente cria próprio PIN no 1º acesso ao portal.
      if (enviarWpp) {
        const cli = todosClientesUnificado(p.cliente_id) || {};
        const tel = (cli.telefone1 || '').replace(/\D/g,'');
        if (tel) {
          const cleanTel = tel.length === 11 || tel.length === 10 ? '55' + tel : tel;
          const txt = 'Olá ' + (cli.nome ? cli.nome.split(' ')[0] : '') +
            '! Sua outorga foi publicada (Portaria ' + portaria + ').\n\n' +
            '*Portal Zello Ambiental*\n' +
            'Acesse para ver sua portaria e gerenciar a outorga:\n' +
            getClienteUrl() + '\n\n' +
            '*No primeiro acesso:*\n' +
            '• Use seu CPF/CNPJ: ' + (cli.cpf_cnpj || '—') + '\n' +
            '• Crie um PIN de 4 dígitos (memorize, é a sua senha)\n\n' +
            'Eng. Guilherme Montanari - Zello Ambiental';
          window.open('https://wa.me/' + cleanTel + '?text=' + encodeURIComponent(txt), '_blank');
        } else {
          zAlert('Cliente sem telefone cadastrado. Avise manualmente que o portal está liberado pelo CPF/CNPJ.', 'sucesso');
        }
      }

    } catch(e) {
      console.error('Erro confirmarPublicarOutorga:', e);
      zAlert('Erro ao publicar: ' + (e.message || e), 'erro');
      _pontoEspecificoPublicar = null;  // reset em caso de erro também
    } finally {
      btn.disabled = false; btn.textContent = '✅ Publicar e ativar cliente';
    }
  }


  // ============================================================
  // FINANCEIRO (valor_total + NF + pagamentos)
  // ============================================================
  function atualizarCardsFinanceiro(p) {
    document.getElementById('fin-valor-total').textContent = fmtBRL(p.valor_total);
    document.getElementById('fin-valor-pago').textContent = fmtBRL(p.valor_pago);
    const saldo = (p.valor_total || 0) - (p.valor_pago || 0);
    document.getElementById('fin-saldo').textContent = 'Saldo: ' + fmtBRL(saldo);
    const stPgto = p.status_pgto || 'aberto';
    const stLabel = { aberto:'ABERTO', parcial:'PARCIAL', quitado:'QUITADO' }[stPgto];
    document.getElementById('fin-status-pgto').innerHTML = '<span class="pgto-tag pg-' + stPgto + '">' + stLabel + '</span>';

    // REVISÃO: Seção comissão (admin only)
    renderSecaoComissaoProjeto(p);
  }

  // REVISÃO: Mostra info da comissão + opções de troca de hunter / recalcular
  async function renderSecaoComissaoProjeto(p) {
    const sec = document.getElementById('proj-secao-comissao');
    if (!sec) return;
    if (!souAdmin()) { sec.style.display = 'none'; return; }
    sec.style.display = '';

    const info = document.getElementById('proj-comissao-info');
    if (!info) return;

    const _vMinCom = await getValorMinimoProposta();

    // 1. Tem hunter?
    let huntInfo = '<em>Sem hunter associado — não vai gerar comissão.</em>';
    if (p.hunter_id_origem) {
      const huntObj = (_usuariosCache || []).find(function(u){ return u.id === p.hunter_id_origem; });
      if (huntObj) {
        const cor = huntObj.cor ? CORES_TIMES[huntObj.cor] : null;
        const emoji = cor ? cor.emoji : '👤';
        huntInfo = '<strong>Hunter:</strong> ' + emoji + ' ' + escapeHtml(huntObj.nome);
      } else {
        huntInfo = '<em>Hunter não encontrado (excluído?)</em>';
      }
    }

    // 2. Tem comissão registrada?
    let comInfo = '';
    try {
      const r = await fetch(SUPABASE_URL + '/rest/v1/comissoes?projeto_id=eq.' + p.id + '&select=*', {
        headers: { 'apikey': SUPABASE_KEY, 'Authorization': 'Bearer ' + SUPABASE_KEY }
      });
      if (r.ok) {
        const coms = await r.json();
        if (coms.length === 0) {
          if (p.pago_1) {
            // Pago 1º mas sem comissão → diagnóstico
            let motivo = '';
            if (!p.hunter_id_origem) motivo = 'sem hunter associado';
            else if (!p.valor_total || p.valor_total < _vMinCom) motivo = 'valor R$ ' + (p.valor_total||0) + ' < mínimo R$ ' + _vMinCom.toLocaleString('pt-BR');
            else motivo = 'a trigger SQL pode não estar instalada';
            comInfo = '<br/><strong style="color:#C62828;">⚠ Pago 1º marcado mas sem comissão!</strong><br/><em>Motivo provável: ' + motivo + '</em>';
          } else {
            comInfo = '<br/><em>Comissão será gerada quando "Pago 1º" for marcado.</em>';
          }
        } else {
          const c = coms[0];
          const valor = parseFloat(c.valor_comissao || 0).toLocaleString('pt-BR');
          const status = c.status_pagamento === 'pago' ? '✅ PAGO' : (c.status_pagamento === 'estornado' ? '↩ ESTORNADO' : '⏳ PENDENTE');
          comInfo = '<br/><strong>Comissão:</strong> R$ ' + valor + ' · ' + c.numero_fechamento_mes + 'º do mês · ' + status;
        }
      }
    } catch(e) { console.warn('Erro renderSecaoComissao:', e); }

    info.innerHTML = huntInfo + comInfo;
  }

  // REVISÃO: Admin troca o hunter de um projeto
  async function reatribuirHunterProjeto() {
    if (!projetoAtualId) return;
    if (!souAdmin()) return;
    const p = projetos.find(function(pp){ return pp.id === projetoAtualId; });
    if (!p) return;

    const hunters = (_usuariosCache || []).filter(function(u){ return u.papel === 'hunter' && u.ativo; });
    if (hunters.length === 0) {
      zAlert('Não há hunters cadastrados.', 'aviso');
      return;
    }

    // ONDA 2 BUG#6: usa modal visual em vez de prompt nativo
    // Marca o hunter atual com indicador visual (ATUAL)
    const escolhido = await selecionarHunter({
      titulo: 'Trocar hunter responsável',
      mensagem: 'Escolha o novo hunter responsável pela comissão deste projeto.',
      atualId: p.hunter_id_origem || null,
      permitirNenhum: true
    });
    if (escolhido === false) return;   // cancelou
    const novoHunterId = escolhido;     // null ou id

    if (novoHunterId === p.hunter_id_origem) {
      zAlert('Hunter não mudou.', 'info');
      return;
    }

    if (!(await zConfirm('Trocar o hunter responsável?\n\nDe: ' + (p.hunter_id_origem ? 'hunter atual' : 'sem hunter') + '\nPara: ' + (novoHunterId ? 'novo hunter' : 'nenhum') + '\n\nSe já existe comissão pendente, ela será ESTORNADA e uma nova será gerada (se aplicável).', { tipo:'erro', btnOk:'Trocar' }))) return;

    try {
      // 1. Estorna comissão existente (se houver, e pendente)
      await fetch(SUPABASE_URL + '/rest/v1/comissoes?projeto_id=eq.' + projetoAtualId + '&status_pagamento=eq.pendente', {
        method: 'PATCH',
        headers: { 'apikey': SUPABASE_KEY, 'Authorization': 'Bearer ' + SUPABASE_KEY, 'Content-Type': 'application/json', 'Prefer': 'return=minimal' },
        body: JSON.stringify({ status_pagamento: 'estornado' })
      });

      // 2. Atualiza hunter no projeto
      const r = await fetch(SUPABASE_URL + '/rest/v1/projetos?id=eq.' + projetoAtualId, {
        method: 'PATCH',
        headers: { 'apikey': SUPABASE_KEY, 'Authorization': 'Bearer ' + SUPABASE_KEY, 'Content-Type': 'application/json', 'Prefer': 'return=minimal' },
        body: JSON.stringify({ hunter_id_origem: novoHunterId })
      });
      if (!r.ok) throw new Error('HTTP ' + r.status);

      p.hunter_id_origem = novoHunterId;

      // 3. Se pago_1=true e tem novo hunter, força recriação da comissão
      if (p.pago_1 && novoHunterId) {
        await recalcularComissaoInterno(p.id);
      }

      // FIX BUG #11: registra mudança no histórico do projeto (auditoria)
      try {
        const sess2 = getSessao();
        const huntAntigoNome = p.hunter_id_origem ?
          ((_usuariosCache || []).find(function(u){ return u.id === p.hunter_id_origem; }) || {}).nome || '(?)' :
          '(sem hunter)';
        const huntNovoNome = novoHunterId ?
          ((_usuariosCache || []).find(function(u){ return u.id === novoHunterId; }) || {}).nome || '(?)' :
          '(sem hunter)';
        await api('projeto_historico', 'POST', {
          projeto_id: projetoAtualId,
          acao: 'hunter_alterado',
          observacao: 'Hunter alterado de "' + huntAntigoNome + '" para "' + huntNovoNome + '"' + (p.pago_1 && novoHunterId ? '. Comissão recalculada.' : ''),
          criado_por: (sess2 && sess2.nome) || 'admin'
        }, 'return=minimal');
      } catch(e) { console.warn('Erro registrando histórico:', e); }

      zAlert('✅ Hunter atualizado!\n\n' + (novoHunterId && p.pago_1 ? 'Comissão recalculada.' : ''), 'sucesso');
      // Re-render
      const proj = projetos.find(function(pp){ return pp.id === projetoAtualId; });
      if (proj) renderSecaoComissaoProjeto(proj);
      atualizarCardComissoesDashboard();
    } catch(e) {
      zAlert('Erro: ' + (e.message || ''), 'erro');
    }
  }

  // REVISÃO: Recalcular comissão (deletar e disparar trigger de novo)
  async function recalcularComissaoProjeto() {
    if (!projetoAtualId) return;
    if (!souAdmin()) return;
    const p = projetos.find(function(pp){ return pp.id === projetoAtualId; });
    if (!p) return;

    if (!p.pago_1) {
      zAlert('Pago 1º não está marcado. Marque o checkbox primeiro pra gerar comissão.', 'aviso');
      return;
    }
    if (!p.hunter_id_origem) {
      zAlert('Sem hunter associado. Use "Trocar hunter" pra atribuir.', 'aviso');
      return;
    }
    const _vMin = await getValorMinimoProposta();
    if (!p.valor_total || p.valor_total < _vMin) {
      zAlert('Valor do projeto (R$ ' + (p.valor_total || 0) + ') está abaixo do mínimo (R$ ' + _vMin.toLocaleString('pt-BR') + ').\n\nAjuste o "Valor total" na seção acima e salve antes de recalcular.', 'aviso');
      return;
    }

    if (!(await zConfirm('Recalcular comissão?\n\nIsso vai:\n• Apagar comissão pendente (se houver) deste projeto\n• Disparar trigger pra criar nova\n\nÚtil se mudou hunter ou valor.', { tipo:'info', btnOk:'Recalcular' }))) return;

    try {
      await recalcularComissaoInterno(projetoAtualId);
      zAlert('✅ Comissão recalculada!', 'aviso');
      renderSecaoComissaoProjeto(p);
      atualizarCardComissoesDashboard();
    } catch(e) {
      zAlert('Erro: ' + (e.message || ''), 'erro');
    }
  }

  // Auxiliar interno: deleta comissões pendentes do projeto e força re-trigger
  async function recalcularComissaoInterno(projetoId) {
    // 1. Deleta comissões PENDENTES deste projeto (preserva pagas/estornadas)
    const rDel = await fetch(SUPABASE_URL + '/rest/v1/comissoes?projeto_id=eq.' + projetoId + '&status_pagamento=eq.pendente', {
      method: 'DELETE',
      headers: { 'apikey': SUPABASE_KEY, 'Authorization': 'Bearer ' + SUPABASE_KEY }
    });
    if (!rDel.ok) console.warn('Erro ao deletar comissão pendente:', rDel.status);

    // 2. Toggle pago_1 (false → true) pra disparar trigger
    // FIX BUG #5: aguarda cada PATCH terminar de verdade
    const r1 = await fetch(SUPABASE_URL + '/rest/v1/projetos?id=eq.' + projetoId, {
      method: 'PATCH',
      headers: { 'apikey': SUPABASE_KEY, 'Authorization': 'Bearer ' + SUPABASE_KEY, 'Content-Type': 'application/json', 'Prefer': 'return=minimal' },
      body: JSON.stringify({ pago_1: false })
    });
    if (!r1.ok) throw new Error('Erro ao resetar pago_1: ' + r1.status);

    // Pequeno delay pra garantir consistência
    await new Promise(function(res){ setTimeout(res, 400); });

    const r2 = await fetch(SUPABASE_URL + '/rest/v1/projetos?id=eq.' + projetoId, {
      method: 'PATCH',
      headers: { 'apikey': SUPABASE_KEY, 'Authorization': 'Bearer ' + SUPABASE_KEY, 'Content-Type': 'application/json', 'Prefer': 'return=minimal' },
      body: JSON.stringify({ pago_1: true, pago_1_em: getDataHojeBR() })
    });
    if (!r2.ok) throw new Error('Erro ao marcar pago_1: ' + r2.status);

    // Aguarda trigger rodar
    await new Promise(function(res){ setTimeout(res, 800); });

    // Verifica se comissão foi criada
    const rCheck = await fetch(SUPABASE_URL + '/rest/v1/comissoes?projeto_id=eq.' + projetoId + '&status_pagamento=eq.pendente&select=id', {
      headers: { 'apikey': SUPABASE_KEY, 'Authorization': 'Bearer ' + SUPABASE_KEY }
    });
    if (rCheck.ok) {
      const coms = await rCheck.json();
      if (coms.length === 0) {
        throw new Error('Trigger não criou comissão. Verifique se a migração SQL foi rodada.');
      }
    }
  }

  async function salvarFinanceiroProjeto() {
    if (!projetoAtualId) return;
    const valorStr = document.getElementById('ver-proj-valor-total').value.trim();
    const nf = document.getElementById('ver-proj-nf').value.trim();
    const nfUrl = document.getElementById('ver-proj-nf-url').value.trim();

    let valor = null;
    if (valorStr) {
      const v = parseFloat(valorStr.replace(',', '.'));
      if (isNaN(v) || v < 0) { zAlert('Valor total inválido.', 'aviso'); return; }
      valor = v;
    }

    try {
      // Recalcula status_pgto
      const proj = projetos.find(function(pp){ return pp.id === projetoAtualId; });
      const pago = proj.valor_pago || 0;
      let stPgto = 'aberto';
      if (valor != null && valor > 0) {
        if (pago >= valor) stPgto = 'quitado';
        else if (pago > 0) stPgto = 'parcial';
      }
      const r = await api('projetos?id=eq.' + projetoAtualId, 'PATCH', {
        valor_total: valor,
        nf_numero: nf || null,
        nf_url: nfUrl || null,
        status_pgto: stPgto,
        atualizado_em: new Date().toISOString()
      }, 'return=minimal');
      if (!r || !r.ok) throw new Error('HTTP ' + (r ? r.status : '?'));
      await carregarDados();
      verProjeto(projetoAtualId);
      const btn = event && event.target;
      if (btn && btn.tagName === 'BUTTON') {
        const orig = btn.textContent;
        btn.textContent = '✓ Salvo';
        setTimeout(function(){ btn.textContent = orig; }, 1500);
      }
    } catch(e) {
      console.error('Erro salvarFinanceiroProjeto:', e);
      zAlert('Erro: ' + (e.message || e), 'erro');
    }
  }

  async function carregarPagamentosProjeto(pid) {
    try {
      pagamentosProjAtual = await api('projeto_pagamentos?projeto_id=eq.' + pid + '&order=data_prevista.asc.nullslast,data_pago.desc.nullslast') || [];
    } catch(e) { pagamentosProjAtual = []; }
    renderPagamentosProjeto();
  }

  function renderPagamentosProjeto() {
    const cont = document.getElementById('ver-proj-pgtos-lista');
    if (!cont) return;
    if (!pagamentosProjAtual.length) {
      cont.innerHTML = '<div class="hist-empty">Nenhum pagamento registrado.</div>';
      return;
    }
    cont.innerHTML = pagamentosProjAtual.map(function(pg) {
      const pago = !!pg.data_pago;
      const icone = pago ? '✓' : '⏳';
      const cor = pago ? '#2E7D32' : '#E65100';
      const dataStr = pago
        ? ('pago em ' + fmtData(pg.data_pago))
        : (pg.data_prevista ? 'previsto pra ' + fmtData(pg.data_prevista) : 'a receber');
      const linkComp = pg.comprovante_url
        ? '<a href="' + escapeHtml(pg.comprovante_url) + '" target="_blank" class="btn btn-sm" style="background:#E3F2FD;color:#1565C0;margin-right:4px;" title="Ver comprovante">🔗</a>'
        : '';
      return '<div class="hist-item">' +
        '<div class="hist-icon" style="background:' + (pago ? '#E8F5E9' : '#FFF3E0') + ';color:' + cor + ';">' + icone + '</div>' +
        '<div class="hist-body">' +
          '<div class="hist-title-row">' +
            '<span class="hist-tipo">' + fmtBRL(pg.valor) + '</span>' +
            '<span class="hist-data">' + dataStr + '</span>' +
          '</div>' +
          '<div class="hist-desc">' + (pg.forma || '—') + (pg.observacao ? ' · ' + pg.observacao.replace(/</g,'&lt;') : '') + '</div>' +
        '</div>' +
        '<div style="display:flex;gap:4px;align-items:center;">' + linkComp + '<button class="btn btn-sm btn-danger" onclick="excluirPagamento(\'' + pg.id + '\')" title="Excluir">🗑</button></div>' +
      '</div>';
    }).join('');
  }

  function abrirRegistrarPagamento() {
    if (!projetoAtualId) return;
    const p = projetos.find(function(pp){ return pp.id === projetoAtualId; });
    if (!p) return;
    document.getElementById('reg-pgto-id').value = '';
    document.getElementById('reg-pgto-proj-nome').textContent = p.nome;
    document.getElementById('reg-pgto-valor').value = '';
    document.getElementById('reg-pgto-forma').value = 'PIX';
    document.getElementById('reg-pgto-prevista').value = getDataHojeBR();
    document.getElementById('reg-pgto-data').value = '';
    document.getElementById('reg-pgto-obs').value = '';
    const compEl = document.getElementById('reg-pgto-comprovante');
    if (compEl) compEl.value = '';
    abrirModal('ov-reg-pgto');
  }

  async function salvarRegistroPagamento() {
    if (!projetoAtualId) return;
    const valorStr = document.getElementById('reg-pgto-valor').value.trim();
    const forma = document.getElementById('reg-pgto-forma').value;
    const prev = document.getElementById('reg-pgto-prevista').value || null;
    const data = document.getElementById('reg-pgto-data').value || null;
    const obs = document.getElementById('reg-pgto-obs').value.trim();
    const comprovanteUrlEl = document.getElementById('reg-pgto-comprovante');
    const comprovanteUrl = comprovanteUrlEl ? comprovanteUrlEl.value.trim() : '';

    if (!valorStr) { zAlert('Valor é obrigatório.', 'aviso'); return; }
    const valor = parseFloat(valorStr.replace(',', '.'));
    if (isNaN(valor) || valor <= 0) { zAlert('Valor inválido.', 'aviso'); return; }

    const sess = getSessao();
    const criadoPor = (sess && sess.nome) ? sess.nome : (sess && sess.email ? sess.email : 'admin');

    const btn = document.getElementById('btn-salvar-pgto');
    btn.disabled = true; btn.textContent = '⏳ Salvando...';

    try {
      // 1. Cria pagamento
      const r = await api('projeto_pagamentos', 'POST', {
        projeto_id: projetoAtualId,
        data_prevista: prev,
        data_pago: data,
        valor: valor,
        forma: forma,
        observacao: obs || null,
        comprovante_url: comprovanteUrl || null,
        criado_por: criadoPor
      }, 'return=minimal');
      if (!r || !r.ok) throw new Error('HTTP ' + (r ? r.status : '?'));

      // 2. Recalcula valor_pago do projeto (soma de tudo com data_pago)
      const todosPgs = await api('projeto_pagamentos?projeto_id=eq.' + projetoAtualId);
      const totalPago = (todosPgs || []).filter(function(x){ return x.data_pago; }).reduce(function(acc, x){ return acc + (parseFloat(x.valor) || 0); }, 0);

      // 3. Atualiza projeto + recalcula status_pgto
      const proj = projetos.find(function(pp){ return pp.id === projetoAtualId; });
      const valTotal = proj.valor_total || 0;
      let stPgto = 'aberto';
      if (valTotal > 0) {
        if (totalPago >= valTotal) stPgto = 'quitado';
        else if (totalPago > 0) stPgto = 'parcial';
      } else if (totalPago > 0) {
        stPgto = 'parcial';
      }

      await api('projetos?id=eq.' + projetoAtualId, 'PATCH', {
        valor_pago: totalPago,
        status_pgto: stPgto,
        atualizado_em: new Date().toISOString()
      }, 'return=minimal');

      // 4. Histórico
      await api('projeto_historico', 'POST', {
        projeto_id: projetoAtualId,
        acao: 'pagamento_registrado',
        para_valor: fmtBRL(valor),
        observacao: forma + (obs ? ' · ' + obs : ''),
        criado_por: criadoPor
      }, 'return=minimal');

      fecharModal('ov-reg-pgto');
      await carregarDados();
      verProjeto(projetoAtualId);
    } catch(e) {
      console.error('Erro salvarRegistroPagamento:', e);
      zAlert('Erro ao salvar: ' + (e.message || e), 'erro');
    } finally {
      btn.disabled = false; btn.textContent = '💾 Salvar';
    }
  }

  async function excluirPagamento(pgId) {
    if (!confirm('Excluir este registro de pagamento?\n\nO valor pago do projeto será recalculado.')) return;
    try {
      await api('projeto_pagamentos?id=eq.' + pgId, 'DELETE', null, 'return=minimal');

      // Recalcula valor_pago do projeto
      if (projetoAtualId) {
        const todosPgs = await api('projeto_pagamentos?projeto_id=eq.' + projetoAtualId);
        const totalPago = (todosPgs || []).filter(function(x){ return x.data_pago; }).reduce(function(acc, x){ return acc + (parseFloat(x.valor) || 0); }, 0);
        const proj = projetos.find(function(pp){ return pp.id === projetoAtualId; });
        const valTotal = proj.valor_total || 0;
        let stPgto = 'aberto';
        if (valTotal > 0) {
          if (totalPago >= valTotal) stPgto = 'quitado';
          else if (totalPago > 0) stPgto = 'parcial';
        } else if (totalPago > 0) {
          stPgto = 'parcial';
        }
        await api('projetos?id=eq.' + projetoAtualId, 'PATCH', {
          valor_pago: totalPago,
          status_pgto: stPgto,
          atualizado_em: new Date().toISOString()
        }, 'return=minimal');
        await carregarDados();
        verProjeto(projetoAtualId);
      }
    } catch(e) {
      zAlert('Erro: ' + (e.message || e), 'erro');
    }
  }


  // ============================================================
  // DOCUMENTOS DO PROJETO
  // ============================================================
  async function carregarDocsProjeto(pid) {
    try {
      // POST-ONDA 4 (FIX CRÍTICO): carrega docs por projeto_id E também
      // docs órfãos do cliente (cliente_id mas sem projeto_id) — pra mostrar
      // proposta assinada anexada no lead antes de virar projeto
      const proj = (typeof projetos !== 'undefined' ? projetos : []).find(function(p){ return p.id === pid; });
      const cid = proj && proj.cliente_id;
      const queries = ['documentos?projeto_id=eq.' + pid + '&order=created_at.desc'];
      if (cid) {
        // Adiciona docs do cliente sem projeto vinculado
        queries.push('documentos?cliente_id=eq.' + cid + '&projeto_id=is.null&order=created_at.desc');
      }
      const resps = await Promise.all(queries.map(function(q){ return api(q).catch(function(){ return []; }); }));
      const dedupe = {};
      [].concat(resps[0] || [], resps[1] || []).forEach(function(d){ dedupe[d.id] = d; });
      docsProjAtual = Object.values(dedupe).sort(function(a, b){
        return (b.created_at || '').localeCompare(a.created_at || '');
      });
    } catch(e) { docsProjAtual = []; }
    renderDocsProjeto();
  }

  // ONDA F1: Refresh manual da aba Documentos (chamado pelo botão "Atualizar lista").
  // Útil quando o cliente sobe documento pelo portal e você quer ver na hora,
  // sem fechar e reabrir o modal do projeto.
  async function refreshDocsProjeto() {
    if (!projetoAtualId) return;
    const btn = document.querySelector('[onclick="refreshDocsProjeto()"]');
    const textoOriginal = btn ? btn.innerHTML : '';
    if (btn) { btn.innerHTML = '⏳ Atualizando...'; btn.disabled = true; }
    try {
      const qtdAntes = docsProjAtual.length;
      await carregarDocsProjeto(projetoAtualId);
      const qtdDepois = docsProjAtual.length;
      if (qtdDepois > qtdAntes) {
        toastSuccess('✓ ' + (qtdDepois - qtdAntes) + ' novo(s) documento(s) carregado(s).');
      } else {
        toastSuccess('Lista atualizada.');
      }
    } catch(e) {
      console.error('refreshDocsProjeto:', e);
      toastError('Falha ao atualizar lista.');
    } finally {
      if (btn) { btn.innerHTML = textoOriginal; btn.disabled = false; }
    }
  }
  window.refreshDocsProjeto = refreshDocsProjeto;

  function renderDocsProjeto() {
    const cont = document.getElementById('ver-proj-docs-lista');
    if (!cont) return;
    document.getElementById('ver-proj-cnt-docs').textContent = '(' + docsProjAtual.length + ')';
    if (!docsProjAtual.length) {
      cont.innerHTML = '<div class="hist-empty">Nenhum documento anexado ao projeto.</div>';
      return;
    }
    const tipoIcone = { laudo:'📋', art:'📝', croqui:'🗺', protocolo:'📥', exigencia:'⚠', outro:'📄' };
    cont.innerHTML = docsProjAtual.map(function(d) {
      const ic = tipoIcone[d.tipo] || '📄';
      // POST-ONDA 4: doc sem projeto_id veio do lead (anexado antes de virar projeto)
      const badgeLead = !d.projeto_id ? ' <span style="font-size:9px;background:#FFF3E0;color:#E65100;padding:1px 6px;border-radius:8px;font-weight:600;">do lead</span>' : '';
      // ONDA 107: indicador de visibilidade pro cliente (cadeado fechado = privado)
      const visivel = !!d.visivel_cliente;
      const badgeVisib = visivel
        ? ' <span style="font-size:9px;background:#DCFCE7;color:#15803D;padding:1px 6px;border-radius:8px;font-weight:600;" title="Visível pra o cliente no portal">👁️ visível pro cliente</span>'
        : ' <span style="font-size:9px;background:#F3F4F6;color:#6B7280;padding:1px 6px;border-radius:8px;font-weight:600;" title="Não aparece no portal do cliente">🔒 privado</span>';
      // Botão de toggle (1 clique pra alternar)
      const btnToggle = visivel
        ? '<button class="btn btn-sm" style="background:#DCFCE7;color:#15803D;border:1px solid #86EFAC;" onclick="toggleVisibDocCliente(\'' + d.id + '\', false)" title="Ocultar do portal do cliente">👁️ Visível</button>'
        : '<button class="btn btn-sm" style="background:#F3F4F6;color:#6B7280;border:1px solid #D1D5DB;" onclick="toggleVisibDocCliente(\'' + d.id + '\', true)" title="Liberar para o cliente ver no portal">🔒 Privado</button>';
      return '<div class="hist-item">' +
        '<div class="hist-icon" style="background:#E3F2FD;color:#1565C0;">' + ic + '</div>' +
        '<div class="hist-body">' +
          '<div class="hist-title-row">' +
            '<span class="hist-tipo">' + (d.titulo || d.tipo || 'Documento') + badgeLead + badgeVisib + '</span>' +
            '<span class="hist-data">' + (d.created_at ? fmtData(d.created_at) : '') + '</span>' +
          '</div>' +
          (d.observacao ? '<div class="hist-desc">' + d.observacao.replace(/</g,'&lt;') + '</div>' : '') +
        '</div>' +
        '<div style="display:flex;gap:4px;flex-wrap:wrap;">' +
          btnToggle +
          (d.arquivo_url ? '<a href="' + d.arquivo_url + '" target="_blank" rel="noopener" class="btn btn-sm btn-blue">🔗 Abrir</a>' : '') +
          (d.arquivo_url ? '<button class="btn btn-sm" style="background:#E8F5E9;color:#2E7D32;border:1px solid #A5D6A7;" data-url="' + escapeHtml(d.arquivo_url) + '" data-nome="' + escapeHtml(d.arquivo_nome || d.titulo || 'documento') + '" onclick="baixarDocumentoArquivo(this.dataset.url, this.dataset.nome)" title="Baixar no computador">⬇️ Baixar</button>' : '') +
          '<button class="btn btn-sm" style="background:#E3F2FD;color:#1565C0;border:1px solid #90CAF9;" onclick="editarNomeDocProjeto(\'' + d.id + '\')" title="Editar nome">✏️</button>' +
          '<button class="btn btn-sm btn-danger" onclick="excluirDocProjeto(\'' + d.id + '\')" title="Excluir">🗑</button>' +
        '</div>' +
      '</div>';
    }).join('');
  }

  // ONDA 107: alterna a visibilidade de um documento pro cliente.
  // Default no banco é false (escondido). Toggle 1-clique.
  async function toggleVisibDocCliente(docId, novoValor) {
    try {
      await api('documentos?id=eq.' + docId, 'PATCH', { visivel_cliente: !!novoValor }, 'return=minimal');
      // Atualiza no estado local também
      const d = (typeof docsProjAtual !== 'undefined' ? docsProjAtual : []).find(function(x){ return x.id === docId; });
      if (d) d.visivel_cliente = !!novoValor;
      renderDocsProjeto();
      if (typeof toastSuccess === 'function') {
        toastSuccess(novoValor ? '✓ Documento agora é visível pro cliente' : '🔒 Documento escondido do cliente', 3000);
      }
    } catch(e) {
      console.error('toggleVisibDocCliente:', e);
      if (typeof toastError === 'function') toastError('Erro ao alterar visibilidade.');
    }
  }
  window.toggleVisibDocCliente = toggleVisibDocCliente;

  // POST-ONDA 4: editar o título (nome) de um documento já anexado
  async function editarNomeDocProjeto(docId) {
    const d = (typeof docsProjAtual !== 'undefined' ? docsProjAtual : []).find(function(x){ return x.id === docId; });
    if (!d) { toastError('Documento não encontrado.'); return; }
    const novo = await zPrompt('Nome do documento:', d.titulo || '');
    if (novo === null) return; // cancelou
    if (!novo.trim()) { zAlert('O nome não pode ficar vazio.', 'aviso'); return; }
    try {
      await api('documentos?id=eq.' + docId, 'PATCH', { titulo: novo.trim().toUpperCase() }, 'return=minimal');
      if (projetoAtualId) await carregarDocsProjeto(projetoAtualId);
    } catch(e) {
      console.error('editarNomeDocProjeto:', e);
      toastError('Erro ao renomear o documento.');
    }
  }

  // ONDA BATCH-PROJETO 2026-05-27: agora aceita múltiplos arquivos
  let _addDocProjFiles = []; // [File, File, ...]

  function abrirAddDocProjeto() {
    if (!projetoAtualId) return;
    const p = projetos.find(function(pp){ return pp.id === projetoAtualId; });
    if (!p) return;
    document.getElementById('add-doc-proj-sub').textContent = p.nome;
    document.getElementById('add-doc-proj-tipo').value = 'laudo';
    document.getElementById('add-doc-proj-obs').value = '';
    _addDocProjFiles = [];
    _renderListaAddDocProj();
    document.getElementById('add-doc-proj-dz-texto').textContent = 'Arraste os arquivos aqui ou clique para selecionar';
    const progEl = document.getElementById('add-doc-proj-progresso');
    if (progEl) { progEl.style.display = 'none'; progEl.textContent = ''; }
    const btn = document.getElementById('btn-add-doc-proj');
    if (btn) { btn.disabled = false; btn.textContent = '💾 Salvar'; }
    _setupDropzoneDocProj();
    abrirModal('ov-add-doc-proj');
  }

  // Renderiza a lista de arquivos selecionados (com botão remover)
  function _renderListaAddDocProj() {
    const lista = document.getElementById('add-doc-proj-lista');
    if (!lista) return;
    if (!_addDocProjFiles.length) {
      lista.style.display = 'none';
      lista.innerHTML = '';
      return;
    }
    lista.style.display = 'flex';
    lista.innerHTML = _addDocProjFiles.map(function(f, i) {
      const sizeKb = Math.round(f.size / 1024);
      const tamStr = sizeKb > 1024 ? (sizeKb/1024).toFixed(1) + ' MB' : sizeKb + ' KB';
      return '<div style="display:flex;align-items:center;gap:8px;padding:6px 10px;background:#f9fafb;border:1px solid #e5e7eb;border-radius:6px;">'
        + '<div style="font-size:18px;">📄</div>'
        + '<div style="flex:1;min-width:0;overflow:hidden;">'
        + '  <div style="font-size:12.5px;font-weight:600;overflow:hidden;text-overflow:ellipsis;white-space:nowrap;" title="'+escapeHtml(f.name)+'">'+escapeHtml(f.name)+'</div>'
        + '  <div style="font-size:10.5px;color:#6b7280;">'+tamStr+'</div>'
        + '</div>'
        + '<button class="btn btn-sm btn-danger" onclick="removerArquivoAddDocProj('+i+')" title="Remover este arquivo">×</button>'
        + '</div>';
    }).join('');
  }

  // Permite remover um arquivo individual da lista
  function removerArquivoAddDocProj(idx) {
    _addDocProjFiles.splice(idx, 1);
    _renderListaAddDocProj();
    if (!_addDocProjFiles.length) {
      document.getElementById('add-doc-proj-dz-texto').textContent = 'Arraste os arquivos aqui ou clique para selecionar';
    } else {
      document.getElementById('add-doc-proj-dz-texto').textContent = '✓ ' + _addDocProjFiles.length + ' arquivo(s) selecionado(s)';
    }
  }
  window.removerArquivoAddDocProj = removerArquivoAddDocProj;

  // Configura os eventos da área de upload (arrastar + clicar)
  function _setupDropzoneDocProj() {
    const dz = document.getElementById('add-doc-proj-dropzone');
    const inp = document.getElementById('add-doc-proj-file');
    if (!dz || !inp) return;
    dz.onclick = function(){ inp.click(); };
    inp.onchange = function(){
      if (inp.files && inp.files.length) _aceitarArquivosDocProj(inp.files);
      inp.value = ''; // reset pra permitir re-selecionar o mesmo arquivo se removido
    };
    dz.ondragover = function(e){ e.preventDefault(); dz.style.background = '#E3F2FD'; dz.style.borderColor = '#1565C0'; };
    dz.ondragleave = function(){ dz.style.background = '#F8FBFF'; dz.style.borderColor = '#90CAF9'; };
    dz.ondrop = function(e){
      e.preventDefault();
      dz.style.background = '#F8FBFF'; dz.style.borderColor = '#90CAF9';
      if (e.dataTransfer.files && e.dataTransfer.files.length) _aceitarArquivosDocProj(e.dataTransfer.files);
    };
  }

  // Valida cada arquivo e adiciona à lista (pode chamar várias vezes acumulando)
  function _aceitarArquivosDocProj(fileList) {
    let adicionados = 0;
    let pulados = 0;
    for (let i = 0; i < fileList.length; i++) {
      const f = fileList[i];
      if (f.size > 10 * 1024 * 1024) {
        pulados++;
        continue;
      }
      _addDocProjFiles.push(f);
      adicionados++;
    }
    if (pulados > 0) {
      zAlert(pulados + ' arquivo(s) maior(es) que 10MB foi(ram) ignorado(s).', 'aviso');
    }
    _renderListaAddDocProj();
    if (_addDocProjFiles.length > 0) {
      document.getElementById('add-doc-proj-dz-texto').textContent = '✓ ' + _addDocProjFiles.length + ' arquivo(s) selecionado(s) — arraste mais ou clique pra adicionar';
    }
  }

  async function salvarDocProjeto() {
    if (!projetoAtualId) return;
    const tipo = document.getElementById('add-doc-proj-tipo').value;
    const obs = document.getElementById('add-doc-proj-obs').value.trim();
    if (!_addDocProjFiles.length) { zAlert('Selecione pelo menos 1 arquivo.', 'aviso'); return; }

    const sess = getSessao();
    const criadoPor = (sess && sess.nome) ? sess.nome : (sess && sess.email ? sess.email : 'admin');
    const proj = projetos.find(function(pp){ return pp.id === projetoAtualId; });

    const btn = document.getElementById('btn-add-doc-proj');
    btn.disabled = true;

    const progEl = document.getElementById('add-doc-proj-progresso');
    progEl.style.display = 'block';
    progEl.style.background = '#E3F2FD';
    progEl.style.color = '#1565C0';

    let ok = 0;
    let falhas = 0;
    const total = _addDocProjFiles.length;

    for (let i = 0; i < total; i++) {
      const arq = _addDocProjFiles[i];
      const numFmt = (i+1) + ' de ' + total;
      progEl.textContent = '📤 Enviando ' + numFmt + ': ' + arq.name;
      btn.textContent = 'Enviando ' + numFmt + '...';

      try {
        const safeNome = arq.name.replace(/[^\w.-]/g, '_').substring(0, 80);
        const path = 'projetos/' + projetoAtualId.replace(/-/g,'') + '/' + Date.now() + '_' + i + '_' + safeNome;
        const arquivoUrl = await uploadFile('documentos-zello', path, arq);
        if (!arquivoUrl) { falhas++; console.error('Falha no upload:', arq.name); continue; }

        // Título = nome do arquivo sem extensão (maiúsculas)
        const tituloAuto = arq.name.replace(/\.[^.]+$/, '').toUpperCase();

        const r = await api('documentos', 'POST', {
          projeto_id: projetoAtualId,
          cliente_id: proj.cliente_id,
          propriedade_id: proj.propriedade_id,
          tipo: tipo,
          titulo: tituloAuto,
          observacao: obs || null,
          arquivo_url: arquivoUrl,
          arquivo_nome: arq.name,
          ativo: true
        }, 'return=minimal');
        if (!r || !r.ok) { falhas++; console.error('Falha registro:', arq.name); continue; }

        await api('projeto_historico', 'POST', {
          projeto_id: projetoAtualId,
          acao: 'doc_anexado',
          para_valor: tipo,
          observacao: tituloAuto,
          criado_por: criadoPor
        }, 'return=minimal');

        ok++;
      } catch(e) {
        falhas++;
        console.error('Erro no batch projeto:', arq.name, e);
      }
    }

    btn.disabled = false;
    btn.textContent = '💾 Salvar';

    if (falhas === 0) {
      progEl.style.background = '#E8F5E9';
      progEl.style.color = '#2E7D32';
      progEl.textContent = '✅ ' + ok + ' documento(s) salvo(s) com sucesso!';
    } else {
      progEl.style.background = '#FFF3E0';
      progEl.style.color = '#E65100';
      progEl.textContent = '⚠ ' + ok + ' salvo(s), ' + falhas + ' falhou(falharam). Veja o console.';
    }

    await carregarDocsProjeto(projetoAtualId);
    await carregarHistoricoProjeto(projetoAtualId);

    if (falhas === 0) {
      setTimeout(function(){
        fecharModal('ov-add-doc-proj');
      }, 1200);
    }
  }

  async function excluirDocProjeto(docId) {
    if (!(await zConfirm('Excluir este documento?\n\nEsta ação não pode ser desfeita.', { tipo:'erro', btnOk:'Excluir' }))) return;
    try {
      await api('documentos?id=eq.' + docId, 'DELETE', null, 'return=minimal');
      if (projetoAtualId) await carregarDocsProjeto(projetoAtualId);
    } catch(e) {
      zAlert('Erro: ' + (e.message || e), 'erro');
    }
  }


  // ============================================================
  // LINK DE UPLOAD DO CLIENTE
  // ============================================================
  function copiarLinkUploadCliente() {
    if (!projetoAtualId) return;
    const p = projetos.find(function(pp){ return pp.id === projetoAtualId; });
    if (!p || !p.upload_token) { zAlert('Token de upload não encontrado.', 'erro'); return; }
    const link = getClienteUrl() + '?upload=' + p.upload_token;

    // Tenta clipboard API primeiro
    if (navigator.clipboard && navigator.clipboard.writeText) {
      navigator.clipboard.writeText(link).then(function() {
        zAlert('🔗 Link copiado!\n\n' + link + '\n\nEnvie ao cliente para ele anexar documentos.', 'sucesso');
      }, function() {
        prompt('Copie o link abaixo:', link);
      });
    } else {
      prompt('Copie o link abaixo:', link);
    }
  }

  // ============================================================
  // ONDA Z-API — ETAPA A (2026-06-22 v214)
  // Wrapper JS pra chamar a Edge Function `whatsapp-enviar`.
  // ============================================================
  // Esta função é a porta de entrada única do painel pro envio
  // automatizado de WhatsApp via Z-API. Não substitui ainda os
  // botões existentes que abrem wa.me/ — esses ficam em paralelo,
  // como fallback manual, até a Etapa B.
  //
  // Como funciona:
  //  1. Valida entrada client-side (evita ida desnecessária à Edge)
  //  2. Normaliza o telefone (mesma lógica da Edge, pra UI consistente)
  //  3. Chama POST /functions/v1/whatsapp-enviar com JWT anon
  //  4. Retorna { ok, mensagem_id, status, motivo?, erro? }
  //
  // Modo casca (sem secrets Z-API): a Edge ainda LOGA a mensagem
  // como `pendente` em whatsapp_mensagens e devolve motivo='zapi_nao_configurada'.
  // Isso permite construir e testar UI sem ter o Z-API ativo.
  //
  // Uso típico (quem chama trata o feedback):
  //   const r = await enviarWhatsAppViaApi(clienteId, '16981427633', 'Olá!');
  //   if (r.ok && r.status === 'enviada') zAlert('Enviado!', 'sucesso');
  //   else if (r.motivo === 'zapi_nao_configurada') zAlert('Z-API ainda não configurada — mensagem agendada', 'aviso');
  //   else zAlert('Erro: ' + (r.erro || 'desconhecido'), 'erro');
  // ============================================================

  // Normaliza pra formato Z-API: 55XXYYYYYYYYY (DDI + DDD + número).
  // Espelha a função da Edge — mantém UI consistente.
  function _normalizarTelefoneWpp(tel) {
    if (!tel) return null;
    var limpo = String(tel).replace(/\D/g, '');
    if (!limpo) return null;
    if (limpo.length === 10 || limpo.length === 11) {
      limpo = '55' + limpo;
    }
    if (limpo.length < 12 || limpo.length > 13) return null;
    return limpo;
  }
  window._normalizarTelefoneWpp = _normalizarTelefoneWpp;

  // Modo WhatsApp: 'api' (chama Edge Function) ou 'manual' (abre wa.me/)
  // Guardado em localStorage pra persistir entre sessões.
  function getModoWhatsApp() {
    var m = localStorage.getItem('zello_whatsapp_modo');
    return (m === 'api' || m === 'manual') ? m : 'manual';
  }
  window.getModoWhatsApp = getModoWhatsApp;

  function setModoWhatsApp(modo) {
    if (modo !== 'api' && modo !== 'manual') return;
    localStorage.setItem('zello_whatsapp_modo', modo);
  }
  window.setModoWhatsApp = setModoWhatsApp;

  async function enviarWhatsAppViaApi(clienteId, telefone, mensagem, criadoPor) {
    // 1) Validação client-side (rápida, sem rede)
    var telNorm = _normalizarTelefoneWpp(telefone);
    if (!telNorm) {
      return { ok: false, erro: 'telefone_invalido', detalhe: telefone };
    }
    var msg = (mensagem || '').toString().trim();
    if (!msg) {
      return { ok: false, erro: 'mensagem_vazia' };
    }
    if (msg.length > 4096) {
      return { ok: false, erro: 'mensagem_muito_longa', max: 4096, atual: msg.length };
    }

    // 2) Chama a Edge Function
    try {
      var resp = await fetch(SUPABASE_URL + '/functions/v1/whatsapp-enviar', {
        method: 'POST',
        headers: {
          'Authorization': 'Bearer ' + SUPABASE_KEY,
          'apikey': SUPABASE_KEY,
          'Content-Type': 'application/json'
        },
        body: JSON.stringify({
          cliente_id: clienteId || null,
          telefone: telNorm,
          mensagem: msg,
          criado_por: criadoPor || null
        })
      });
      var data = {};
      try { data = await resp.json(); } catch(_) { data = {}; }

      // 3) Resposta esperada da Edge:
      //    200 { ok:true, mensagem_id, status:'enviada' }                 → sucesso real
      //    200 { ok:true, motivo:'zapi_nao_configurada', status:'pendente' } → modo casca
      //    4xx { ok:false, erro }                                         → validação falhou na Edge
      //    502 { ok:false, erro:'falha_zapi' }                            → Z-API recusou
      //    500 { ok:false, erro:'erro_interno' }                          → bug Edge
      if (!resp.ok && resp.status !== 200) {
        // Edge retornou erro mas com JSON estruturado
        return Object.assign({ ok: false, erro: 'http_' + resp.status }, data);
      }
      return data;
    } catch (e) {
      // Erro de rede ou similar
      console.error('[enviarWhatsAppViaApi] falha de rede:', e);
      return { ok: false, erro: 'falha_rede', detalhe: e && e.message ? e.message : String(e) };
    }
  }
  window.enviarWhatsAppViaApi = enviarWhatsAppViaApi;

  // ============================================================
  // ONDA Z-API — ETAPA C (2026-06-22 v215)
  // Histórico de mensagens WhatsApp por cliente.
  // ============================================================
  // Lê whatsapp_mensagens?cliente_id=eq.X e renderiza num modal
  // próprio (ov-historico-whatsapp). Funciona já em modo casca:
  // mostra mensagens "pendentes" (logadas mas não enviadas porque
  // os secrets Z-API ainda não foram configurados).
  // ============================================================
  var _histWppClienteAtual = null;

  async function abrirHistoricoWhatsApp(clienteId) {
    if (!clienteId) { zAlert('Cliente não identificado.', 'erro'); return; }
    _histWppClienteAtual = clienteId;

    // Mostra nome do cliente no subtítulo
    var c = (typeof acharPessoa === 'function') ? acharPessoa(clienteId) : null;
    var nomeEl = document.getElementById('hist-wpp-cliente-nome');
    if (nomeEl) nomeEl.textContent = c ? c.nome : '(cliente)';

    // Abre o modal já com loading e dispara o fetch
    var lista = document.getElementById('hist-wpp-lista');
    if (lista) lista.innerHTML = '<div style="text-align:center;padding:24px;color:#94a3b8;">Carregando histórico...</div>';
    var ctd = document.getElementById('hist-wpp-contador');
    if (ctd) ctd.textContent = '—';

    abrirModal('ov-historico-whatsapp');
    await _carregarHistoricoWhatsApp(clienteId);
  }
  window.abrirHistoricoWhatsApp = abrirHistoricoWhatsApp;

  // Atalho quando estamos no modal de projeto aberto
  function abrirHistoricoWhatsAppProjetoAtual() {
    if (typeof projetoAtualId === 'undefined' || !projetoAtualId) {
      zAlert('Abra um projeto primeiro.', 'aviso');
      return;
    }
    var p = (typeof projetos !== 'undefined' ? projetos : []).find(function(x){ return x.id === projetoAtualId; });
    if (!p || !p.cliente_id) {
      zAlert('Projeto sem cliente vinculado.', 'erro');
      return;
    }
    return abrirHistoricoWhatsApp(p.cliente_id);
  }
  window.abrirHistoricoWhatsAppProjetoAtual = abrirHistoricoWhatsAppProjetoAtual;

  // Recarrega o histórico do cliente que está aberto no modal
  async function recarregarHistoricoWhatsApp() {
    if (!_histWppClienteAtual) return;
    await _carregarHistoricoWhatsApp(_histWppClienteAtual);
  }
  window.recarregarHistoricoWhatsApp = recarregarHistoricoWhatsApp;

  // Busca + renderiza
  async function _carregarHistoricoWhatsApp(clienteId) {
    var lista = document.getElementById('hist-wpp-lista');
    var ctd = document.getElementById('hist-wpp-contador');
    try {
      // Limite 100 — suficiente pra UX; cliente típico tem dezenas, não milhares
      var msgs = await api('whatsapp_mensagens?cliente_id=eq.' + clienteId + '&order=criado_em.desc&limit=100&select=*');
      msgs = msgs || [];

      if (ctd) {
        if (msgs.length === 0) {
          ctd.textContent = 'Nenhuma mensagem ainda';
        } else {
          var enviadas = msgs.filter(function(m){ return m.status === 'enviada'; }).length;
          var pendentes = msgs.filter(function(m){ return m.status === 'pendente'; }).length;
          var erros = msgs.filter(function(m){ return m.status === 'erro'; }).length;
          var partes = [msgs.length + ' total'];
          if (enviadas) partes.push(enviadas + ' enviadas');
          if (pendentes) partes.push(pendentes + ' pendentes');
          if (erros) partes.push(erros + ' com erro');
          ctd.textContent = partes.join(' · ');
        }
      }

      if (!lista) return;
      if (msgs.length === 0) {
        lista.innerHTML =
          '<div style="text-align:center;padding:30px 12px;color:#94a3b8;">' +
          '<div style="font-size:32px;margin-bottom:8px;">💬</div>' +
          '<div style="font-size:13px;">Nenhuma mensagem registrada ainda.</div>' +
          '<div style="font-size:11px;margin-top:6px;">As mensagens enviadas via Z-API vão aparecer aqui.</div>' +
          '</div>';
        return;
      }

      lista.innerHTML = msgs.map(_renderItemHistWpp).join('');
    } catch (e) {
      console.error('[abrirHistoricoWhatsApp] erro:', e);
      if (lista) lista.innerHTML =
        '<div style="text-align:center;padding:20px;color:#C62828;font-size:12px;">' +
        '⚠️ Erro ao carregar histórico: ' + (e.message || String(e)) +
        '</div>';
    }
  }

  // Renderiza UM item da lista de mensagens
  function _renderItemHistWpp(m) {
    var dir = m.tipo === 'recebida' ? '📥' : '📤';
    var dirLabel = m.tipo === 'recebida' ? 'Recebida' : 'Enviada';

    // Selo de status com cor por categoria
    var statusCfg = {
      pendente: { bg: '#FEF3C7', cor: '#92400E', icone: '⏳', label: 'Pendente' },
      enviada:  { bg: '#DCFCE7', cor: '#166534', icone: '✓', label: 'Enviada' },
      entregue: { bg: '#DBEAFE', cor: '#1E40AF', icone: '✓✓', label: 'Entregue' },
      lida:     { bg: '#E0E7FF', cor: '#3730A3', icone: '✓✓', label: 'Lida' },
      erro:     { bg: '#FEE2E2', cor: '#991B1B', icone: '✕', label: 'Erro' }
    };
    var sc = statusCfg[m.status] || { bg: '#F1F5F9', cor: '#475569', icone: '?', label: m.status || '—' };
    var seloStatus = '<span style="background:' + sc.bg + ';color:' + sc.cor + ';font-size:10px;font-weight:700;padding:2px 7px;border-radius:4px;">' + sc.icone + ' ' + sc.label + '</span>';

    // Data relativa ("agora", "5 min atrás", "ontem", "12/06" etc)
    var dataRel = _dataRelativa(m.criado_em);

    // Telefone formatado pra UX (5516981427633 → +55 16 98142-7633)
    var telFmt = _formatarTelefoneWpp(m.telefone || '');

    // Trecho da mensagem (corta longa)
    var msgTxt = (m.mensagem || '').toString();
    var msgFinal = msgTxt.length > 200 ? msgTxt.slice(0, 200) + '…' : msgTxt;

    // Erro destacado, se houver
    var blocoErro = '';
    if (m.status === 'erro' && m.erro_msg) {
      blocoErro = '<div style="margin-top:4px;padding:4px 8px;background:#FEE2E2;border-left:3px solid #C62828;border-radius:4px;font-size:11px;color:#991B1B;">⚠️ ' + _esc(m.erro_msg) + '</div>';
    } else if (m.status === 'pendente' && m.erro_msg) {
      // Pendente com motivo (ex.: 'Z-API não configurada')
      blocoErro = '<div style="margin-top:4px;padding:4px 8px;background:#FEF9C3;border-left:3px solid #CA8A04;border-radius:4px;font-size:11px;color:#854D0E;">ℹ️ ' + _esc(m.erro_msg) + '</div>';
    }

    return '<div style="background:white;border:1px solid #e5e7eb;border-radius:8px;padding:10px 12px;margin-bottom:8px;">' +
      '<div style="display:flex;justify-content:space-between;align-items:flex-start;gap:8px;margin-bottom:4px;">' +
        '<div style="font-size:12px;color:#475569;">' +
          '<span style="font-size:14px;">' + dir + '</span> <strong>' + dirLabel + '</strong>' +
          ' · <span style="font-family:monospace;">' + _esc(telFmt) + '</span>' +
        '</div>' +
        '<div style="display:flex;gap:6px;align-items:center;flex-shrink:0;">' +
          seloStatus +
          '<span style="font-size:10px;color:#94a3b8;">' + dataRel + '</span>' +
        '</div>' +
      '</div>' +
      '<div style="font-size:13px;color:#1e293b;line-height:1.4;white-space:pre-wrap;">' + _esc(msgFinal) + '</div>' +
      blocoErro +
    '</div>';
  }

  // Helper: data relativa em português
  function _dataRelativa(iso) {
    if (!iso) return '';
    try {
      var d = new Date(iso);
      var diffMs = Date.now() - d.getTime();
      var min = Math.floor(diffMs / 60000);
      if (min < 1) return 'agora';
      if (min < 60) return min + ' min atrás';
      var h = Math.floor(min / 60);
      if (h < 24) return h + 'h atrás';
      var dias = Math.floor(h / 24);
      if (dias === 1) return 'ontem';
      if (dias < 7) return dias + ' dias atrás';
      // Mais antigo: data curta
      return d.toLocaleDateString('pt-BR', { day: '2-digit', month: '2-digit', year: '2-digit' });
    } catch(_) { return iso; }
  }

  // Helper: formata 5516981427633 → +55 (16) 98142-7633
  function _formatarTelefoneWpp(tel) {
    var d = String(tel || '').replace(/\D/g, '');
    if (d.length === 13) {
      return '+' + d.slice(0,2) + ' (' + d.slice(2,4) + ') ' + d.slice(4,9) + '-' + d.slice(9);
    } else if (d.length === 12) {
      return '+' + d.slice(0,2) + ' (' + d.slice(2,4) + ') ' + d.slice(4,8) + '-' + d.slice(8);
    }
    return tel || '';
  }

  // Helper: escapar HTML (defensivo)
  function _esc(s) {
    return String(s == null ? '' : s).replace(/[&<>"']/g, function(c){
      return ({ '&':'&amp;', '<':'&lt;', '>':'&gt;', '"':'&quot;', "'":'&#39;' })[c];
    });
  }

  function enviarLinkUploadWhatsApp() {
    if (!projetoAtualId) return;
    const p = projetos.find(function(pp){ return pp.id === projetoAtualId; });
    if (!p) return;
    const cli = todosClientesUnificado(p.cliente_id) || {};
    const tel = (cli.telefone1 || '').replace(/\D/g,'');
    if (!tel) { toastError('Cliente sem telefone cadastrado.'); return; }

    // SEMANA 4.18: oferece duas opções: link curto OU checklist completo
    if (typeof enviarChecklistCliente === 'function') {
      // Reusa a função melhorada com checklist
      return enviarChecklistCliente();
    }

    // Fallback: link curto (versão antiga)
    const link = getClienteUrl() + '?upload=' + p.upload_token;
    const cleanTel = tel.length === 11 || tel.length === 10 ? '55' + tel : tel;
    const txt = 'Olá ' + (cli.nome ? cli.nome.split(' ')[0] : '') + '! Para o seu projeto de outorga "' + p.nome + '", anexe os documentos solicitados aqui (sem login): ' + link;
    window.open('https://wa.me/' + cleanTel + '?text=' + encodeURIComponent(txt), '_blank');
  }


