  // -------- helpers --------
  function getCriadoPor() {
    const sess = getSessao();
    return (sess && sess.nome) ? sess.nome : (sess && sess.email ? sess.email : 'admin');
  }


  // ============================================================
  // VOLTAR ETAPA
  // ============================================================
  // ============================================================
  // FASE 3B Item 2: Iniciar Renovação cria projeto na ETAPA 2
  // ============================================================
  // Iniciar Renovação: marca o cliente como "em renovação" e o coloca no
  // Kanban da Prospecção (coluna Aguardando), SEM tirá-lo de cliente ativo.
  // ============================================================
  async function abrirIniciarRenovacao(propId) {
    const p = propriedades.find(function(x){ return x.id === propId; });
    if (!p) { zAlert('Propriedade não encontrada.', 'erro'); return; }
    // BUG FIX 2026-05-27: usa acharPessoa() — renovação pode ser de qualquer fase
    const c = acharPessoa(p.cliente_id);
    if (!c) { zAlert('Cliente não encontrado.', 'erro'); return; }

    // Já está em renovação? Evita marcar de novo.
    if (c.em_renovacao) {
      if (await zConfirm('"' + c.nome + '" já está em processo de renovação (aba Prospecção, coluna Aguardando). Ir para a Prospecção?', { tipo:'info', btnOk:'Ir para Prospecção' })) {
        navTo('prospeccao', document.querySelector('.nav-item[data-page="prospeccao"]'));
      }
      return;
    }

    // Confirma
    if (!(await zConfirm('Iniciar renovação para "' + c.nome + ' — ' + p.nome + '"?\n\n' +
                 '• O cliente vai para a aba Prospecção, na coluna "Aguardando"\n' +
                 '• Lá você emite a proposta e aguarda a assinatura\n' +
                 '• Ele continua na sua carteira de clientes ativos normalmente\n\n' +
                 'Continuar?', { tipo:'info', btnOk:'Iniciar renovação' }))) {
      return;
    }

    try {
      // Marca o cliente: em_renovacao=true + entra no Kanban na coluna Aguardando.
      // status_funil continua 'cliente_ativo' — ele NÃO deixa de ser cliente.
      await api('clientes?id=eq.' + c.id, 'PATCH', {
        em_renovacao: true,
        status_lead: 'aguardando'
      }, 'return=minimal');

      // Marca os usos da propriedade (compatibilidade com a cor azul de renovação)
      try {
        await api('usos?propriedade_id=eq.' + propId, 'PATCH', { renovacao_em_andamento: true }, 'return=minimal');
      } catch(e) { /* ignora */ }

      // Registra no histórico de contato do cliente
      try {
        await api('historico_contatos', 'POST', {
          cliente_id: c.id,
          data: getDataHojeBR(),
          tipo: 'renovacao',
          descricao: 'Renovação de outorga iniciada (propriedade ' + (p.nome || '') + '). Cliente movido para a coluna Aguardando da Prospecção para emissão e assinatura da proposta.',
          criado_por: getCriadoPor()
        }, 'return=minimal');
      } catch(e) { /* ignora — histórico é secundário */ }

      await carregarDados();
      zAlert('Renovação iniciada! "' + c.nome + '" está agora na aba Prospecção, coluna "Aguardando".', 'sucesso');
      // Leva o usuário pra Prospecção
      navTo('prospeccao', document.querySelector('.nav-item[data-page="prospeccao"]'));
    } catch(e) {
      console.error('Erro abrirIniciarRenovacao:', e);
      zAlert('Erro ao iniciar renovação: ' + (e.message || e), 'erro');
    }
  }


  function abrirVoltarEtapa() {
    if (!projetoAtualId) return;
    const p = projetos.find(function(pp){ return pp.id === projetoAtualId; });
    if (!p) return;
    if (p.etapa_atual <= 1) {
      zAlert('O projeto já está na etapa inicial. Não há etapa para onde voltar.', 'aviso');
      return;
    }

    document.getElementById('voltar-etapa-titulo').textContent = '← Voltar etapa do projeto';
    document.getElementById('voltar-etapa-sub').textContent = 'Etapa atual: ' + ETAPAS_PROJETO[p.etapa_atual - 1].nome;

    // Popula select com etapas anteriores
    const sel = document.getElementById('voltar-etapa-destino');
    sel.innerHTML = '';
    for (let i = 1; i < p.etapa_atual; i++) {
      const o = document.createElement('option');
      o.value = String(i);
      o.textContent = 'Etapa ' + i + ': ' + ETAPAS_PROJETO[i - 1].nome;
      sel.appendChild(o);
    }
    // Default: etapa imediatamente anterior
    sel.value = String(p.etapa_atual - 1);

    document.getElementById('voltar-etapa-motivo').value = '';
    abrirModal('ov-voltar-etapa');
  }

  async function confirmarVoltarEtapa() {
    if (!projetoAtualId) return;
    const p = projetos.find(function(pp){ return pp.id === projetoAtualId; });
    if (!p) return;

    const destino = parseInt(document.getElementById('voltar-etapa-destino').value, 10);
    const motivo = document.getElementById('voltar-etapa-motivo').value.trim();

    if (!destino || destino < 1 || destino >= p.etapa_atual) {
      zAlert('Etapa de destino inválida.', 'erro');
      return;
    }
    if (!motivo) {
      zAlert('Motivo é obrigatório para voltar etapa (registrado no histórico).', 'aviso');
      return;
    }

    const btn = document.getElementById('btn-confirmar-voltar');
    btn.disabled = true; btn.textContent = '⏳ Voltando...';

    try {
      // Monta payload: etapa nova + zera datas das etapas que vão "deixar de existir"
      const payload = {
        etapa_atual: destino,
        atualizado_em: new Date().toISOString()
      };
      // Zera datas das etapas >= destino (etapa "destino" ainda não foi concluída, então sua data fica null;
      // se destino=2, zera data_protocolo, data_analise, data_publicacao; mantém data_vistoria)
      for (let i = destino; i <= 4; i++) {
        payload[ETAPAS_PROJETO[i - 1].col] = null;
      }
      // Se voltou de "concluído" (improvável aqui mas seguro), reativa
      if (p.status === 'concluido') payload.status = 'em_andamento';

      const r = await api('projetos?id=eq.' + projetoAtualId, 'PATCH', payload, 'return=minimal');
      if (!r || !r.ok) throw new Error('HTTP ' + (r ? r.status : '?'));

      // Histórico
      await api('projeto_historico', 'POST', {
        projeto_id: projetoAtualId,
        acao: 'etapa_revertida',
        de_valor: String(p.etapa_atual),
        para_valor: String(destino),
        observacao: motivo,
        criado_por: getCriadoPor()
      }, 'return=minimal');

      fecharModal('ov-voltar-etapa');
      await carregarDados();
      verProjeto(projetoAtualId);
    } catch(e) {
      console.error('Erro confirmarVoltarEtapa:', e);
      zAlert('Erro ao voltar etapa: ' + (e.message || e), 'erro');
    } finally {
      btn.disabled = false; btn.textContent = '← Confirmar';
    }
  }


  // ============================================================
  // DRAG-AND-DROP NO KANBAN
  // ============================================================
  let _dragProjetoId = null;
  let _dragFromEtapa = null;
  let _kanbanColsListenersOk = false;  // FASE 8: previne re-adicionar listeners nas colunas

  function setupDragKanban() {
    // SEMANA 4.19 FIX: scoped pra #page-em-projeto (antes pegava cards de outras páginas também)
    document.querySelectorAll('#page-em-projeto .projeto-card').forEach(function(card) {
      card.setAttribute('draggable', 'true');
      card.ondragstart = onDragStart;
      card.ondragend = onDragEnd;
    });

    document.querySelectorAll('#page-em-projeto .kanban-col-body').forEach(function(col) {
      col.ondragover = onDragOver;
      col.ondragleave = onDragLeave;
      col.ondrop = onDropCard;
    });
  }

  function onDragStart(e) {
    const pid = this.getAttribute('data-projeto-id');
    if (!pid) return;
    const p = projetos.find(function(pp){ return pp.id === pid; });
    if (!p || p.status !== 'em_andamento') {
      e.preventDefault();
      return;
    }
    _dragProjetoId = pid;
    _dragFromEtapa = p.etapa_atual;
    this.classList.add('dragging');
    try { e.dataTransfer.effectAllowed = 'move'; e.dataTransfer.setData('text/plain', pid); } catch(_) {}
  }

  function onDragEnd() {
    this.classList.remove('dragging');
    document.querySelectorAll('.kanban-col').forEach(function(c){ c.classList.remove('drag-over'); });
  }

  function onDragOver(e) {
    e.preventDefault();
    try { e.dataTransfer.dropEffect = 'move'; } catch(_) {}
    const col = this.closest('.kanban-col');
    if (col) col.classList.add('drag-over');
  }

  function onDragLeave(e) {
    const col = this.closest('.kanban-col');
    if (col) col.classList.remove('drag-over');
  }

  async function onDropCard(e) {
    e.preventDefault();
    const col = this.closest('.kanban-col');
    if (col) col.classList.remove('drag-over');

    const pid = _dragProjetoId;
    _dragProjetoId = null;
    if (!pid) return;

    const etapaDestino = parseInt(col.getAttribute('data-etapa'), 10);
    if (!etapaDestino || etapaDestino === _dragFromEtapa) return;

    // SEMANA 4.19: SÓ permite arrastar entre etapas ADJACENTES (+1 ou -1)
    const diff = etapaDestino - _dragFromEtapa;
    if (Math.abs(diff) > 1) {
      toastWarn('⚠ Só pode arrastar pra uma etapa por vez.\n\nDe ' + ETAPAS_PROJETO[_dragFromEtapa-1].nome + ' você pode ir só pra ' +
        (_dragFromEtapa > 1 ? ETAPAS_PROJETO[_dragFromEtapa-2].nome + ' ou ' : '') +
        (_dragFromEtapa < 4 ? ETAPAS_PROJETO[_dragFromEtapa].nome : '') + '.', 6000);
      renderKanban();
      setTimeout(setupDragKanban, 100);
      return;
    }

    const p = projetos.find(function(pp){ return pp.id === pid; });
    if (!p) return;

    // Valida checkboxes da etapa 1 antes de avançar via drag
    if (etapaDestino > _dragFromEtapa) {
      const check = verificarChecksEtapa(p, etapaDestino);
      if (!check.ok) {
        zAlert(check.motivo, 'aviso');
        renderKanban();
        setTimeout(setupDragKanban, 100);
        return;
      }
    }

    // Abre modal apropriado: avançar ou voltar
    projetoAtualId = pid;
    if (etapaDestino > _dragFromEtapa) {
      // Avançar 1 etapa só
      await avancarParaEtapa(pid, etapaDestino);
    } else {
      // Voltar — força usar modal pra exigir motivo
      verProjeto(pid);
      setTimeout(function() {
        abrirVoltarEtapa();
        const sel = document.getElementById('voltar-etapa-destino');
        if (sel) sel.value = String(etapaDestino);
      }, 300);
    }
  }

  async function avancarParaEtapa(pid, etapaDestino) {
    const p = projetos.find(function(pp){ return pp.id === pid; });
    if (!p) return;
    const hoje = getDataHojeBR();

    try {
      // Marca todas as etapas intermediárias (da atual até destino-1) com hoje
      const payload = { etapa_atual: etapaDestino, atualizado_em: new Date().toISOString() };
      for (let i = p.etapa_atual; i < etapaDestino; i++) {
        payload[ETAPAS_PROJETO[i - 1].col] = hoje;
      }
      const r = await api('projetos?id=eq.' + pid, 'PATCH', payload, 'return=minimal');
      if (!r || !r.ok) throw new Error('HTTP ' + (r ? r.status : '?'));

      // Histórico
      await api('projeto_historico', 'POST', {
        projeto_id: pid,
        acao: 'etapa_alterada',
        de_valor: String(p.etapa_atual),
        para_valor: String(etapaDestino),
        observacao: 'Avanço via drag-and-drop',
        criado_por: getCriadoPor()
      }, 'return=minimal');

      await carregarDados();
    } catch(e) {
      console.error('Erro avancarParaEtapa:', e);
      zAlert('Erro: ' + (e.message || e), 'erro');
      renderKanban();
      setTimeout(setupDragKanban, 100);
    }
  }


  // ============================================================
  // PROJETOS ATRASADOS (>30 dias na etapa atual)
  // ============================================================
  function calcularProjetosAtrasados() {
    const lista = [];
    const agora = Date.now();
    (typeof projetos !== 'undefined' ? projetos : []).forEach(function(p) {
      if (p.status !== 'em_andamento') return;
      // Data de referência: data da etapa anterior, ou data_inicio se etapa 1
      let dataRef = null;
      if (p.etapa_atual === 1) {
        dataRef = p.data_inicio || p.criado_em;
      } else {
        const colAnterior = ETAPAS_PROJETO[p.etapa_atual - 2].col;
        dataRef = p[colAnterior] || p.atualizado_em || p.criado_em;
      }
      if (!dataRef) return;
      const d = new Date(dataRef.length > 10 ? dataRef : dataRef + 'T12:00:00');
      if (isNaN(d.getTime())) return;
      const dias = Math.floor((agora - d.getTime()) / (1000*60*60*24));
      const etapaAtual = ETAPAS_PROJETO[p.etapa_atual - 1];
      const limiteEtapa = (etapaAtual && etapaAtual.limite_dias) ? etapaAtual.limite_dias : LIMITE_ATRASADO_DIAS;
      if (dias > limiteEtapa) {
        lista.push({ projeto: p, dias: dias });
      }
    });
    return lista;
  }

  function renderCardAtrasadosDashboard() {
    const card = document.getElementById('card-projetos-atrasados');
    const valEl = document.getElementById('m-proj-atrasados');
    if (!card || !valEl) return;
    const atrasados = calcularProjetosAtrasados();
    if (atrasados.length === 0) {
      card.style.display = 'none';
    } else {
      card.style.display = '';
      valEl.textContent = atrasados.length;
    }
  }

  function renderBannerAtrasados() {
    const banner = document.getElementById('banner-atrasados');
    if (!banner) return;
    const atrasados = calcularProjetosAtrasados();
    if (atrasados.length === 0) {
      banner.style.display = 'none';
      return;
    }
    banner.style.display = '';
    // Ordena por dias desc (mais antigos primeiro)
    atrasados.sort(function(a, b){ return b.dias - a.dias; });

    let html = '<div class="banner-atrasados">';
    html += '<div class="banner-atrasados-titulo">⚠ ' + atrasados.length + ' projeto(s) parado(s) além do prazo</div>';
    html += '<div class="banner-atrasados-lista">';
    atrasados.slice(0, 10).forEach(function(it) {
      const p = it.projeto;
      const cli = todosClientesUnificado(p.cliente_id) || {};
      const prop = (typeof propriedades !== 'undefined' ? propriedades : []).find(function(pp){ return pp.id === p.propriedade_id; }) || {};
      html += '<div class="banner-atrasados-item" onclick="verProjeto(\'' + p.id + '\')">';
      html += '• <strong>' + (cli.nome || '(?)') + '</strong> — ' + (prop.nome || '(?)') + ' — ' + ETAPAS_PROJETO[p.etapa_atual - 1].nome + ' (' + it.dias + ' dias parado)';
      html += '</div>';
    });
    if (atrasados.length > 10) {
      html += '<div style="font-size:11px;color:#E65100;margin-top:6px;font-style:italic;">+ ' + (atrasados.length - 10) + ' projeto(s) atrasado(s) (filtra a lista pra ver tudo)</div>';
    }
    html += '</div></div>';
    banner.innerHTML = html;
  }


  // ============================================================
  // ONDA 3 BUG#15: REVISAR pendentes — visibilidade e ação
  // ============================================================
  // Lista propriedades cujo nome começa com "REVISAR" (placeholders da importação)
  function listarPropsRevisar() {
    return (typeof propriedades !== 'undefined' ? propriedades : [])
      .filter(function(p){ return p.nome && p.nome.indexOf('REVISAR') === 0; });
  }

  // Atualiza o card "Propriedades a revisar" no dashboard
  // ONDA 111 (LGPD): card no dashboard mostrando solicitações pendentes de exclusão.
  // Só admin vê (hunter não cuida disso).
  async function renderCardLgpdPendentes() {
    if (!souAdmin()) return;
    const cont = document.getElementById('dash-cards-admin') || document.getElementById('dash-grid');
    if (!cont) return;

    let pendentes = [];
    try {
      pendentes = await api('consentimentos_lgpd?status=eq.pendente&tipo=eq.solicitacao_exclusao&select=id,cliente_id,observacao,criado_em&order=criado_em.asc');
    } catch(e) { console.warn('Erro carregando LGPD:', e); }

    // Remove card anterior se existir (re-render)
    const anterior = document.getElementById('card-lgpd-pendentes');
    if (anterior) anterior.remove();

    if (!pendentes || !pendentes.length) return;

    // Monta o card
    const card = document.createElement('div');
    card.id = 'card-lgpd-pendentes';
    card.style.cssText = 'background:#FEF2F2;border:1px solid #FCA5A5;border-radius:10px;padding:14px 16px;margin-bottom:14px;cursor:pointer;';
    card.onclick = function(){ abrirListaLgpdPendentes(); };
    card.innerHTML =
      '<div style="display:flex;align-items:center;gap:10px;">'
      + '<span style="font-size:22px;">🔒</span>'
      + '<div style="flex:1;">'
      + '<div style="font-size:14px;font-weight:700;color:#991B1B;">'
      + pendentes.length + ' solicitação(ões) LGPD pendente(s)'
      + '</div>'
      + '<div style="font-size:12px;color:#7F1D1D;">Cliente pediu exclusão de dados — analise e responda em até 15 dias úteis</div>'
      + '</div>'
      + '<span style="font-size:11px;font-weight:700;color:#991B1B;">VER →</span>'
      + '</div>';

    cont.insertBefore(card, cont.firstChild);
  }

  // Abre listagem das solicitações LGPD pendentes pra admin processar
  async function abrirListaLgpdPendentes() {
    let pendentes = [];
    try {
      pendentes = await api('consentimentos_lgpd?status=eq.pendente&tipo=eq.solicitacao_exclusao&select=*&order=criado_em.asc');
    } catch(e) {
      zAlert('Erro carregando solicitações: ' + (e.message || ''), 'erro');
      return;
    }
    if (!pendentes || !pendentes.length) {
      zAlert('Nenhuma solicitação LGPD pendente.', 'info');
      return;
    }

    const linhas = pendentes.map(function(p){
      const cli = (typeof leads !== 'undefined' ? leads : []).find(function(c){ return c.id === p.cliente_id; })
                || (typeof clientes !== 'undefined' ? clientes : []).find(function(c){ return c.id === p.cliente_id; })
                || (typeof clientesEmProjeto !== 'undefined' ? clientesEmProjeto : []).find(function(c){ return c.id === p.cliente_id; });
      const nome = cli ? (cli.nome || '(sem nome)') : '(cliente não localizado)';
      const data = p.criado_em ? new Date(p.criado_em).toLocaleString('pt-BR') : '—';
      const obs = (p.observacao || '').replace(/</g,'&lt;');
      return '<div style="border:1px solid #FCA5A5;background:#FEF2F2;border-radius:8px;padding:12px;margin-bottom:8px;">'
        + '<div style="font-weight:700;color:#991B1B;font-size:13px;margin-bottom:4px;">' + escapeHtml(nome) + '</div>'
        + '<div style="font-size:11px;color:#7F1D1D;margin-bottom:6px;">Solicitado em ' + data + '</div>'
        + '<div style="font-size:12px;color:#374151;margin-bottom:10px;">' + obs + '</div>'
        + '<div style="display:flex;gap:6px;flex-wrap:wrap;">'
        + '<button class="btn btn-sm" style="background:#FEE2E2;color:#991B1B;border:1px solid #FCA5A5;" onclick="processarLgpd(\'' + p.id + '\',\'processado\')">✓ Processado (exclui ou anonimiza)</button>'
        + '<button class="btn btn-sm" style="background:#F3F4F6;color:#374151;border:1px solid #D1D5DB;" onclick="processarLgpd(\'' + p.id + '\',\'rejeitado\')">✗ Rejeitar (justificar)</button>'
        + '</div></div>';
    }).join('');

    // Cria modal customizado (zAlert não suporta HTML)
    let mod = document.getElementById('ov-lgpd-listagem');
    if (mod) mod.remove();
    mod = document.createElement('div');
    mod.id = 'ov-lgpd-listagem';
    mod.className = 'overlay';
    mod.style.cssText = 'position:fixed;inset:0;background:rgba(0,0,0,0.6);display:flex;align-items:center;justify-content:center;z-index:500;padding:14px;';
    mod.onclick = function(e){ if (e.target === mod) mod.remove(); };
    mod.innerHTML =
      '<div class="modal" style="background:white;max-width:600px;width:100%;border-radius:12px;padding:20px;max-height:85vh;overflow-y:auto;">'
      + '<div style="display:flex;justify-content:space-between;align-items:center;margin-bottom:14px;">'
      + '<div style="font-size:16px;font-weight:700;color:#0a2744;">🔒 Solicitações LGPD pendentes</div>'
      + '<button onclick="document.getElementById(\'ov-lgpd-listagem\').remove()" style="background:none;border:none;font-size:20px;cursor:pointer;color:#64748b;">×</button>'
      + '</div>'
      + linhas
      + '<div style="background:#F3F4F6;border-radius:6px;padding:10px;margin-top:10px;font-size:11px;color:#4B5563;">'
      + '<strong>Lembre-se:</strong> a LGPD obriga responder em até <strong>15 dias úteis</strong>. '
      + 'Antes de excluir, considere contratos em andamento e obrigações legais de retenção. '
      + 'Se manter por dever legal, registre como "Rejeitado" com a justificativa. '
      + 'Se anonimizar, marque "Processado".'
      + '</div>'
      + '</div>';
    document.body.appendChild(mod);
  }

  async function processarLgpd(idSolic, novoStatus) {
    if (novoStatus !== 'processado' && novoStatus !== 'rejeitado') return;
    const sess = getSessao();
    const quem = (sess && sess.nome) || (sess && sess.email) || 'admin';

    let justificativa = '';
    if (novoStatus === 'rejeitado') {
      justificativa = window.prompt(
        'Justificativa da rejeição (obrigatório):\n\n' +
        'Ex: "Contrato em andamento, exclusão prevista para 2031"\n' +
        '    "Anonimização realizada - histórico mantido sem dados pessoais"\n' +
        '    "Retenção fiscal obrigatória até 2030"'
      );
      if (!justificativa) return;
    } else {
      justificativa = window.prompt(
        'Descreva como foi processado (obrigatório):\n\n' +
        'Ex: "Dados excluídos integralmente em 22/05/2026"\n' +
        '    "Anonimização: CPF/nome substituídos por hash; processo mantido pra histórico legal"'
      );
      if (!justificativa) return;
    }

    try {
      await api('consentimentos_lgpd?id=eq.' + idSolic, 'PATCH', {
        status: novoStatus,
        processado_por: quem,
        processado_em: new Date().toISOString(),
        observacao: (justificativa).substring(0, 1000)
      }, 'return=minimal');

      toastSuccess(novoStatus === 'processado' ? '✓ Solicitação marcada como processada' : '✓ Solicitação rejeitada', 3000);
      const mod = document.getElementById('ov-lgpd-listagem');
      if (mod) mod.remove();
      renderCardLgpdPendentes();  // atualiza card no dashboard
    } catch(e) {
      console.error('Erro processando LGPD:', e);
      toastError('Erro ao processar: ' + (e.message || ''));
    }
  }

  // Expor pro onclick do HTML
  window.processarLgpd = processarLgpd;
  window.abrirListaLgpdPendentes = abrirListaLgpdPendentes;

