  // ============================================================
  // EXCLUIR PROPOSTA
  // ============================================================
  async function excluirPropostaConfirm() {
    const propId = document.getElementById('prop-id').value;
    if (!propId) return;
    const p = propostas.find(function(x){ return x.id === propId; });
    if (!p) return;
    if (!(await zConfirm('Excluir a proposta Nº ' + p.numero + '?\n\nO PDF no Storage NÃO será removido automaticamente.\nO número (' + p.numero + ') não será reutilizado.\n\nEsta ação não pode ser desfeita.', { tipo:'erro', btnOk:'Excluir proposta' }))) return;

    try {
      // Deleta serviços primeiro (FK CASCADE faria, mas explicit é seguro)
      await api('proposta_servicos?proposta_id=eq.' + propId, 'DELETE', null, 'return=minimal');
      await api('propostas?id=eq.' + propId, 'DELETE', null, 'return=minimal');
      await carregarPropostas();
      fecharModal('ov-gerar-proposta');
      if (leadAtualId) renderPropostasDoLead(leadAtualId);
      zAlert('✓ Proposta excluída.', 'aviso');
    } catch(e) {
      zAlert('Erro ao excluir: ' + (e.message || e), 'erro');
    }
  }


  // ============================================================
  // INICIALIZAÇÃO: verifica login antes de carregar tudo
  // ============================================================

  // FASE 3B Item 3: força UPPERCASE em todos os campos .upper (input + textarea)
  // Listener global no document (event delegation). Pega inclusive inputs em modais criados após DOMContentLoaded.
  function instalarListenerUpper() {
    document.addEventListener('input', function(e) {
      const el = e.target;
      if (!el || !el.classList) return;
      if (!el.classList.contains('upper')) return;
      // Não transformar inputs do tipo email, url, password
      if (el.type === 'email' || el.type === 'url' || el.type === 'password') return;
      const v = el.value;
      if (!v) return;
      const up = v.toUpperCase();
      if (v !== up) {
        // Preserva posição do cursor
        const start = el.selectionStart;
        const end = el.selectionEnd;
        el.value = up;
        try { el.setSelectionRange(start, end); } catch(_) {}
      }
    }, true);
  }
  instalarListenerUpper();

  // SEMANA 4.13: Alterna tema dark/light
  function toggleTema() {
    const body = document.body;
    const novoTema = body.classList.toggle('theme-dark') ? 'dark' : 'light';
    try { localStorage.setItem('z_tema', novoTema); } catch(e){}
    const btn = document.getElementById('btn-tema');
    if (btn) btn.textContent = novoTema === 'dark' ? '☀️' : '🌙';
  }

  // Aplica tema salvo no boot
  function aplicarTemaSalvo() {
    try {
      const t = localStorage.getItem('z_tema');
      if (t === 'dark') {
        document.body.classList.add('theme-dark');
        const btn = document.getElementById('btn-tema');
        if (btn) btn.textContent = '☀️';
      }
    } catch(e){}
  }
  aplicarTemaSalvo();

  // SEMANA 4.13: Auto-save de drafts
  // Salva valores de inputs/textareas dentro de um modal a cada mudança no localStorage.
  // Restaura ao reabrir o modal, oferece "Descartar" se houver draft pendente.
  const _DRAFT_PREFIX = 'z_draft_';
  const _DRAFT_TTL = 24 * 60 * 60 * 1000;   // 24h

  function _salvarDraft(modalId) {
    const modal = document.getElementById(modalId);
    if (!modal) return;
    const dados = {};
    modal.querySelectorAll('input, textarea, select').forEach(function(el){
      if (!el.id) return;
      if (el.type === 'file' || el.type === 'password' || el.type === 'hidden') return;
      if (el.type === 'checkbox' || el.type === 'radio') dados[el.id] = el.checked;
      else dados[el.id] = el.value;
    });
    if (Object.keys(dados).length === 0) return;
    try {
      localStorage.setItem(_DRAFT_PREFIX + modalId, JSON.stringify({
        ts: Date.now(),
        dados: dados
      }));
    } catch(e) { console.warn('Draft:', e); }
  }

  function _carregarDraft(modalId) {
    try {
      const raw = localStorage.getItem(_DRAFT_PREFIX + modalId);
      if (!raw) return null;
      const obj = JSON.parse(raw);
      if (!obj || !obj.dados) return null;
      // Expira após 24h
      if (Date.now() - (obj.ts || 0) > _DRAFT_TTL) {
        localStorage.removeItem(_DRAFT_PREFIX + modalId);
        return null;
      }
      return obj.dados;
    } catch(e) { return null; }
  }

  function _limparDraft(modalId) {
    try { localStorage.removeItem(_DRAFT_PREFIX + modalId); } catch(e) {}
  }

  // Ativa auto-save num modal específico
  // - draftAtivo: array de IDs de modais que devem auto-salvar
  // - chame _instalarAutosaveDraft após abrir o modal
  function _instalarAutosaveDraft(modalId) {
    const modal = document.getElementById(modalId);
    if (!modal) return;
    // Restaura draft (se houver)
    const draft = _carregarDraft(modalId);
    if (draft) {
      const algumPreenchido = Object.values(draft).some(function(v){ return v && v !== false; });
      if (algumPreenchido) {
        showToast('📝 Rascunho recuperado de antes', 'info', 4000, {
          label: 'Descartar',
          fn: function(){
            _limparDraft(modalId);
            // Limpa os campos
            modal.querySelectorAll('input, textarea, select').forEach(function(el){
              if (el.type === 'checkbox' || el.type === 'radio') el.checked = false;
              else if (el.type !== 'file' && el.type !== 'hidden') el.value = '';
            });
          }
        });
        Object.entries(draft).forEach(function(pair){
          const el = document.getElementById(pair[0]);
          if (!el) return;
          if (el.type === 'checkbox' || el.type === 'radio') el.checked = !!pair[1];
          else if (el.type !== 'file' && el.type !== 'hidden') el.value = pair[1] || '';
        });
      }
    }
    // Instala listener de mudança (debounce 500ms)
    let timerId = null;
    modal.querySelectorAll('input, textarea, select').forEach(function(el){
      if (el._draftListener) return;
      el._draftListener = true;
      el.addEventListener('input', function(){
        clearTimeout(timerId);
        timerId = setTimeout(function(){ _salvarDraft(modalId); }, 500);
      });
      el.addEventListener('change', function(){
        clearTimeout(timerId);
        timerId = setTimeout(function(){ _salvarDraft(modalId); }, 500);
      });
    });
  }


  // ESC → fecha modal aberto
  // / ou Ctrl+K → foca busca
  // Ctrl+S → salva form aberto (procura primeiro botão de salvar visível)
  // N → novo lead (se estiver na tela de prospecção e nenhum modal aberto)
  function instalarAtalhosTeclado() {
    document.addEventListener('keydown', function(e){
      // Não interfere quando user está digitando em input/textarea
      const tag = (e.target.tagName || '').toUpperCase();
      const tipando = tag === 'INPUT' || tag === 'TEXTAREA' || tag === 'SELECT' || e.target.isContentEditable;

      // ESC fecha modal aberto (mesmo se estiver tipando)
      if (e.key === 'Escape') {
        const overlay = Array.from(document.querySelectorAll('.overlay')).reverse().find(function(o){
          return o.style.display === 'flex' || (window.getComputedStyle(o).display !== 'none' && o.style.display !== 'none');
        });
        if (overlay) {
          e.preventDefault();
          fecharModal(overlay.id);
          return;
        }
      }

      // Não tipa atalhos quando está digitando
      if (tipando) {
        // Exceção: Ctrl+S sempre funciona pra salvar
        if (e.key === 's' && (e.ctrlKey || e.metaKey)) {
          e.preventDefault();
          _atalhoSalvar();
        }
        return;
      }

      // /  → foca busca
      if (e.key === '/' && !e.ctrlKey && !e.metaKey) {
        const busca = document.querySelector('input[type="search"], input[placeholder*="uscar"]');
        if (busca) { e.preventDefault(); busca.focus(); busca.select(); }
        return;
      }
      // Ctrl+K → foca busca
      if (e.key === 'k' && (e.ctrlKey || e.metaKey)) {
        const busca = document.querySelector('input[type="search"], input[placeholder*="uscar"]');
        if (busca) { e.preventDefault(); busca.focus(); busca.select(); }
        return;
      }
      // Ctrl+S
      if (e.key === 's' && (e.ctrlKey || e.metaKey)) {
        e.preventDefault();
        _atalhoSalvar();
        return;
      }
      // N → novo lead (se na tela de prospecção)
      if (e.key === 'n' || e.key === 'N') {
        const tela = document.querySelector('.page[style*="display: block"]');
        if (tela && tela.id === 'page-leads') {
          const btnNovo = document.getElementById('btn-novo-lead-prospeccao') || document.querySelector('[onclick*="abrirCadastroLead"]');
          if (btnNovo) { e.preventDefault(); btnNovo.click(); }
        }
        return;
      }
    });
  }

  function _atalhoSalvar() {
    // Encontra modal aberto e clica no botão de "salvar" / primário (azul/verde)
    const overlay = Array.from(document.querySelectorAll('.overlay')).reverse().find(function(o){
      return o.style.display === 'flex' || (window.getComputedStyle(o).display !== 'none' && o.style.display !== 'none');
    });
    if (!overlay) return;
    // Procura primeiro botão que parece "salvar/confirmar/criar"
    const btns = overlay.querySelectorAll('button');
    for (let i = 0; i < btns.length; i++) {
      const txt = (btns[i].textContent || '').toLowerCase();
      if (txt.indexOf('salvar') >= 0 || txt.indexOf('confirm') >= 0 ||
          txt.indexOf('criar') >= 0 || txt.indexOf('avançar') >= 0 ||
          txt.indexOf('publicar') >= 0) {
        if (!btns[i].disabled) { btns[i].click(); return; }
      }
    }
  }

  instalarAtalhosTeclado();

  (async function inicializar(){
    const logado = await verificarLogin();
    if (!logado) {
      // Se não está logado, NÃO carrega os dados ainda. O login fará isso.
      return;
    }
    await carregarDados();
    carregarTodasCidades();
    setTimeout(carregarConfigEmpresa, 500);
    setTimeout(inicializarDragDropMenu, 100);
  })();

  // SEMANA 3.4: Registra Service Worker pra PWA
  // POST-ONDA 4 (Bloco 4): auto-update — detecta nova versão e atualiza sem
  // o usuário precisar limpar cache na mão.
  // ONDA C.3: detector de offline (independe de service worker)
  window.addEventListener('load', function() {
    _ativarDetectorOffline();
  });

  if ('serviceWorker' in navigator) {
    window.addEventListener('load', function() {
      navigator.serviceWorker.register('/service-worker.js')
        .then(function(reg) {
          console.log('[PWA] Service Worker registrado', reg.scope);
          // Verifica se há atualização toda vez que a página carrega
          reg.update();
          // Quando uma nova versão do SW é encontrada e instalada...
          reg.addEventListener('updatefound', function() {
            const novoSW = reg.installing;
            if (!novoSW) return;
            novoSW.addEventListener('statechange', function() {
              // Nova versão instalada E já existe um SW controlando (não é 1º load)
              if (novoSW.state === 'installed' && navigator.serviceWorker.controller) {
                console.log('[PWA] Nova versão disponível — ativando...');
                // Pede pro novo SW assumir o controle imediatamente
                if (novoSW.postMessage) {
                  try { novoSW.postMessage({ type: 'SKIP_WAITING' }); } catch(e) {}
                }
              }
            });
          });
        })
        .catch(function(err) { console.warn('[PWA] Falha ao registrar SW:', err); });

      // Quando o SW que controla a página muda, recarrega 1x pra pegar a versão nova
      let _swRecarregou = false;
      navigator.serviceWorker.addEventListener('controllerchange', function() {
        if (_swRecarregou) return;
        _swRecarregou = true;
        console.log('[PWA] Service Worker atualizado — recarregando página');
        window.location.reload();
      });
    });
  }



/* ============================================================
   AGENTE DE PROSPECÇÃO — UI Etapa 2/3 (v245)
   Botão "🤖 Prospectar" no lead + Fila de rascunhos.
   NOVO: "Aprovar e ENVIAR" dispara de verdade (Resend + Z-API)
   via edge function agente-disparar, com confirmação antes.
   Módulo autossuficiente (lê URL/chave/sessão do localStorage).
   ============================================================ */
window.AgenteZello = (function(){
  var URL_BASE = localStorage.getItem('z_url') || 'https://evxolmfwblxtmudksmnt.supabase.co';
  var CHAVE = localStorage.getItem('z_key') || 'eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyJpc3MiOiJzdXBhYmFzZSIsInJlZiI6ImV2eG9sbWZ3Ymx4dG11ZGtzbW50Iiwicm9sZSI6ImFub24iLCJpYXQiOjE3Nzc3MzQxNTgsImV4cCI6MjA5MzMxMDE1OH0.v7uvLbz6NJoa4K0_KT9bKm5-M4mVAZ__77Tbqfef9fA';
  var FN_AGENTE = URL_BASE + '/functions/v1/agente-prospeccao';
  var FN_DISPARO = URL_BASE + '/functions/v1/agente-disparar';
  var API = URL_BASE + '/rest/v1';

  function _alert(msg, tipo){
    if (typeof window.zAlert === 'function') window.zAlert(msg, tipo);
    else alert(msg);
  }

  async function _confirm(msg, opts){
    if (typeof window.zConfirm === 'function') return await window.zConfirm(msg, opts || {});
    return window.confirm(msg);
  }

  function _sessao(){
    try {
      var raw = localStorage.getItem('z_admin_session');
      if (!raw) return null;
      var s = JSON.parse(raw);
      if (!s.expires || Date.now() > s.expires) return null;
      return s;
    } catch(e){ return null; }
  }

  function _h(extra){
    var h = {
      'Authorization': 'Bearer ' + CHAVE,
      'apikey': CHAVE,
      'Content-Type': 'application/json'
    };
    if (extra) for (var k in extra) h[k] = extra[k];
    return h;
  }

  /* ---------- Botão 🤖 no modal do lead ---------- */
  function botaoLead(l){
    try {
      var anc = document.getElementById('ver-lead-sticky') || document.getElementById('ver-lead-titulo');
      if (!anc) return;
      var old = document.getElementById('agente-btn-prospectar');
      if (old) old.remove();
      var btn = document.createElement('button');
      btn.id = 'agente-btn-prospectar';
      btn.type = 'button';
      btn.textContent = '🤖 Prospectar';
      btn.style.cssText = 'margin:6px 0;padding:8px 14px;border:none;border-radius:8px;background:#0EA5E9;color:#fff;font-weight:600;cursor:pointer;font-size:13px;';
      btn.onclick = function(){ prospectar(l); };
      anc.parentNode.insertBefore(btn, anc.nextSibling);
    } catch(e){ console.warn('[agente] botaoLead', e); }
  }

  async function prospectar(l){
    var sess = _sessao();
    if (!sess || !sess.id || !sess.sessao_hash){
      _alert('Sessão expirada. Faça login novamente.', 'erro');
      return;
    }
    var btn = document.getElementById('agente-btn-prospectar');
    if (btn){ btn.disabled = true; btn.textContent = '🤖 Trabalhando…'; }
    try {
      var r = await fetch(FN_AGENTE, {
        method: 'POST',
        headers: _h(),
        body: JSON.stringify({
          usuario_id: sess.id,
          sessao_hash: sess.sessao_hash,
          cliente_id: l.id
        })
      });
      var j = await r.json();
      if (!r.ok){
        _alert('Agente falhou: ' + (j.detalhe || j.error || ('HTTP ' + r.status)), 'erro');
        return;
      }
      if (j.resultado === 'sem_contato'){
        _alert('Sem telefone/e-mail mesmo após enriquecer.\nLead marcado como perdido pelo agente.', 'aviso');
      } else if (j.resultado === 'cortado_por_teto'){
        _alert('⛔ ' + (j.detalhe || 'Teto de gasto do dia atingido.'), 'aviso');
      } else if (j.resultado === 'rascunhos_gerados'){
        _alert('✅ ' + j.rascunhos_criados + ' rascunho(s) criado(s) na fila!\nCusto desta rodada: R$ ' + Number(j.custo_claude_brl || 0).toFixed(3), 'sucesso');
      } else if (j.resultado === 'ja_tem_rascunho'){
        _alert('Este lead já tem rascunho aguardando revisão na fila. 😉', 'info');
      } else if (j.resultado === 'erro_enriquecimento'){
        _alert('⚠️ Enriquecimento indisponível agora:\n' + (j.detalhe || '') + '\n\nO lead NÃO foi descartado — tente de novo mais tarde.', 'aviso');
      } else {
        _alert('Resultado: ' + (j.resultado || '?') + '\n' + (j.detalhe || ''), 'info');
      }
      atualizarBadge();
    } catch(e){
      _alert('Erro de rede ao chamar o agente: ' + e.message, 'erro');
    } finally {
      if (btn){ btn.disabled = false; btn.textContent = '🤖 Prospectar'; }
    }
  }

  /* ---------- Botão flutuante + badge de pendentes ---------- */
  function montarBotaoFlutuante(){
    if (document.getElementById('agente-fab')) return;
    if (!_sessao()) return;
    var fab = document.createElement('button');
    fab.id = 'agente-fab';
    fab.type = 'button';
    fab.innerHTML = '🤖 <span id="agente-fab-badge" style="display:none;background:#EF4444;color:#fff;border-radius:10px;padding:1px 7px;font-size:11px;margin-left:4px;"></span>';
    fab.title = 'Fila do agente de prospecção';
    fab.style.cssText = 'position:fixed;bottom:18px;left:18px;z-index:9000;padding:10px 16px;border:none;border-radius:24px;background:#0F172A;color:#fff;font-size:15px;cursor:pointer;box-shadow:0 4px 14px rgba(0,0,0,.25);';
    fab.onclick = abrirFila;
    document.body.appendChild(fab);
    atualizarBadge();
    setInterval(atualizarBadge, 120000);
  }

  async function atualizarBadge(){
    try {
      var r = await fetch(API + '/agente_rascunhos?status=eq.aguardando_revisao&select=id', {
        method: 'HEAD',
        headers: _h({ 'Prefer': 'count=exact' })
      });
      var total = 0;
      var cr = r.headers.get('content-range');
      if (cr && cr.indexOf('/') >= 0) total = parseInt(cr.split('/')[1], 10) || 0;
      var b = document.getElementById('agente-fab-badge');
      if (b){
        b.textContent = total;
        b.style.display = total > 0 ? '' : 'none';
      }
    } catch(e){ /* silencioso */ }
  }

  /* ---------- Fila de rascunhos (modal) ---------- */
  async function abrirFila(){
    var overlay = document.getElementById('agente-fila-overlay');
    if (overlay) overlay.remove();

    overlay = document.createElement('div');
    overlay.id = 'agente-fila-overlay';
    overlay.style.cssText = 'position:fixed;inset:0;background:rgba(15,23,42,.55);z-index:9500;display:flex;align-items:center;justify-content:center;padding:16px;';
    overlay.innerHTML =
      '<div style="background:#fff;border-radius:14px;max-width:720px;width:100%;max-height:88vh;display:flex;flex-direction:column;overflow:hidden;">' +
        '<div style="padding:14px 18px;border-bottom:1px solid #E2E8F0;display:flex;justify-content:space-between;align-items:center;">' +
          '<strong style="font-size:16px;">🤖 Fila do agente — aguardando revisão</strong>' +
          '<button type="button" onclick="document.getElementById(\'agente-fila-overlay\').remove()" style="border:none;background:none;font-size:20px;cursor:pointer;">✕</button>' +
        '</div>' +
        '<div id="agente-fila-lista" style="overflow-y:auto;padding:14px 18px;flex:1;">Carregando…</div>' +
        '<div style="padding:12px 18px;border-top:1px solid #E2E8F0;display:flex;gap:10px;justify-content:flex-end;align-items:center;">' +
          '<span id="agente-fila-status" style="margin-right:auto;font-size:12px;color:#64748B;"></span>' +
          '<button type="button" onclick="AgenteZello.descartarSelecionados()" style="padding:9px 16px;border:1px solid #EF4444;background:#fff;color:#EF4444;border-radius:8px;font-weight:600;cursor:pointer;">🗑 Descartar</button>' +
          '<button type="button" id="agente-btn-enviar" onclick="AgenteZello.aprovarEnviarSelecionados()" style="padding:9px 16px;border:none;background:#16A34A;color:#fff;border-radius:8px;font-weight:600;cursor:pointer;">🚀 Aprovar e ENVIAR</button>' +
        '</div>' +
      '</div>';
    document.body.appendChild(overlay);

    try {
      var r = await fetch(API + '/agente_rascunhos?status=eq.aguardando_revisao&select=id,tipo,assunto,corpo,destino,criado_em,clientes(nome)&order=criado_em.asc', { headers: _h() });
      var itens = await r.json();
      var box = document.getElementById('agente-fila-lista');
      if (!Array.isArray(itens) || !itens.length){
        box.innerHTML = '<div style="text-align:center;color:#64748B;padding:30px 0;">Nenhum rascunho pendente. 🎉</div>';
        return;
      }
      box.innerHTML = itens.map(function(it){
        var icone = it.tipo === 'email' ? '✉️' : '💬';
        var nomeCli = (it.clientes && it.clientes.nome) || '(lead)';
        var assuntoHtml = it.tipo === 'email'
          ? '<div style="font-size:13px;margin-bottom:6px;"><b>Assunto:</b> ' + (it.assunto || '') + '</div>'
          : '';
        return (
          '<div style="border:1px solid #E2E8F0;border-radius:10px;padding:12px;margin-bottom:12px;">' +
            '<div style="display:flex;align-items:center;gap:10px;margin-bottom:8px;">' +
              '<input type="checkbox" class="agente-check" value="' + it.id + '" checked style="width:17px;height:17px;">' +
              '<strong>' + icone + ' ' + nomeCli + '</strong>' +
              '<span style="color:#64748B;font-size:12px;">→ ' + (it.destino || '') + '</span>' +
            '</div>' +
            assuntoHtml +
            '<textarea class="agente-corpo" data-id="' + it.id + '" style="width:100%;min-height:84px;border:1px solid #CBD5E1;border-radius:8px;padding:9px;font-size:13px;font-family:inherit;box-sizing:border-box;">' + (it.corpo || '') + '</textarea>' +
          '</div>'
        );
      }).join('');
    } catch(e){
      var box2 = document.getElementById('agente-fila-lista');
      if (box2) box2.innerHTML = '<div style="color:#EF4444;">Erro ao carregar fila: ' + e.message + '</div>';
    }
  }

  function _selecionados(){
    return Array.prototype.slice.call(document.querySelectorAll('.agente-check:checked')).map(function(c){ return c.value; });
  }

  async function _patchLote(ids, montarPatch){
    for (var i = 0; i < ids.length; i++){
      var id = ids[i];
      var ta = document.querySelector('.agente-corpo[data-id="' + id + '"]');
      var patch = montarPatch(ta ? ta.value : null);
      await fetch(API + '/agente_rascunhos?id=eq.' + id + '&select=id', {
        method: 'PATCH',
        headers: _h({ 'Prefer': 'return=representation' }),
        body: JSON.stringify(patch)
      });
    }
  }

  /* ---------- ETAPA 2: aprovar e DISPARAR de verdade ---------- */
  async function aprovarEnviarSelecionados(){
    var ids = _selecionados();
    if (!ids.length){ _alert('Nenhum rascunho selecionado.', 'aviso'); return; }

    var sess = _sessao();
    if (!sess || !sess.id || !sess.sessao_hash){
      _alert('Sessão expirada. Faça login novamente.', 'erro');
      return;
    }

    var conf = await _confirm(
      '🚀 Enviar ' + ids.length + ' mensagem(ns) AGORA?\n\n' +
      'E-mails saem pelo Resend e WhatsApp pela Z-API.\n' +
      'Esta ação não pode ser desfeita.',
      { btnOk: 'Sim, enviar' }
    );
    if (!conf) return;

    var btn = document.getElementById('agente-btn-enviar');
    if (btn){ btn.disabled = true; btn.textContent = '🚀 Enviando…'; }
    var st = document.getElementById('agente-fila-status');
    if (st) st.textContent = 'Salvando edições e disparando…';

    try {
      /* 1. Salva o texto atual (com tuas edições) e marca aprovado */
      await _patchLote(ids, function(corpoAtual){
        var p = { status: 'aprovado', revisado_em: new Date().toISOString() };
        if (corpoAtual != null) p.corpo = corpoAtual;
        return p;
      });

      /* 2. Dispara de verdade */
      var r = await fetch(FN_DISPARO, {
        method: 'POST',
        headers: _h(),
        body: JSON.stringify({
          usuario_id: sess.id,
          sessao_hash: sess.sessao_hash,
          rascunho_ids: ids
        })
      });
      var j = await r.json();
      if (!r.ok){
        _alert('Falha no disparo: ' + (j.error || ('HTTP ' + r.status)), 'erro');
        return;
      }

      var msg = '📤 Resultado do disparo:\n\n' +
        '✅ Enviados: ' + (j.enviados || 0) + '\n' +
        (j.falhas ? '❌ Falhas: ' + j.falhas + ' (continuam na fila)\n' : '') +
        (j.pulados ? '⏭ Pulados: ' + j.pulados + '\n' : '') +
        (j.leads_movidos ? '👥 Leads movidos para "Em contato": ' + j.leads_movidos : '');
      _alert(msg, j.falhas ? 'aviso' : 'sucesso');

      if (j.falhas && Array.isArray(j.detalhes)){
        var erros = j.detalhes.filter(function(d){ return d.resultado === 'falha'; })
          .map(function(d){ return '• ' + d.tipo + ': ' + (d.motivo || '?'); }).join('\n');
        if (erros) console.warn('[agente] falhas de disparo:\n' + erros);
      }
    } catch(e){
      _alert('Erro de rede no disparo: ' + e.message, 'erro');
    } finally {
      if (btn){ btn.disabled = false; btn.textContent = '🚀 Aprovar e ENVIAR'; }
      abrirFila();
      atualizarBadge();
    }
  }

  async function descartarSelecionados(){
    var ids = _selecionados();
    if (!ids.length){ _alert('Nenhum rascunho selecionado.', 'aviso'); return; }
    await _patchLote(ids, function(){
      return { status: 'descartado', revisado_em: new Date().toISOString() };
    });
    _alert('🗑 ' + ids.length + ' rascunho(s) descartado(s).', 'info');
    abrirFila();
    atualizarBadge();
  }

  /* v245: montagem resiliente — insiste até existir sessão (login em SPA
     não recarrega a página, então tentamos a cada 3s até conseguir) */
  function _tentarMontar(){
    if (document.getElementById('agente-fab')) return true;
    if (!document.body) return false;
    if (!_sessao()) return false;
    montarBotaoFlutuante();
    return !!document.getElementById('agente-fab');
  }
  var _agenteTimerMontagem = setInterval(function(){
    if (_tentarMontar()) clearInterval(_agenteTimerMontagem);
  }, 3000);
  if (document.readyState === 'loading'){
    document.addEventListener('DOMContentLoaded', _tentarMontar);
  } else {
    _tentarMontar();
  }

  return {
    botaoLead: botaoLead,
    abrirFila: abrirFila,
    aprovarEnviarSelecionados: aprovarEnviarSelecionados,
    descartarSelecionados: descartarSelecionados,
    atualizarBadge: atualizarBadge
  };
})();
